ype":["Person","Organization"],"@id":"https:\\/\\/spainonafork.com\\/#\\/schema\\/person\\/bb7046bf61575d8073e9646a387f53a9","name":"Spain on a Fork","image":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","contentUrl":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","caption":"Spain on a Fork"},"logo":{"@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g"},"sameAs":["https:\\/\\/spainonafork.wpengine.com"]},{"@type":"Recipe","name":"Hasselback Zucchini with Tomato Sauce","author":{"@type":"Person","name":"Albert Bevia @ Spain on a Fork"},"description":"","datePublished":"2024-07-08T14:00:00+00:00","image":["https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/07\\/image1-69-11.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/07\\/image1-69-11-500x500.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/07\\/image1-69-11-500x375.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/07\\/image1-69-11-480x270.png"],"recipeYield":["4"],"prepTime":"PT10M","cookTime":"PT25M","recipeIngredient":["4 medium-sized zucchinis","3 tbsp extra virgin olive oil (45 ml)","1 small onion","4 cloves garlic","1 tsp sweet smoked Spanish paprika (2.50 grams)","1\\/2 tsp dried thyme (.50 grams)","1 can tomato sauce (15 oz \\/ 425 grams)","3 tbsp chopped fresh parsley (11 grams)","1\\/4 cup grated Manchego cheese (30 grams)","sea salt &amp; black pepper"],"recipeInstructions":[{"@type":"HowToStep","text":"Place each zucchini over two chopsticks or wooden spoons, cut into slices that are 1 cm thick (a little over a 1\\/4 inch), making sure to not cut all the way through","name":"Place each zucchini over two chopsticks or wooden spoons, cut into slices that are 1 cm thick (a little over a 1\\/4 inch), making sure to not cut all the way through","url":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#wprm-recipe-16748-step-0-0"},{"@type":"HowToStep","text":"Add the zucchinis over a baking tray that&#39;s lined with foil paper, brush 1 tbsp (15 ml) extra virgin olive oil all over the each zucchini and season with sea salt &amp; black pepper, add into a preheated oven 425 F \\/ 220 C, bake for 25 to 30 minutes or until just tender, making sure to gently flip them at the half way point","name":"Add the zucchinis over a baking tray that&#39;s lined with foil paper, brush 1 tbsp (15 ml) extra virgin olive oil all over the each zucchini and season with sea salt &amp; black pepper, add into a preheated oven 425 F \\/ 220 C, bake for 25 to 30 minutes or until just tender, making sure to gently flip them at the half way point","url":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#wprm-recipe-16748-step-0-1"},{"@type":"HowToStep","text":"In the meantime, heat a fry pan with a medium heat and add in 2 tbsp (30 ml) extra virgin olive oil","name":"In the meantime, heat a fry pan with a medium heat and add in 2 tbsp (30 ml) extra virgin olive oil","url":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#wprm-recipe-16748-step-0-2"},{"@type":"HowToStep","text":"While the oil is heating, finely chop the onion and roughly chop the garlic","name":"While the oil is heating, finely chop the onion and roughly chop the garlic","url":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#wprm-recipe-16748-step-0-3"},{"@type":"HowToStep","text":"Add the chopped onion and garlic into the hot fry pan, mix continuously, after 3 to 4 minutes and the onion is translucent, add in the paprika and thyme, quickly mix together, then add in the canned tomato sauce, 2 tbsp (8 grams) chopped parsley and season with sea salt &amp; black pepper, mix together, then lower to a low heat","name":"Add the chopped onion and garlic into the hot fry pan, mix continuously, after 3 to 4 minutes and the onion is translucent, add in the paprika and thyme, quickly mix together, then add in the canned tomato sauce, 2 tbsp (8 grams) chopped parsley and season with sea salt &amp; black pepper, mix together, then lower to a low heat","url":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#wprm-recipe-16748-step-0-4"},{"@type":"HowToStep","text":"Once the zucchini is just tender, once again between 25 to 30 minutes, you can always pierce them with a toothpick, remove from the oven","name":"Once the zucchini is just tender, once again between 25 to 30 minutes, you can always pierce them with a toothpick, remove from the oven","url":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#wprm-recipe-16748-step-0-5"},{"@type":"HowToStep","text":"Gently transfer the zucchinis into a serving dish, top off with the simmering tomato sauce, a kiss of grated cheese and some chopped fresh parsley, serve warm or at room temperature, enjoy!","name":"Gently transfer the zucchinis into a serving dish, top off with the simmering tomato sauce, a kiss of grated cheese and some chopped fresh parsley, serve warm or at room temperature, enjoy!","url":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#wprm-recipe-16748-step-0-6"}],"recipeCategory":["Side Dish"],"recipeCuisine":["Mediterranean"],"nutrition":{"@type":"NutritionInformation","calories":"196 kcal","carbohydrateContent":"15 g","proteinContent":"6 g","fatContent":"14 g","saturatedFatContent":"3 g","cholesterolContent":"8 mg","sodiumContent":"566 mg","fiberContent":"4 g","sugarContent":"10 g","unsaturatedFatContent":"9 g","servingSize":"1 serving"},"@id":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#recipe","isPartOf":{"@id":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/#article"},"mainEntityOfPage":"https:\\/\\/spainonafork.com\\/hasselback-zucchini-with-tomato-sauce-recipe\\/"}]}',
                'image' => 'https://i0.wp.com/spainonafork.com/wp-content/uploads/2024/07/image1-69-11.png?fit=750%2C750&ssl=1',
            'ingredients' => '["4 medium-sized zucchinis","3 tbsp extra virgin olive oil (45 ml)","1 small onion","4 cloves garlic","1 tsp sweet smoked Spanish paprika (2.50 grams)","1\\/2 tsp dried thyme (.50 grams)","1 can tomato sauce (15 oz \\/ 425 grams)","3 tbsp chopped fresh parsley (11 grams)","1\\/4 cup grated Manchego cheese (30 grams)","sea salt &amp; black pepper"]',
            'directions' => '["Place each zucchini over two chopsticks or wooden spoons, cut into slices that are 1 cm thick (a little over a 1\\/4 inch), making sure to not cut all the way through","Add the zucchinis over a baking tray that&#39;s lined with foil paper, brush 1 tbsp (15 ml) extra virgin olive oil all over the each zucchini and season with sea salt &amp; black pepper, add into a preheated oven 425 F \\/ 220 C, bake for 25 to 30 minutes or until just tender, making sure to gently flip them at the half way point","In the meantime, heat a fry pan with a medium heat and add in 2 tbsp (30 ml) extra virgin olive oil","While the oil is heating, finely chop the onion and roughly chop the garlic","Add the chopped onion and garlic into the hot fry pan, mix continuously, after 3 to 4 minutes and the onion is translucent, add in the paprika and thyme, quickly mix together, then add in the canned tomato sauce, 2 tbsp (8 grams) chopped parsley and season with sea salt &amp; black pepper, mix together, then lower to a low heat","Once the zucchini is just tender, once again between 25 to 30 minutes, you can always pierce them with a toothpick, remove from the oven","Gently transfer the zucchinis into a serving dish, top off with the simmering tomato sauce, a kiss of grated cheese and some chopped fresh parsley, serve warm or at room temperature, enjoy!"]',
                'nutrition' => '[{"@type":"NutritionInformation","calories":"196 kcal","carbohydrateContent":"15 g","proteinContent":"6 g","fatContent":"14 g","saturatedFatContent":"3 g","cholesterolContent":"8 mg","sodiumContent":"566 mg","fiberContent":"4 g","sugarContent":"10 g","unsaturatedFatContent":"9 g","servingSize":"1 serving"}]',
