bject","inLanguage":"en-US","@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","contentUrl":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","caption":"Spain on a Fork"},"logo":{"@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g"},"sameAs":["https:\\/\\/spainonafork.wpengine.com"]},{"@type":"Recipe","name":"\\"EXTREME Garlic\\" Garlic Potatoes | Spanish Patatas al Ajillo","author":{"@type":"Person","name":"Albert Bevia @ Spain on a Fork"},"description":"","datePublished":"2024-04-15T14:00:00+00:00","image":["https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/04\\/image8-28-11.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/04\\/image8-28-11-500x500.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/04\\/image8-28-11-500x375.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/04\\/image8-28-11-480x270.png"],"recipeYield":["4"],"prepTime":"PT10M","cookTime":"PT25M","recipeIngredient":["1\\/2 cup extra virgin olive oil + 1 tbsp (120 ml + 15 ml)","2 1\\/4 lbs potatoes (1 kilogram)","1 head garlic + 2 cloves","2 tbsp chopped fresh parsley (8 grams)","sea salt"],"recipeInstructions":[{"@type":"HowToStep","text":"Heat a large fry pan with a medium heat and add in 1\\/2 cup (120 ml) extra virgin olive oil","name":"Heat a large fry pan with a medium heat and add in 1\\/2 cup (120 ml) extra virgin olive oil","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-0"},{"@type":"HowToStep","text":"In the meantime, separate the cloves of garlic from the head of garlic, then gently twist each clove to easily remove the skins","name":"In the meantime, separate the cloves of garlic from the head of garlic, then gently twist each clove to easily remove the skins","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-1"},{"@type":"HowToStep","text":"Add the cloves of garlic into the hot fry pan, mix every 1 to 2 minutes so all the cloves evenly saute","name":"Add the cloves of garlic into the hot fry pan, mix every 1 to 2 minutes so all the cloves evenly saute","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-2"},{"@type":"HowToStep","text":"While the garlic is cooking, cut the potatoes (peeled) into small bite-size pieces that are 2 cm (3\\/4 inch) thick","name":"While the garlic is cooking, cut the potatoes (peeled) into small bite-size pieces that are 2 cm (3\\/4 inch) thick","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-3"},{"@type":"HowToStep","text":"Once the cloves of garlic are golden fried, about 4 to 5 minutes, remove from the pan and set aside","name":"Once the cloves of garlic are golden fried, about 4 to 5 minutes, remove from the pan and set aside","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-4"},{"@type":"HowToStep","text":"Using the same pan with the same heat, add in the chopped potatoes, mix with the olive oil, then mix every 3 to 4 minutes so all the potatoes evenly fry","name":"Using the same pan with the same heat, add in the chopped potatoes, mix with the olive oil, then mix every 3 to 4 minutes so all the potatoes evenly fry","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-5"},{"@type":"HowToStep","text":"In the meantime, add 2 cloves of garlic roughly chopped into a mortar, along with the chopped parsley and a kiss of sea salt, using a pestle pound down on the ingredients until you get a paste-like texture, then add in 1 tbsp (15 ml) extra virgin olive oil, mix together and set aside","name":"In the meantime, add 2 cloves of garlic roughly chopped into a mortar, along with the chopped parsley and a kiss of sea salt, using a pestle pound down on the ingredients until you get a paste-like texture, then add in 1 tbsp (15 ml) extra virgin olive oil, mix together and set aside","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-6"},{"@type":"HowToStep","text":"Once the potatoes are golden fried and fully cooked through, about 20 to 25 minutes, remove the pan from the heat, transfer the potatoes into a large bowl, making sure to not add any excess oil in the pan, then add in the fried cloves of garlic, the garlic &amp; parsley sauce and season everything with sea salt, gently toss together until well mixed","name":"Once the potatoes are golden fried and fully cooked through, about 20 to 25 minutes, remove the pan from the heat, transfer the potatoes into a large bowl, making sure to not add any excess oil in the pan, then add in the fried cloves of garlic, the garlic &amp; parsley sauce and season everything with sea salt, gently toss together until well mixed","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-7"},{"@type":"HowToStep","text":"Transfer the potatoes into a large serving dish, serve warm or at room temperature, enjoy!","name":"Transfer the potatoes into a large serving dish, serve warm or at room temperature, enjoy!","url":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#wprm-recipe-16481-step-0-8"}],"recipeCategory":["Appetizer","Side Dish"],"recipeCuisine":["Spanish"],"nutrition":{"@type":"NutritionInformation","calories":"446 kcal","carbohydrateContent":"47 g","proteinContent":"6 g","fatContent":"27 g","saturatedFatContent":"4 g","sodiumContent":"309 mg","fiberContent":"6 g","sugarContent":"2 g","unsaturatedFatContent":"23 g","servingSize":"1 serving"},"@id":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#recipe","isPartOf":{"@id":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/#article"},"mainEntityOfPage":"https:\\/\\/spainonafork.com\\/extreme-garlic-garlic-potatoes-recipe\\/"}]}',
                'image' => 'https://i0.wp.com/spainonafork.com/wp-content/uploads/2024/04/image8-28-11.png?fit=750%2C750&ssl=1',
            'ingredients' => '["1\\/2 cup extra virgin olive oil + 1 tbsp (120 ml + 15 ml)","2 1\\/4 lbs potatoes (1 kilogram)","1 head garlic + 2 cloves","2 tbsp chopped fresh parsley (8 grams)","sea salt"]',
            'directions' => '["Heat a large fry pan with a medium heat and add in 1\\/2 cup (120 ml) extra virgin olive oil","In the meantime, separate the cloves of garlic from the head of garlic, then gently twist each clove to easily remove the skins","Add the cloves of garlic into the hot fry pan, mix every 1 to 2 minutes so all the cloves evenly saute","While the garlic is cooking, cut the potatoes (peeled) into small bite-size pieces that are 2 cm (3\\/4 inch) thick","Once the cloves of garlic are golden fried, about 4 to 5 minutes, remove from the pan and set aside","Using the same pan with the same heat, add in the chopped potatoes, mix with the olive oil, then mix every 3 to 4 minutes so all the potatoes evenly fry","In the meantime, add 2 cloves of garlic roughly chopped into a mortar, along with the chopped parsley and a kiss of sea salt, using a pestle pound down on the ingredients until you get a paste-like texture, then add in 1 tbsp (15 ml) extra virgin olive oil, mix together and set aside","Once the potatoes are golden fried and fully cooked through, about 20 to 25 minutes, remove the pan from the heat, transfer the potatoes into a large bowl, making sure to not add any excess oil in the pan, then add in the fried cloves of garlic, the garlic &amp; parsley sauce and season everything with sea salt, gently toss together until well mixed","Transfer the potatoes into a large serving dish, serve warm or at room temperature, enjoy!"]',
                'nutrition' => '[{"@type":"NutritionInformation","calories":"446 kcal","carbohydrateContent":"47 g","proteinContent":"6 g","fatContent":"27 g","saturatedFatContent":"4 g","sodiumContent":"309 mg","fiberContent":"6 g","sugarContent":"2 g","unsaturatedFatContent":"23 g","servingSize":"1 serving"}]',
