search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":["Person","Organization"],"@id":"https:\\/\\/spainonafork.com\\/#\\/schema\\/person\\/bb7046bf61575d8073e9646a387f53a9","name":"Spain on a Fork","image":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","contentUrl":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g","caption":"Spain on a Fork"},"logo":{"@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/1e8709ffbf762ce98cf11b19eed76154f6088c5b0eb5ff06afbe0fec31ed969c?s=96&d=mm&r=g"},"sameAs":["https:\\/\\/spainonafork.wpengine.com"]},{"@type":"Recipe","name":"Spanish Lentils with Rice | Lentajas con Arroz","author":{"@type":"Person","name":"Albert Bevia @ Spain on a Fork"},"description":"","datePublished":"2024-06-21T14:00:00+00:00","image":["https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/06\\/image1-62-11.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/06\\/image1-62-11-500x500.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/06\\/image1-62-11-500x375.png","https:\\/\\/spainonafork.com\\/wp-content\\/uploads\\/2024\\/06\\/image1-62-11-480x270.png"],"recipeYield":["4"],"prepTime":"PT10M","cookTime":"PT35M","recipeIngredient":["2 tbsp extra virgin olive oil (35 ml)","1 small onion","4 cloves garlic","1 green bell pepper","2 carrots","1 tbsp sherry vinegar (15 ml)","1 tsp sweet smoked Spanish paprika (2.50 grams)","1\\/2 tsp ground cumin (1.50 grams)","2 tomatoes","1 cup dried green lentils (130 grams)","4 1\\/2 cups vegetable broth (1050 ml)","1 bay leaf","sea salt &amp; black pepper","3 cups vegetable broth (720 ml)","1 cup Spanish round rice (190 grams)","sea salt","handful chopped fresh parsley"],"recipeInstructions":[{"@type":"HowToSection","name":"TO MAKE THE LENTILS","itemListElement":[{"@type":"HowToStep","text":"Heat a stock pot with a medium heat and add in the olive oil","name":"Heat a stock pot with a medium heat and add in the olive oil","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-0-0"},{"@type":"HowToStep","text":"While the oil is heating, finely chop the onion, roughly chop the garlic, finely chop the green bell pepper, cut the carrots (peeled) into small bite-size pieces and finely grate the tomatoes","name":"While the oil is heating, finely chop the onion, roughly chop the garlic, finely chop the green bell pepper, cut the carrots (peeled) into small bite-size pieces and finely grate the tomatoes","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-0-1"},{"@type":"HowToStep","text":"Add the chopped ingredients (except the tomato) into the stock, mix continuously, after 3 to 4 minutes and the vegetables are lightly sauteed, add in the sherry vinegar, paprika and cumin, quickly mix together, then add in the grated tomato, mix and then simmer","name":"Add the chopped ingredients (except the tomato) into the stock, mix continuously, after 3 to 4 minutes and the vegetables are lightly sauteed, add in the sherry vinegar, paprika and cumin, quickly mix together, then add in the grated tomato, mix and then simmer","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-0-2"},{"@type":"HowToStep","text":"In the meantime, add the dried lentils into a fine sieve and rinse under water","name":"In the meantime, add the dried lentils into a fine sieve and rinse under water","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-0-3"},{"@type":"HowToStep","text":"Once the grated tomato has slightly thickened, about 3 to 4 minutes, add in the rinsed lentils, along with the vegetable broth and bay leaf, raise to a high heat, once it comes to a boil, place a lid on the stock pot and lower to a low heat","name":"Once the grated tomato has slightly thickened, about 3 to 4 minutes, add in the rinsed lentils, along with the vegetable broth and bay leaf, raise to a high heat, once it comes to a boil, place a lid on the stock pot and lower to a low heat","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-0-4"}]},{"@type":"HowToSection","name":"TO MAKE THE RICE","itemListElement":[{"@type":"HowToStep","text":"While the lentils are simmering, add the broth into a sauce pan, season with sea salt and heat with a high heat","name":"While the lentils are simmering, add the broth into a sauce pan, season with sea salt and heat with a high heat","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-1-0"},{"@type":"HowToStep","text":"Once it comes to a boil add in the rice, mix together, then place a lid on the sauce pan and lower to a low-medium heat, cook until the rice is done and all the broth has been absorbed (15 minutes in my case, make sure to check package instructions on the rice you are using), then remove from the heat and let it sit for a couple of minutes with the lid, then remove the lid and fluff the rice with a fork","name":"Once it comes to a boil add in the rice, mix together, then place a lid on the sauce pan and lower to a low-medium heat, cook until the rice is done and all the broth has been absorbed (15 minutes in my case, make sure to check package instructions on the rice you are using), then remove from the heat and let it sit for a couple of minutes with the lid, then remove the lid and fluff the rice with a fork","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-1-1"},{"@type":"HowToStep","text":"Move back to the lentils, after 20 to 25 minutes and the lentils are cooked through, season with sea salt &amp; black pepper, mix together, then remove from the heat","name":"Move back to the lentils, after 20 to 25 minutes and the lentils are cooked through, season with sea salt &amp; black pepper, mix together, then remove from the heat","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-1-2"},{"@type":"HowToStep","text":"To assemble the dish, add some of the rice into a shallow bowl, then add in some of the lentils next to the rice, garnish with chopped fresh parsley inbetween the rice and lentils, enjoy!","name":"To assemble the dish, add some of the rice into a shallow bowl, then add in some of the lentils next to the rice, garnish with chopped fresh parsley inbetween the rice and lentils, enjoy!","url":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#wprm-recipe-16697-step-1-3"}]}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"5","ratingCount":"1","reviewCount":"1"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"My husband and I were visiting friends in France recently and we were served this dish for lunch one day. Absolutely delicious! I will be making this often. Thanks so much!","author":{"@type":"Person","name":"Dawn Erickson"},"datePublished":"2024-11-27"}],"recipeCategory":["Main Course"],"recipeCuisine":["Spanish"],"nutrition":{"@type":"NutritionInformation","calories":"483 kcal","carbohydrateContent":"84 g","proteinContent":"19 g","fatContent":"8 g","saturatedFatContent":"1 g","sodiumContent":"612 mg","fiberContent":"21 g","sugarContent":"7 g","unsaturatedFatContent":"6 g","servingSize":"1 serving"},"@id":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#recipe","isPartOf":{"@id":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/#article"},"mainEntityOfPage":"https:\\/\\/spainonafork.com\\/the-best-lentils-of-your-life-spanish-lentils-with-rice-recipe\\/"}]}',
                'image' => 'https://i0.wp.com/spainonafork.com/wp-content/uploads/2024/06/image1-62-11.png?fit=750%2C750&ssl=1',
            'ingredients' => '["2 tbsp extra virgin olive oil (35 ml)","1 small onion","4 cloves garlic","1 green bell pepper","2 carrots","1 tbsp sherry vinegar (15 ml)","1 tsp sweet smoked Spanish paprika (2.50 grams)","1\\/2 tsp ground cumin (1.50 grams)","2 tomatoes","1 cup dried green lentils (130 grams)","4 1\\/2 cups vegetable broth (1050 ml)","1 bay leaf","sea salt &amp; black pepper","3 cups vegetable broth (720 ml)","1 cup Spanish round rice (190 grams)","sea salt","handful chopped fresh parsley"]',
            'directions' => '{"TO MAKE THE LENTILS":["Heat a stock pot with a medium heat and add in the olive oil","While the oil is heating, finely chop the onion, roughly chop the garlic, finely chop the green bell pepper, cut the carrots (peeled) into small bite-size pieces and finely grate the tomatoes","Add the chopped ingredients (except the tomato) into the stock, mix continuously, after 3 to 4 minutes and the vegetables are lightly sauteed, add in the sherry vinegar, paprika and cumin, quickly mix together, then add in the grated tomato, mix and then simmer","In the meantime, add the dried lentils into a fine sieve and rinse under water","Once the grated tomato has slightly thickened, about 3 to 4 minutes, add in the rinsed lentils, along with the vegetable broth and bay leaf, raise to a high heat, once it comes to a boil, place a lid on the stock pot and lower to a low heat"],"TO MAKE THE RICE":["While the lentils are simmering, add the broth into a sauce pan, season with sea salt and heat with a high heat","Once it comes to a boil add in the rice, mix together, then place a lid on the sauce pan and lower to a low-medium heat, cook until the rice is done and all the broth has been absorbed (15 minutes in my case, make sure to check package instructions on the rice you are using), then remove from the heat and let it sit for a couple of minutes with the lid, then remove the lid and fluff the rice with a fork","Move back to the lentils, after 20 to 25 minutes and the lentils are cooked through, season with sea salt &amp; black pepper, mix together, then remove from the heat","To assemble the dish, add some of the rice into a shallow bowl, then add in some of the lentils next to the rice, garnish with chopped fresh parsley inbetween the rice and lentils, enjoy!"]}',
