            'site_name' => 'Laura Strange (www.mygfguide.com)',
                'user_id' => 1,
                'description' => NULL,
            'content' => '{"@context":"http:\\/\\/schema.org","@type":"Recipe","name":"Indian-Style Paneer &amp; Lentil Curry","author":{"@type":"Person","name":"Laura Strange (www.mygfguide.com)"},"datePublished":"2020-07-10","recipeYield":4,"image":["https:\\/\\/www.mygfguide.com\\/wp-content\\/uploads\\/2020\\/07\\/Veggie-curry-cover-shot-web-720x720.jpg","https:\\/\\/www.mygfguide.com\\/wp-content\\/uploads\\/2020\\/07\\/Veggie-curry-cover-shot-web-720x540.jpg","https:\\/\\/www.mygfguide.com\\/wp-content\\/uploads\\/2020\\/07\\/Veggie-curry-cover-shot-web.jpg","https:\\/\\/www.mygfguide.com\\/wp-content\\/uploads\\/2020\\/07\\/Veggie-curry-cover-shot-web-720x405.jpg","https:\\/\\/www.mygfguide.com\\/wp-content\\/uploads\\/2020\\/07\\/Veggie-curry-cover-shot-web-735x551.jpg"],"recipeCategory":"Gluten Free Recipe","recipeCuisine":"Vegetarian","prepTime":"PT5M","cookTime":"PT55M","performTime":"PT55M","totalTime":"PT1H","recipeIngredient":["200g paneer cheese","390g tin green lentils, drained and rinsed","4 garlic cloves","1 tsp ground ginger","2 white onions","1 yellow\\/orange\\/red pepper","2 tsp garam masala","1 tsp tumeric","2 tsp ground cumin","2 tsp ground coriander","500ml vegetable stock","1 tin chopped tomatoes","100g spinach"],"recipeInstructions":[{"@type":"HowToStep","text":"Finely dice the onions and fry in a high-sided frying pan or saucepan for 5 minutes over a low-medium heat. After this time they should be translucent and soft.","position":1,"name":"Finely dice the onions and fry in a...","url":"https:\\/\\/www.mygfguide.com\\/gluten-free-recipe-paneer-lentil-curry\\/#mv_create_50_1"},{"@type":"HowToStep","text":"Mince the garlic and add to the pan with the onion, then allow to cook for a couple of minutes and stir through the onion.","position":2,"name":"Mince the garlic and add to the pan...","url":"https:\\/\\/www.mygfguide.com\\/gluten-free-recipe-paneer-lentil-curry\\/#mv_create_50_2"},{"@type":"HowToStep","text":"Next add the ground ginger and other spices (garam masala, cumin, coriander, tumeric and optional cayenne) to the pan and allow them to sizzle gently until everything starts to smell fragrant (a couple of mins).","position":3,"name":"Next add the ground ginger and other spices...","url":"https:\\/\\/www.mygfguide.com\\/gluten-free-recipe-paneer-lentil-curry\\/#mv_create_50_3"},{"@type":"HowToStep","text":"Chop the pepper into small chunks and add this to the pan too.","position":4,"name":"Chop the pepper into small chunks and add...","url":"https:\\/\\/www.mygfguide.com\\/gluten-free-recipe-paneer-lentil-curry\\/#mv_create_50_4"},{"@type":"HowToStep","text":"Add the tinned tomatoes, green lentils and stock to the pan and bring to the boil before turning right down to a gentle simmer. Allow the curry to cook for 40 minutes, until the sauce has thickened nicely. If it begins to dry out slightly simply add a little more water.","position":5,"name":"Add the tinned tomatoes, green lentils and stock...","url":"https:\\/\\/www.mygfguide.com\\/gluten-free-recipe-paneer-lentil-curry\\/#mv_create_50_5"},{"@type":"HowToStep","text":"While this is cooking, dice the paneer cheese into small chunks and dry fry it in a frying pan, to allow it to colour and lightly caramelise on the outside. Set aside.","position":6,"name":"While this is cooking, dice the paneer cheese...","url":"https:\\/\\/www.mygfguide.com\\/gluten-free-recipe-paneer-lentil-curry\\/#mv_create_50_6"},{"@type":"HowToStep","text":"Wilt the spinach into the curry and add the paneer, before cooking the curry for a further 10 minutes. Then you can serve the paneer and lentil curry on a bed of rice with some yummy poppadums or gluten free onion bhajis and mango chutney on the side!","position":7,"name":"Wilt the spinach into the curry and add...","url":"https:\\/\\/www.mygfguide.com\\/gluten-free-recipe-paneer-lentil-curry\\/#mv_create_50_7"}],"suitableForDiet":"VegetarianDiet","aggregateRating":{"@type":"AggregateRating","ratingValue":"4.5","reviewCount":65},"review":[{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-10-28T19:30:48+00:00","reviewRating":{"@type":"Rating","ratingValue":"4.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-09-12T15:39:43+00:00","reviewRating":{"@type":"Rating","ratingValue":"4.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-08-16T15:55:15+00:00","reviewRating":{"@type":"Rating","ratingValue":"4.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-07-13T12:46:33+00:00","reviewRating":{"@type":"Rating","ratingValue":"5.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-03-10T19:50:21+00:00","reviewRating":{"@type":"Rating","ratingValue":"5.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-02-09T01:11:33+00:00","reviewRating":{"@type":"Rating","ratingValue":"5.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-01-27T00:39:09+00:00","reviewRating":{"@type":"Rating","ratingValue":"4.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-01-19T12:18:18+00:00","reviewRating":{"@type":"Rating","ratingValue":"5.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-01-18T17:51:44+00:00","reviewRating":{"@type":"Rating","ratingValue":"4.0","bestRating":"5","worstRating":"1"}},{"@type":"Review","author":{"@type":"Person","name":"Anonymous"},"datePublished":"2025-01-15T22:55:34+00:00","reviewRating":{"@type":"Rating","ratingValue":"4.0","bestRating":"5","worst