            18 => 
            array (
                'id' => 19,
                'name' => 'Sheet-Pan Feta With Chickpeas and Tomatoes',
                'url' => 'https://cooking.nytimes.com/recipes/1023371-sheet-pan-feta-with-chickpeas-and-tomatoes',
                'site_domain' => 'https//cooking.nytimes.com',
                'site_name' => 'Ali Slagle',
                'user_id' => 1,
            'description' => 'In a spread of Greek appetizers, or meze, there’s often a warm feta dish like bouyiourdi (baked feta with tomato and hot peppers) or a saganaki (fried cheese). This recipe combines elements of these two classic appetizers into a sheet-pan meal. Softened feta provides a salty, creamy counterpoint to sweet, juicy tomatoes and chickpeas that are sticky from honey and spicy from dried chile. Try this version, then riff wildly: Switch out tomatoes for mini peppers, olives, dates or cauliflower. Swap the hot honey for anchovies, harissa, smoked paprika or turmeric. Eat with pita, grains, salad greens, hummus or yogurt.',
            'content' => '{"@context":"http:\\/\\/schema.org","@id":"nyt:\\/\\/recipe\\/846f7dce-da08-5dcb-a4ad-b87013b89348","@type":"Recipe","mainEntityOfPage":{"@id":"https:\\/\\/cooking.nytimes.com\\/recipes\\/1023371-sheet-pan-feta-with-chickpeas-and-tomatoes","@type":"WebPage","name":"Sheet-Pan Feta With Chickpeas and Tomatoes"},"url":"https:\\/\\/cooking.nytimes.com\\/recipes\\/1023371-sheet-pan-feta-with-chickpeas-and-tomatoes","name":"Sheet-Pan Feta With Chickpeas and Tomatoes","description":"In a spread of Greek appetizers, or meze, there\\u2019s often a warm feta dish like bouyiourdi (baked feta with tomato and hot peppers) or a saganaki (fried cheese). This recipe combines elements of these two classic appetizers into a sheet-pan meal. Softened feta provides a salty, creamy counterpoint to sweet, juicy tomatoes and chickpeas that are sticky from honey and spicy from dried chile. Try this version, then riff wildly: Switch out tomatoes for mini peppers, olives, dates or cauliflower. Swap the hot honey for anchovies, harissa, smoked paprika or turmeric. Eat with pita, grains, salad greens, hummus or yogurt.","author":{"@type":"Person","name":"Ali Slagle"},"image":[{"@id":"nyt:\\/\\/image\\/a52a8028-caf1-590f-8e9d-220b5b3241f8#videoSixteenByNineJumbo1600","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2022\\/07\\/28\\/dining\\/as-roasted-feta-and-chickpeas\\/merlin_209335479_52115ec4-9a9b-483e-b749-ed40dc44a69d-videoSixteenByNineJumbo1600.jpg","creditText":"Ryan Liebe for The New York Times. Food Stylist: Simon Andrews.","dateModified":"2022-09-04T20:20:45.227Z","datePublished":"2022-07-28T14:33:11.000Z","height":"900","representativeOfPage":true,"uploadDate":"2022-07-28T14:33:11.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2022\\/07\\/28\\/dining\\/as-roasted-feta-and-chickpeas\\/merlin_209335479_52115ec4-9a9b-483e-b749-ed40dc44a69d-videoSixteenByNineJumbo1600.jpg","width":"1600"},{"@id":"nyt:\\/\\/image\\/a52a8028-caf1-590f-8e9d-220b5b3241f8#superJumbo","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2022\\/07\\/28\\/dining\\/as-roasted-feta-and-chickpeas\\/merlin_209335479_52115ec4-9a9b-483e-b749-ed40dc44a69d-superJumbo.jpg","creditText":"Ryan Liebe for The New York Times. Food Stylist: Simon Andrews.","dateModified":"2022-09-04T20:20:45.227Z","datePublished":"2022-07-28T14:33:11.000Z","height":"1365","representativeOfPage":true,"uploadDate":"2022-07-28T14:33:11.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2022\\/07\\/28\\/dining\\/as-roasted-feta-and-chickpeas\\/merlin_209335479_52115ec4-9a9b-483e-b749-ed40dc44a69d-superJumbo.jpg","width":"2048"},{"@id":"nyt:\\/\\/image\\/a52a8028-caf1-590f-8e9d-220b5b3241f8#mediumSquareAt3X","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2022\\/07\\/28\\/dining\\/as-roasted-feta-and-chickpeas\\/merlin_209335479_52115ec4-9a9b-483e-b749-ed40dc44a69d-mediumSquareAt3X.jpg","creditText":"Ryan Liebe for The New York Times. Food Stylist: Simon Andrews.","dateModified":"2022-09-04T20:20:45.227Z","datePublished":"2022-07-28T14:33:11.000Z","height":"1800","representativeOfPage":true,"uploadDate":"2022-07-28T14:33:11.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2022\\/07\\/28\\/dining\\/as-roasted-feta-and-chickpeas\\/merlin_209335479_52115ec4-9a9b-483e-b749-ed40dc44a69d-mediumSquareAt3X.jpg","width":"1800"}],"totalTime":"PT40M","recipeYield":"4 servings","recipeCuisine":"","recipeCategory":"dinner, easy, beans, appetizer, main course","keywords":"chickpea, feta, partial-access-ic, vegetarian","aggregateRating":{"@type":"AggregateRating","ratingValue":5,"ratingCount":5026},"nutrition":{"@context":"http:\\/\\/schema.org","@type":"NutritionInformation","calories":650,"unsaturatedFatContent":"19 grams","carbohydrateContent":"54 grams","cholesterolContent":null,"fatContent":"38 grams","fiberContent":"11 grams","proteinContent":"27 grams","saturatedFatContent":"15 grams","sodiumContent":"1439 milligrams","sugarContent":"19 grams","transFatContent":"0 grams"},"recipeIngredient":["3 cups cooked chickpeas (homemade or two 15-ounce cans), drained, rinsed and shaken dry","2 pints (16 to 20 ounces) cherry or Sungold tomatoes","1 shallot, thinly sliced","1\\/4 cup extra-virgin olive oil\\u00a0","2 tablespoons honey","1 teaspoon mild chile flakes (like gochugaru) or \\u00bd teaspoon red-pepper flakes","Salt","2 (6- to 8-ounce) blocks of feta (see Tip), sliced 1-inch-thick"],"recipeInstructions":[{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"Heat the oven to 400 degrees. On a sheet pan, stir together the chickpeas, tomatoes, shallot, olive oil, honey and chile flakes. Season with salt, then spread in an even layer. Arrange the feta among the chickpeas."},{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"Roast until the feta and tomatoes are soft and the chickpeas are golden brown, 30 to 35 minutes (no need to stir). Eat right away. (The feta will harden as it cools; reheat leftovers.)\\u00a0"}],"publisher":{"@id":"https:\\/\\/cooking.nytimes.com\\/#publisher","@type":"Organization","name":"NYT Cooking"},"datePublished":"2022-07-28T00:00:00.000Z","dateModified":"2024-02-16T17:19:14.000Z","review":[{"@type":"Review","author":{"@type":"Person","name":"Maggie"},"reviewBody":"This is as delicious as it is easy. I\'ve served this in a pinch many times, and every time, everyone loves it. \\u2764\\ufe0f","datePublished":"2024-12-14T23:47:39.000Z"},{"@type":"Review","author":{"@type":"Person","name":"sammo"},"reviewBody":"Kind of bland, would add more spices next time","datePublished":"2024-12-09T16:36:57.000Z"},{"@type":"Review","author":{"@type":"Person","name":"jmthie"},"reviewBody":"Bell peppers\\nBroth or white wine\\nCauliflower \\nRed onions instead of shallots","datePublished":"2024-12-01T17:32:47.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Cristina"},"reviewBody":"I misread the recipe and used hot honey instead of honey - came out delicious so now I use hot honey every time I make this! Great recipe, love the combination","datePublished":"2024-11-28T16:52:44.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Sangvi"},"reviewBody":"This was really yummy, I ate it with some pita and it felt like a complete meal. I also used only a block of feta and half the amount of oil. I would probably cut up another shallot too if I made it again.","datePublished":"2024-11-27T19:43:13.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Amy Sullivan"},"reviewBody":"I know it would be more delicious prepared as directed, but here is what I did to shortcut and it was still so good. I used a can of fire roasted diced tomatoes that I drained through a sieve. I also used fat free feta crumbles, and I know the full fat sheep feta block would be so much better, but this is what I had and I\'m watching sat fat and cheese is a thing. I also used a regular onion sliced thinly instead of a shallot. Had it with a homemade herby boule toasted with olive oil in the oven.","datePublished":"2024-11-21T23:37:58.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Jessica"},"reviewBody":"I added broccoli, and I only used 1 block of feta and 1 can of chickpeas! It\'s very good and super easy. I served it over some arugula and topped it with hummus.","datePublished":"2024-11-18T17:49:51.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Christa"},"reviewBody":"I swapped mini-bell peppers for the tomatoes and one tablespoon smoked paprika for the honey, but in hindsight, one 8-oz. block of feta would have been sufficient. Also used my own home-cooked chickpeas. Otherwise love this simple recipe as I love and look forward to all of Ali Slagle\'s recipes--very simple to make, which I appreciate, having multiple sclerosis, and very flavorful. Appreciate the suggestions for riffing. Love roasted bell peppers as well as chickpeas and smoked paprika.","datePublished":"2024-11-17T21:55:59.000Z"},{"@type":"Review","author":{"@type":"Person","name":"JSG"},"reviewBody":"WOW was this good! Made it as written, and it was easy enough for a weeknight. The honey doesn\'t make it sweet... I\'m actually not sure what it does, but don\'t skip it! My only tiny issue was I used a sheep\'s milk feta in brine and it melted into puddles. Definitely didn\'t look like the photo. I was worried it would be a disaster but it firmed up. I used a pancake spatula to serve. Ate with garlic bread (thanks to the person who suggested that!). 10\\/10. We will absolutely make this again.","datePublished":"2024-11-13T01:08:48.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Harvey"},"reviewBody":"I found the recipe interesting, if a little bland. The honey gave it a unique flavor twist that I enjoyed, but I ended up adding confited garlic and shredded chicken. It\'s simple to make and uses a lot of \\"left overs\\" that I frequently have in the fridge.\\n\\nThe tip about the type of feta is key. Definitely pay attention to that one.","datePublished":"2024-11-06T23:00:25.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Faye Levy"},"reviewBody":"Looks wonderful! Thank you for the tip about the kind of feta to use.","datePublished":"2024-11-06T21:54:49.000Z"},{"@type":"Review","author":{"@type":"Person","name":"mmg"},"reviewBody":"This meal came together extremely easily, but I felt it was bland. I properly seasoned and used high quality feta but it was a bit dry and unflavorful. Won\\u2019t be making again but will give it credit for being a low lift dinner","datePublished":"2024-10-25T00:02:56.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Gaby"},"reviewBody":"Very easy to make and yummy! I also fed tofu for protein","datePublished":"2024-10-22T02:32:59.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Juliet"},"reviewBody":"This was great. Will definitely make again.","datePublished":"2024-10-21T00:23:19.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Sophia"},"reviewBody":"Add cauliflower and then lemon juice at end.","datePublished":"2024-10-20T19:55:51.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Mary"},"reviewBody":"Enjoyed it. You only need one block of feta. I will cook mine a little longer next time, so more tomatoes burst. A good recipe to play around with. No need for honey. Maybe red onions instead of shallots. Some lemon. Pine nuts might be a nice add for next time. Fresh basil on top at the end.","datePublished":"2022-07-31T23:18:22.000Z"},{"@type":"Review","author":{"@type":"Person","name":"CurryFavor"},"reviewBody":"Really tasty! I used a nice sheeps milk feta, which was delicious, and added 8oz of merguez lamb sausage links and calabrian chiles in lieu of chile flakes (plus some of the chile oil for extra heat). So delicious. The honey blended very well and balanced the tomatoes\' tanginess. I used 25 oz. of garden tomatoes because they are so plentiful right now. Would definitely make this again.","datePublished":"2022-07-31T02:47:41.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Terrie"},"reviewBody":"beans and cheese have protein. Save a cow or a chicken!","datePublished":"2022-08-01T03:11:42.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Levmom4"},"reviewBody":"My favorite NYT Cooking recipe of the summer! Everything worked beautifully (I used Sheep\'s milk feta instead of Cow\'s milk)and the combination is amazing. The best addition I made was to generously sprinkle smoked paprika on everything before putting in the oven. It added this smoky depth that was absolutely delicious!","datePublished":"2022-09-02T18:21:16.000Z"},{"@type":"Review","author":{"@type":"Person","name":"B. Curtis"},"reviewBody":"Added several kinds of olives & artichoke hearts 20 minutes in.","datePublished":"2022-08-12T23:51:06.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Heidi & Phil Sweeney"},"reviewBody":"Great dish! We chose it as we wanted something quick and easy for dinner, and we had all the ingredients. At least we thought we did. ... Ended up substituting onion for shallots and using cow\'s milk feta (8-ounce block from Trader Joe\'s). Cut the feta into smaller than 1-inch slices as the accompanying photo looked like feta chunks were not that large. And the cow\'s milk feta withstood the roasting just fine with some extra olive oil on top. Colorful and tasty. This one\'s definitely a keeper!","datePublished":"2022-07-31T23:33:26.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Mary B. Hennessey"},"reviewBody":"I am going to halve this recipe and make it but I know I am going to make it on top of the stove, too hot to put the oven on. Wish me luck","datePublished":"2022-07-31T16:32:05.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Melinda"},"reviewBody":"Sooooo\\u2026.this should be a great dish. I\\u2019ve made a similar sheet pan dinner with feta and roasted vegetables served on orzo and it\\u2019s fantastic. This was made exactly as written and it was way too dry. Just not as luscious as the other recipe. If I made again, I would add some other vegetable such as red or yellow bell pepper, use red onion rather than shallot, and add some liquid, whether broth, fermented red pepper sauce, or white wine used to deglaze the sheet pan. Needs something\\u2026","datePublished":"2022-08-17T21:51:36.000Z"},{"@type":"Review","author":{"@type":"Person","name":"JC"},"reviewBody":"In a nod to Eric Kim\'s sheet pan kimchi fried rice, we cracked eggs onto the sheet pan after it had been in the oven for 5-10 minutes and served it with grilled bread. It was a great way to make this a more substantial meal. Even my toddler scarfed it down.","datePublished":"2022-09-18T11:53:26.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Eileen"},"reviewBody":"Excellent. I followed the recipe exactly, Bulgarian sheep feta from the deli, and a big pinch of Zaatar. Mixture is pretty wet because the tomatoes are so juicy. Line the baking dish. Served with garlicky saut\\u00e9ed greens and garlic toast. Will definitely make this again.","datePublished":"2022-08-07T02:40:18.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Anne"},"reviewBody":"Could you sub paneer for the feta?","datePublished":"2022-07-31T15:14:36.000Z"},{"@type":"Review","author":{"@type":"Person","name":"nicole"},"reviewBody":"I have a sensitivity to chickpeas and so I did this with lentils. It was fantastic! I\\u2019ve made it multiple times now.","datePublished":"2022-09-14T02:38:56.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Shannon"},"reviewBody":"Added cauliflower and used cows milk feta, but added half way through cooking","datePublished":"2022-08-10T04:18:15.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Bri"},"reviewBody":"I missed the tip to use something other than cow\'s milk feta (not sure why this was buried in a tip). Also the tomatoes burst which resulted in a lot of liquid and the prescribed roast time did not accommodate cooking off the liquid. So the end result was not very roasty. Will probably try again with the proper feta that can withstand a longer roast time. Might also use a bigger baking sheet to cook off the tomato liquid.","datePublished":"2022-08-18T17:31:40.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Annie B"},"reviewBody":"Halves beautifully, as written. Yumm-o.","datePublished":"2022-07-31T18:15:50.000Z"}],"copyrightHolder":{"@id":"https:\\/\\/cooking.nytimes.com\\/#publisher","@type":"Organization","name":"NYT Cooking"},"copyrightYear":2022}',
                'image' => 'https://static01.nyt.com/images/2022/07/28/dining/as-roasted-feta-and-chickpeas/merlin_209335479_52115ec4-9a9b-483e-b749-ed40dc44a69d-videoSixteenByNineJumbo1600.jpg',
            'ingredients' => '["3 cups cooked chickpeas (homemade or two 15-ounce cans), drained, rinsed and shaken dry","2 pints (16 to 20 ounces) cherry or Sungold tomatoes","1 shallot, thinly sliced","1\\/4 cup extra-virgin olive oil\\u00a0","2 tablespoons honey","1 teaspoon mild chile flakes (like gochugaru) or \\u00bd teaspoon red-pepper flakes","Salt","2 (6- to 8-ounce) blocks of feta (see Tip), sliced 1-inch-thick"]',
            'directions' => '["Heat the oven to 400 degrees. On a sheet pan, stir together the chickpeas, tomatoes, shallot, olive oil, honey and chile flakes. Season with salt, then spread in an even layer. Arrange the feta among the chickpeas.","Roast until the feta and tomatoes are soft and the chickpeas are golden brown, 30 to 35 minutes (no need to stir). Eat right away. (The feta will harden as it cools; reheat leftovers.)\\u00a0"]',
                'nutrition' => '{"@context":"http:\\/\\/schema.org","@type":"NutritionInformation","calories":650,"unsaturatedFatContent":"19 grams","carbohydrateContent":"54 grams","cholesterolContent":null,"fatContent":"38 grams","fiberContent":"11 grams","proteinContent":"27 grams","saturatedFatContent":"15 grams","sodiumContent":"1439 milligrams","sugarContent":"19 grams","transFatContent":"0 grams"}',
                'slug' => 'sheet-pan-feta-with-chickpeas-and-tomatoes',
                'raw_data' => NULL,
                'category' => NULL,
                'cuisine' => NULL,
                'created_at' => '2025-01-03 15:11:38',
                'updated_at' => '2025-01-03 15:11:38',
                'site_link' => NULL,
            ),
            19 => 
