                'user_id' => 1,
                'description' => 'Vegan & gluten free grilled Mediterranean tofu kebabs served on a creamy bed of hummus with salad and pita. A flavorful, easy summer dinner!',
            'content' => '{"@context":"https:\\/\\/schema.org","@graph":[{"@type":"Article","@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#article","isPartOf":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/"},"author":{"name":"Lexi","@id":"https:\\/\\/www.crowdedkitchen.com\\/#\\/schema\\/person\\/252040e4d07d4a588923e54e2e9dbdb0"},"headline":"Mediterranean Grilled Tofu","datePublished":"2020-06-11T18:15:36+00:00","dateModified":"2020-09-29T01:34:26+00:00","wordCount":631,"commentCount":38,"publisher":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/#organization"},"image":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/mediterranean-grilled-tofu.jpg","articleSection":["Dairy Free","Dinner","Gluten Free","Main Dishes","Meal Prep Friendly","Nut Free","Reader Favorites","Summer","Tofu","Under 45 Minutes","Vegan","Vegetarian"],"inLanguage":"en-US","potentialAction":[{"@type":"CommentAction","name":"Comment","target":["https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#respond"]}]},{"@type":"WebPage","@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/","url":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/","name":"Mediterranean Grilled Tofu Kebabs (Vegan) - Crowded Kitchen","isPartOf":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/#website"},"primaryImageOfPage":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#primaryimage"},"image":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/mediterranean-grilled-tofu.jpg","datePublished":"2020-06-11T18:15:36+00:00","dateModified":"2020-09-29T01:34:26+00:00","description":"Vegan & gluten free grilled Mediterranean tofu kebabs served on a creamy bed of hummus with salad and pita. A flavorful, easy summer dinner!","breadcrumb":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#primaryimage","url":"https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/mediterranean-grilled-tofu.jpg","contentUrl":"https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/mediterranean-grilled-tofu.jpg","width":1200,"height":1200,"caption":"Vegan grilled tofu skewers served alongside a colorful fresh vegetable salad, perfect for a crowd or family dinner."},{"@type":"BreadcrumbList","@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/www.crowdedkitchen.com\\/"},{"@type":"ListItem","position":2,"name":"Recipes","item":"https:\\/\\/www.crowdedkitchen.com\\/recipe-index\\/"},{"@type":"ListItem","position":3,"name":"Tofu","item":"https:\\/\\/www.crowdedkitchen.com\\/category\\/tofu-recipes\\/"},{"@type":"ListItem","position":4,"name":"Mediterranean Grilled Tofu"}]},{"@type":"WebSite","@id":"https:\\/\\/www.crowdedkitchen.com\\/#website","url":"https:\\/\\/www.crowdedkitchen.com\\/","name":"Crowded Kitchen","description":"Delicious flexitarian recipes to help your family eat well together.","publisher":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/www.crowdedkitchen.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/www.crowdedkitchen.com\\/#organization","name":"Crowded Kitchen","url":"https:\\/\\/www.crowdedkitchen.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/www.crowdedkitchen.com\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2021\\/01\\/CK-Square-Logo-300x300-1.jpg","contentUrl":"https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2021\\/01\\/CK-Square-Logo-300x300-1.jpg","width":300,"height":300,"caption":"Crowded Kitchen"},"image":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/www.facebook.com\\/crowdedkitchen1","https:\\/\\/www.instagram.com\\/crowded_kitchen\\/","https:\\/\\/www.pinterest.com\\/crowdedkitchenblog\\/"]},{"@type":"Person","@id":"https:\\/\\/www.crowdedkitchen.com\\/#\\/schema\\/person\\/252040e4d07d4a588923e54e2e9dbdb0","name":"Lexi","sameAs":["https:\\/\\/www.crowdedkitchen.com\\/about\\/"],"url":"https:\\/\\/www.crowdedkitchen.com\\/author\\/asinclair16\\/"},{"@context":"https:\\/\\/schema.org\\/","@type":"Recipe","name":"Mediterranean Grilled Tofu","description":"These grilled tofu kebabs are marinated in a flavorful Mediterranean\\/Moroccan spice blend and charred to perfection. Best served over a bed of creamy hummus with pita and a simple salad!","author":{"@type":"Person","name":"Lexi","url":"https:\\/\\/www.crowdedkitchen.com\\/about\\/"},"keywords":"grilled Mediterranean tofu","image":["https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/mediterranean-grilled-tofu-225x225.jpg","https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/mediterranean-grilled-tofu-260x195.jpg","https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/mediterranean-grilled-tofu-320x180.jpg","https:\\/\\/www.crowdedkitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/mediterranean-grilled-tofu.jpg"],"url":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/","recipeIngredient":["1 package (14oz) extra firm tofu","1 tsp coconut sugar","1 tsp dried oregano","\\u00be tsp salt","\\u00bd tsp paprika","\\u00bd tsp garlic powder","\\u00bd tsp onion powder","\\u00bd tsp cumin","\\u00bd tsp turmeric","\\u00bc tsp coriander","\\u00bc tsp cinnamon","\\u00bc tsp cayenne\\u00a0","1\\/3 cup olive oil","2 tbsp freshly squeezed lemon juice","1 tbsp tomato paste","For serving: hummus, pita, salad"],"recipeInstructions":[{"@type":"HowToStep","text":"Drain excess water from tofu. Pat dry and wrap in a clean towel or paper towel. Set something heavy on top, like a cookbook, and let sit for at least 30 minutes-1 hour.\\u00a0","url":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#instruction-step-1"},{"@type":"HowToStep","text":"Heat grill to medium.","url":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#instruction-step-2"},{"@type":"HowToStep","text":"Slice tofu into cubes.\\u00a0","url":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#instruction-step-3"},{"@type":"HowToStep","text":"Whisk together all remaining ingredients until the spices are well incorporated into a paste.\\u00a0","url":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#instruction-step-4"},{"@type":"HowToStep","text":"Transfer tofu to skewers and brush with marinade. Let sit for 15 minutes, then grill for 3-5 minutes on each side, until slightly charred. Optional: brush with more marinade while they\'re grilling, or reserve some for serving.","url":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#instruction-step-5"},{"@type":"HowToStep","text":"Serve atop hummus with pita and a salad. Use any leftover marinade as a sauce. Enjoy!","url":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#instruction-step-6"}],"prepTime":"PT30M","cookTime":"PT15M","totalTime":"PT45M","recipeYield":["2","2 servings"],"recipeCategory":"Dinner","cookingMethod":"Grill","recipeCuisine":"Mediterranean","suitableForDiet":"VeganDiet","aggregateRating":{"@type":"AggregateRating","reviewCount":"17","ratingValue":"5"},"nutrition":{"servingSize":null,"calories":"605 calories","sugarContent":"4.4 g","sodiumContent":"889.1 mg","fatContent":"54.8 g","saturatedFatContent":"7.7 g","transFatContent":"0 g","carbohydrateContent":"12.6 g","fiberContent":"4 g","proteinContent":"20.9 g","cholesterolContent":"0 mg","@type":"nutritionInformation"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"author":{"@type":"Person","name":"Stephanie"},"datePublished":"2022-08-01","reviewBody":"The marinade was so flavorful and so easy to make!"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"author":{"@type":"Person","name":"Vicki"},"datePublished":"2023-02-07","reviewBody":"I used the spices in ziploc bag and added cut up tofu and 1\\/3 cup cornstarch. Shook all together and fried in small amount of oil. Came out crispy and put them in pitas with white sauce for gyros! Outstanding! This is the best spice marinade!!"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"author":{"@type":"Person","name":"Claire T"},"datePublished":"2023-09-12","reviewBody":"Truly some of the best tofu I\'ve ever had. It\'s super flavourful and slightly addicting. We served it with tumeric rice, greek salad, and tzetziki. Delicious!"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"author":{"@type":"Person","name":"Kyla"},"datePublished":"2026-05-05","reviewBody":"WOW, absolutely delicious!! The marinade is fantastic, I love that subtle note of cinnamon. This is definitely going to be a go-to recipe for me! I didn\\u2019t grill these today, but will do that next time. Today I baked them in the oven at 425 for 25 minutes and it turned out perfect."}],"datePublished":"2020-06-11","@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#recipe","isPartOf":{"@id":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/#article"},"mainEntityOfPage":"https:\\/\\/www.crowdedkitchen.com\\/mediterranean-grilled-tofu\\/"}]}',
                'image' => 'https://www.crowdedkitchen.com/wp-content/uploads/2020/08/mediterranean-grilled-tofu.jpg',
            'ingredients' => '["1 package (14oz) extra firm tofu","1 tsp coconut sugar","1 tsp dried oregano","\\u00be tsp salt","\\u00bd tsp paprika","\\u00bd tsp garlic powder","\\u00bd tsp onion powder","\\u00bd tsp cumin","\\u00bd tsp turmeric","\\u00bc tsp coriander","\\u00bc tsp cinnamon","\\u00bc tsp cayenne\\u00a0","1\\/3 cup olive oil","2 tbsp freshly squeezed lemon juice","1 tbsp tomato paste","For serving: hummus, pita, salad"]',
                'directions' => '["Drain excess water from tofu. Pat dry and wrap in a clean towel or paper towel. Set something heavy on top, like a cookbook, and let sit for at least 30 minutes-1 hour.\\u00a0","Heat grill to medium.","Slice tofu into cubes.\\u00a0","Whisk together all remaining ingredients until the spices are well incorporated into a paste.\\u00a0","Transfer tofu to skewers and brush with marinade. Let sit for 15 minutes, then grill for 3-5 minutes on each side, until slightly charred. Optional: brush with more marinade while they\'re grilling, or reserve some for serving.","Serve atop hummus with pita and a salad. Use any leftover marinade as a sauce. Enjoy!"]',
                'nutrition' => '[{"servingSize":null,"calories":"605 calories","sugarContent":"4.4 g","sodiumContent":"889.1 mg","fatContent":"54.8 g","saturatedFatContent":"7.7 g","transFatContent":"0 g","carbohydrateContent":"12.6 g","fiberContent":"4 g","proteinContent":"20.9 g","cholesterolContent":"0 mg","@type":"nutritionInformation"}]',
