            array (
                'id' => 23,
                'name' => 'Crema',
                'url' => 'https://cooking.nytimes.com/recipes/1018885-crema',
                'site_domain' => 'https//cooking.nytimes.com',
                'site_name' => 'Sam Sifton',
                'user_id' => 1,
            'description' => 'Crema is thinner than sour cream, a little more tangy and slightly salty. You can sometimes find it in stores, but it’s very simple to make at home by combining sour cream with heavy cream and lime juice (you could use buttermilk instead) and allowing it to set up at room temperature for a few hours, until it turns into a kind of liquid velvet. It’s marvelous with fish tacos, as a dressing for hot slaw, or drizzled over roasted carrots or sweet potatoes. Once you start using it, you will use it all the time.',
            'content' => '{"@context":"http:\\/\\/schema.org","@id":"nyt:\\/\\/recipe\\/904d3a3d-3b5b-5a73-8145-ff13914b8d20","@type":"Recipe","mainEntityOfPage":{"@id":"https:\\/\\/cooking.nytimes.com\\/recipes\\/1018885-crema","@type":"WebPage","name":"Crema"},"url":"https:\\/\\/cooking.nytimes.com\\/recipes\\/1018885-crema","name":"Crema","description":"Crema is thinner than sour cream, a little more tangy and slightly salty. You can sometimes find it in stores, but it\\u2019s very simple to make at home by combining sour cream with heavy cream and lime juice (you could use buttermilk instead) and allowing it to set up at room temperature for a few hours, until it turns into a kind of liquid velvet. It\\u2019s marvelous with fish tacos, as a dressing for hot slaw, or drizzled over roasted carrots or sweet potatoes. Once you start using it, you will use it all the time.","author":{"@type":"Person","name":"Sam Sifton"},"image":[{"@id":"nyt:\\/\\/image\\/bfd15189-ceb9-58f2-8789-e8493aeed871#videoSixteenByNineJumbo1600","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2017\\/08\\/06\\/magazine\\/06eat3\\/06eat3-videoSixteenByNineJumbo1600.jpg","creditText":"Gentl and Hyers for The New York Times. Food stylist: Maggie Ruggiero. Prop stylist: Amy Wilson.","dateModified":"2017-07-31T15:17:43.000Z","datePublished":"2017-07-31T18:01:16.000Z","height":"900","representativeOfPage":true,"uploadDate":"2017-07-31T18:01:16.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2017\\/08\\/06\\/magazine\\/06eat3\\/06eat3-videoSixteenByNineJumbo1600.jpg","width":"1600"},{"@id":"nyt:\\/\\/image\\/bfd15189-ceb9-58f2-8789-e8493aeed871#superJumbo","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2017\\/08\\/06\\/magazine\\/06eat3\\/06eat3-superJumbo.jpg","creditText":"Gentl and Hyers for The New York Times. Food stylist: Maggie Ruggiero. Prop stylist: Amy Wilson.","dateModified":"2017-07-31T15:17:43.000Z","datePublished":"2017-07-31T18:01:16.000Z","height":"1366","representativeOfPage":true,"uploadDate":"2017-07-31T18:01:16.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2017\\/08\\/06\\/magazine\\/06eat3\\/06eat3-superJumbo.jpg","width":"2048"},{"@id":"nyt:\\/\\/image\\/bfd15189-ceb9-58f2-8789-e8493aeed871#square640","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2017\\/08\\/06\\/magazine\\/06eat3\\/06eat3-square640.jpg","creditText":"Gentl and Hyers for The New York Times. Food stylist: Maggie Ruggiero. Prop stylist: Amy Wilson.","dateModified":"2017-07-31T15:17:43.000Z","datePublished":"2017-07-31T18:01:16.000Z","height":"640","representativeOfPage":true,"uploadDate":"2017-07-31T18:01:16.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2017\\/08\\/06\\/magazine\\/06eat3\\/06eat3-square640.jpg","width":"640"}],"totalTime":"PT2H5M","recipeYield":"","recipeCuisine":"","recipeCategory":"sauces and gravies","keywords":"heavy cream, lime, sour cream","aggregateRating":{"@type":"AggregateRating","ratingValue":4,"ratingCount":601},"nutrition":{"@context":"http:\\/\\/schema.org","@type":"NutritionInformation","calories":211,"unsaturatedFatContent":"6 grams","carbohydrateContent":"3 grams","cholesterolContent":null,"fatContent":"22 grams","fiberContent":"0 grams","proteinContent":"2 grams","saturatedFatContent":"13 grams","sodiumContent":"187 milligrams","sugarContent":"3 grams","transFatContent":"1 gram"},"recipeIngredient":["1 cup sour cream","1 cup heavy cream","1 teaspoon kosher salt","1 tablespoon freshly squeezed lime juice"],"recipeInstructions":[{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"Whisk the sour cream and heavy cream together in a bowl, then add the salt and the lime juice, and whisk again. Cover the bowl, and allow it to sit at room temperature for a minimum of 2 hours and ideally overnight. It will thicken nicely. Use right away, or transfer to a jar and store in the refrigerator until ready to use."}],"publisher":{"@id":"https:\\/\\/cooking.nytimes.com\\/#publisher","@type":"Organization","name":"NYT Cooking"},"review":[{"@type":"Review","author":{"@type":"Person","name":"DawnN"},"reviewBody":"How long will this keep in the fridge? ","datePublished":"2019-01-15T21:38:29.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Brian"},"reviewBody":"Sour cream","datePublished":"2019-04-13T22:30:21.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Judy"},"reviewBody":"If using buttermilk, sub for sour cream or heavy cream?","datePublished":"2019-01-13T18:01:41.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Kris Larsen"},"reviewBody":"The cremas I find at the store are thickened with carrageenan and xanthan gum. While these are fine products I prefer to not have them in yoghurt, buttermilk or sour cream. Plus I like that I can control the salt levels. The store bought crema Salvadore\\u00f1a is just too salty.","datePublished":"2018-05-19T14:25:13.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Carrie"},"reviewBody":"How long can I leave this in my fridge? If I make a small batch of slaw but a full batch of crema (to save for a later use), how long will it realistically stay usable?","datePublished":"2017-10-01T17:48:43.000Z"},{"@type":"Review","author":{"@type":"Person","name":"ADR"},"reviewBody":"Can use buttermilk instead of heavy cream per related article.","datePublished":"2017-10-01T17:51:10.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Chris"},"reviewBody":"For what it\'s worth, my last batch remained emulsified for about a week before starting to separate.","datePublished":"2017-10-01T19:17:48.000Z"}],"copyrightHolder":{"@id":"https:\\/\\/cooking.nytimes.com\\/#publisher","@type":"Organization","name":"NYT Cooking"},"copyrightYear":2017}',
                'image' => 'https://static01.nyt.com/images/2017/08/06/magazine/06eat3/06eat3-videoSixteenByNineJumbo1600.jpg',
                'ingredients' => '["1 cup sour cream","1 cup heavy cream","1 teaspoon kosher salt","1 tablespoon freshly squeezed lime juice"]',
                'directions' => '["Whisk the sour cream and heavy cream together in a bowl, then add the salt and the lime juice, and whisk again. Cover the bowl, and allow it to sit at room temperature for a minimum of 2 hours and ideally overnight. It will thicken nicely. Use right away, or transfer to a jar and store in the refrigerator until ready to use."]',
