            array (
                'id' => 26,
                'name' => 'Creamy Jalapeno Sauce Recipe',
                'url' => 'https://urbancowgirllife.com/creamy-jalapeno-sauce-recipe/',
                'site_domain' => 'https://urbancowgirllife.com/',
                'site_name' => 'Urban Cowgirl',
                'user_id' => 1,
                'description' => 'This fiery, creamy jalapeno puree is offered up at taquerias around the southwest. Let\'s learn to make a batch of our very own!',
            'content' => '{"@context":"https:\\/\\/schema.org","@graph":[{"@type":"Article","@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#article","isPartOf":{"@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/"},"author":{"name":"Sarah Penrod","@id":"https:\\/\\/urbancowgirllife.com\\/#\\/schema\\/person\\/154a144724f4c58d7dc8a057306a9f4c"},"headline":"Creamy Jalapeno Sauce Recipe","datePublished":"2020-09-16T18:29:15+00:00","dateModified":"2025-02-13T15:39:06+00:00","wordCount":724,"commentCount":34,"publisher":{"@id":"https:\\/\\/urbancowgirllife.com\\/#organization"},"image":{"@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/urbancowgirllife.com\\/wp-content\\/uploads\\/2020\\/09\\/creamy-jalapeno-sauce-recipe-1.jpg","keywords":["jalapeno","mexican food","sauce","tex mex recipes"],"articleSection":["Sauces &amp; Condiments","Tex Mex","Texas"],"inLanguage":"en-US","potentialAction":[{"@type":"CommentAction","name":"Comment","target":["https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#respond"]}]},{"@type":"WebPage","@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/","name":"Creamy Jalapeno Sauce Recipe | Urban Cowgirl","isPartOf":{"@id":"https:\\/\\/urbancowgirllife.com\\/#website"},"primaryImageOfPage":{"@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#primaryimage"},"image":{"@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/urbancowgirllife.com\\/wp-content\\/uploads\\/2020\\/09\\/creamy-jalapeno-sauce-recipe-1.jpg","datePublished":"2020-09-16T18:29:15+00:00","dateModified":"2025-02-13T15:39:06+00:00","description":"This fiery, creamy jalapeno puree is offered up at taquerias around the southwest. Let\'s learn to make a batch of our very own!","breadcrumb":{"@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#primaryimage","url":"https:\\/\\/urbancowgirllife.com\\/wp-content\\/uploads\\/2020\\/09\\/creamy-jalapeno-sauce-recipe-1.jpg","contentUrl":"https:\\/\\/urbancowgirllife.com\\/wp-content\\/uploads\\/2020\\/09\\/creamy-jalapeno-sauce-recipe-1.jpg","width":985,"height":1478,"caption":"A squeeze bottle of creamy jalapeno sauce standing in front of a plate of tacos."},{"@type":"BreadcrumbList","@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/urbancowgirllife.com\\/"},{"@type":"ListItem","position":2,"name":"Texas Recipes","item":"https:\\/\\/urbancowgirllife.com\\/category\\/texas-recipes\\/"},{"@type":"ListItem","position":3,"name":"Creamy Jalapeno Sauce Recipe"}]},{"@type":"WebSite","@id":"https:\\/\\/urbancowgirllife.com\\/#website","url":"https:\\/\\/urbancowgirllife.com\\/","name":"Urban Cowgirl","description":"Texas Recipes, Tex Mex, &amp; Barbecue Tutorials For The Modern Southern Family","publisher":{"@id":"https:\\/\\/urbancowgirllife.com\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/urbancowgirllife.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/urbancowgirllife.com\\/#organization","name":"Urban Cowgirl","url":"https:\\/\\/urbancowgirllife.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/urbancowgirllife.com\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/urbancowgirllife.com\\/wp-content\\/uploads\\/2016\\/11\\/logotest.png","contentUrl":"https:\\/\\/urbancowgirllife.com\\/wp-content\\/uploads\\/2016\\/11\\/logotest.png","width":350,"height":70,"caption":"Urban Cowgirl"},"image":{"@id":"https:\\/\\/urbancowgirllife.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/www.facebook.com\\/SarahPenrodChef\\/","https:\\/\\/x.com\\/Chefforlife","http:\\/\\/www.instagram.com\\/UrbanCowgirl"]},{"@type":"Person","@id":"https:\\/\\/urbancowgirllife.com\\/#\\/schema\\/person\\/154a144724f4c58d7dc8a057306a9f4c","name":"Sarah Penrod","image":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/efbe4f5174fad4fb4873e8115e619bfc5083824a44334f0730d4dfa283df48da?s=96&d=mm&r=g","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/efbe4f5174fad4fb4873e8115e619bfc5083824a44334f0730d4dfa283df48da?s=96&d=mm&r=g","contentUrl":"https:\\/\\/secure.gravatar.com\\/avatar\\/efbe4f5174fad4fb4873e8115e619bfc5083824a44334f0730d4dfa283df48da?s=96&d=mm&r=g","caption":"Sarah Penrod"},"description":"Sarah Penrod is the bestselling author of The Urban Cowgirl Cookbook, and a professional chef in Dallas, Texas. She can be seen on Food Network, Good Morning Texas, Hallmark Home and Family, Everyday with Rachel Ray, and on her youtube channel, The Urban Cowgirl.","sameAs":["https:\\/\\/urbancowgirllife.com","https:\\/\\/www.facebook.com\\/SarahPenrodChef\\/","http:\\/\\/www.instagram.com\\/urbancowgirl","https:\\/\\/x.com\\/ChefForLife","www.Youtube.com\\/TheUrbanCowgirl"]},{"@type":"Recipe","name":"Creamy Jalapeno Sauce Recipe","author":{"@id":"https:\\/\\/urbancowgirllife.com\\/#\\/schema\\/person\\/154a144724f4c58d7dc8a057306a9f4c"},"description":"This thick and creamy, super SPICY, bursting-with-jalapeno green sauce is GOOD ON EVERYTHING from chips to tacos.","datePublished":"2020-09-16T13:29:15+00:00","image":["https:\\/\\/urbancowgirllife.com\\/wp-content\\/uploads\\/2020\\/09\\/creamy-jalapeno-sauce-recipe-6.jpg"],"recipeYield":["3","3 cups"],"prepTime":"PT5M","cookTime":"PT20M","totalTime":"PT30M","recipeIngredient":["16 fresh jalapeno peppers","1 white onion","8 garlic cloves","2 t. kosher salt","\\u00bd c. avocado oil (or any fresh flavorless oil)","1 \\u00bd T. fresh lime juice (about 1 whole lime)"],"recipeInstructions":[{"@type":"HowToStep","text":"Fill a large stockpot halfway with water and add 1 t. salt,begin heating over high heat.","name":"Fill a large stockpot halfway with water and add 1 t. salt,begin heating over high heat.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-0"},{"@type":"HowToStep","text":"Meanwhile, remove the peel off one white onion and quarterthe onion, place in a bowl.","name":"Meanwhile, remove the peel off one white onion and quarterthe onion, place in a bowl.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-1"},{"@type":"HowToStep","text":"Wash the jalapeno peppers well, drain, and place in the bowlwith the onion.","name":"Wash the jalapeno peppers well, drain, and place in the bowlwith the onion.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-2"},{"@type":"HowToStep","text":"From a large bulb of garlic, break up 8 cloves. You can cookthe garlic in their husks, and it will eventually fall off, so no need to peelthem. Place them in the bowl.","name":"From a large bulb of garlic, break up 8 cloves. You can cookthe garlic in their husks, and it will eventually fall off, so no need to peelthem. Place them in the bowl.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-3"},{"@type":"HowToStep","text":"Take all of the vegetables in the bowl and carefully pourthem into the stockpot. Bring the water to a boil, then reduce the heat untilthe water is just at a simmer.","name":"Take all of the vegetables in the bowl and carefully pourthem into the stockpot. Bring the water to a boil, then reduce the heat untilthe water is just at a simmer.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-4"},{"@type":"HowToStep","text":"Simmer the vegetables for approximately 20 minutes. Thejalapenos and onion should be soft, and the peppers should be an army green.The garlic will fall from its husks. Drain the veggies from the water and placeinto the bowl of a blender.","name":"Simmer the vegetables for approximately 20 minutes. Thejalapenos and onion should be soft, and the peppers should be an army green.The garlic will fall from its husks. Drain the veggies from the water and placeinto the bowl of a blender.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-5"},{"@type":"HowToStep","text":"Add 2 t. kosher salt (you may want to start with 1 t. salt andwork your way up if you are using table salt to see if you need a full 2 t.). Add \\u00bd c. avocado oil and 1 \\u00bd T fresh lime juice.","name":"Add 2 t. kosher salt (you may want to start with 1 t. salt andwork your way up if you are using table salt to see if you need a full 2 t.). Add \\u00bd c. avocado oil and 1 \\u00bd T fresh lime juice.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-6"},{"@type":"HowToStep","text":"Place the lid on the blender and blend 1 full minute. Tastefor seasoning. You may want to add additional salt or lime juice if needed. Iffor any reason you need to thin the puree, add 1 T. water at a time until theblender moves easily.","name":"Place the lid on the blender and blend 1 full minute. Tastefor seasoning. You may want to add additional salt or lime juice if needed. Iffor any reason you need to thin the puree, add 1 T. water at a time until theblender moves easily.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-7"},{"@type":"HowToStep","text":"Pour the jalapeno cream into squeeze bottles and chill. Thissauce should be stored in the refrigerator and lasts about 10 days.","name":"Pour the jalapeno cream into squeeze bottles and chill. Thissauce should be stored in the refrigerator and lasts about 10 days.","url":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#wprm-recipe-5000-step-0-8"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"4.69","ratingCount":"73","reviewCount":"5"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Living in Houston, TX means we make lots of tex-mex dishes. I had concerns about using whole, unseeded jalape\\u00f1os and I was right. Jalape\\u00f1os can vary widely in heat level and I must gotten all really hot ones. Had to seriously dilute with sour cream and even then it was too hot for my family.","author":{"@type":"Person","name":"James"},"datePublished":"2023-09-15"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I made this sauce this morning for today\'s lunch. The flavor of it was AMAZING!! The only issue is, why on earth did it turn brown?? Have you ever had this happen?","author":{"@type":"Person","name":"Jessica Bivins"},"datePublished":"2023-08-29"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I\'m so glad I found this recipe. I\'ve been looking for something that was a little more versatile and we\'ve been putting it on tacos, fajitas, even nachos! You name the type of tex mex and we\'re putting it on there! The flavor and thickness of this sauce was something to behold for sure.","author":{"@type":"Person","name":"Sergio"},"datePublished":"2023-06-26"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Fellow N Texan here! I love this Taqueria salsa but haven\\u2019t had any luck replicating it. I\\u2019m going to try yours. Have you ever thought about smoking the veggies to bring a smoky element to this?","author":{"@type":"Person","name":"Aaron"},"datePublished":"2023-05-28"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"@Mary, I make a green sauce that I found on Pinterest (can\\u2019t remember the name) that uses a LOT of cilantro, jalape\\u00f1o, oil, and I forget what else. It is amazing! You throw everything into the food processor and you\\u2019re done. You can use this recipe and add cilantro.","author":{"@type":"Person","name":"Marlene"},"datePublished":"2023-05-08"}],"recipeCategory":["Sauces &amp; Condiments"],"recipeCuisine":["Tex Mex"],"@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#recipe","isPartOf":{"@id":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/#article"},"mainEntityOfPage":"https:\\/\\/urbancowgirllife.com\\/creamy-jalapeno-sauce-recipe\\/"}]}',
                'image' => 'https://urbancowgirllife.com/wp-content/uploads/2020/09/creamy-jalapeno-sauce-recipe-1.jpg',
            'ingredients' => '["16 fresh jalapeno peppers","1 white onion","8 garlic cloves","2 t. kosher salt","\\u00bd c. avocado oil (or any fresh flavorless oil)","1 \\u00bd T. fresh lime juice (about 1 whole lime)"]',
            'directions' => '["Fill a large stockpot halfway with water and add 1 t. salt,begin heating over high heat.","Meanwhile, remove the peel off one white onion and quarterthe onion, place in a bowl.","Wash the jalapeno peppers well, drain, and place in the bowlwith the onion.","From a large bulb of garlic, break up 8 cloves. You can cookthe garlic in their husks, and it will eventually fall off, so no need to peelthem. Place them in the bowl.","Take all of the vegetables in the bowl and carefully pourthem into the stockpot. Bring the water to a boil, then reduce the heat untilthe water is just at a simmer.","Simmer the vegetables for approximately 20 minutes. Thejalapenos and onion should be soft, and the peppers should be an army green.The garlic will fall from its husks. Drain the veggies from the water and placeinto the bowl of a blender.","Add 2 t. kosher salt (you may want to start with 1 t. salt andwork your way up if you are using table salt to see if you need a full 2 t.). Add \\u00bd c. avocado oil and 1 \\u00bd T fresh lime juice.","Place the lid on the blender and blend 1 full minute. Tastefor seasoning. You may want to add additional salt or lime juice if needed. Iffor any reason you need to thin the puree, add 1 T. water at a time until theblender moves easily.","Pour the jalapeno cream into squeeze bottles and chill. Thissauce should be stored in the refrigerator and lasts about 10 days."]',
