            27 => 
            array (
                'id' => 28,
                'name' => 'Creamy Coconut-Lime Rice With Peanuts',
                'url' => 'https://cooking.nytimes.com/recipes/1025612-creamy-coconut-lime-rice-with-peanuts',
                'site_domain' => 'https//cooking.nytimes.com',
                'site_name' => 'Christian Reynoso',
                'user_id' => 1,
                'description' => 'Coconut milk does double duty here in this light yet hearty rice dish that straddles the line between side salad and pilaf-like main. First the rice is simmered in creamy coconut milk, then the remaining milk is used to make a soothing dressing spiked with lime juice, peanut butter, toasted peanuts and garlic, with a little added heat from chile sauce. Fresh cherry tomatoes and chopped herbs turn it all into a rice salad that can be a flavorful side for grilled chicken or the base for fried eggs. ',
            'content' => '{"@context":"http:\\/\\/schema.org","@id":"nyt:\\/\\/recipe\\/563c6123-36a6-582d-badc-425a6f40c575","@type":"Recipe","mainEntityOfPage":{"@id":"https:\\/\\/cooking.nytimes.com\\/recipes\\/1025612-creamy-coconut-lime-rice-with-peanuts","@type":"WebPage","name":"Creamy Coconut-Lime Rice With Peanuts"},"url":"https:\\/\\/cooking.nytimes.com\\/recipes\\/1025612-creamy-coconut-lime-rice-with-peanuts","name":"Creamy Coconut-Lime Rice With Peanuts","description":"Coconut milk does double duty here in this light yet hearty rice dish that straddles the line between side salad and pilaf-like main. First the rice is simmered in creamy coconut milk, then the remaining milk is used to make a soothing dressing spiked with lime juice, peanut butter, toasted peanuts and garlic, with a little added heat from chile sauce. Fresh cherry tomatoes and chopped herbs turn it all into a rice salad that can be a flavorful side for grilled chicken or the base for fried eggs.\\u00a0","author":{"@type":"Person","name":"Christian Reynoso"},"image":[{"@id":"nyt:\\/\\/image\\/9eb6584d-c0dd-5a66-aeb7-90eed9378279#videoSixteenByNineJumbo1600","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2024\\/06\\/21\\/multimedia\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt-videoSixteenByNineJumbo1600.jpg","creditText":"Armando Rafael for The New York Times. Food Stylist: Cyd Raftus McDowell.","dateModified":"2024-06-20T16:05:35.600Z","datePublished":"2024-06-20T16:05:35.600Z","height":"900","representativeOfPage":true,"uploadDate":"2024-06-20T16:05:35.600Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2024\\/06\\/21\\/multimedia\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt-videoSixteenByNineJumbo1600.jpg","width":"1600"},{"@id":"nyt:\\/\\/image\\/9eb6584d-c0dd-5a66-aeb7-90eed9378279#googleFourByThree","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2024\\/06\\/21\\/multimedia\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt-googleFourByThree.jpg","creditText":"Armando Rafael for The New York Times. Food Stylist: Cyd Raftus McDowell.","dateModified":"2024-06-20T16:05:35.600Z","datePublished":"2024-06-20T16:05:35.600Z","height":"600","representativeOfPage":true,"uploadDate":"2024-06-20T16:05:35.600Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2024\\/06\\/21\\/multimedia\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt-googleFourByThree.jpg","width":"800"},{"@id":"nyt:\\/\\/image\\/9eb6584d-c0dd-5a66-aeb7-90eed9378279#mediumSquareAt3X","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2024\\/06\\/21\\/multimedia\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt-mediumSquareAt3X.jpg","creditText":"Armando Rafael for The New York Times. Food Stylist: Cyd Raftus McDowell.","dateModified":"2024-06-20T16:05:35.600Z","datePublished":"2024-06-20T16:05:35.600Z","height":"1800","representativeOfPage":true,"uploadDate":"2024-06-20T16:05:35.600Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2024\\/06\\/21\\/multimedia\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt\\/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt-mediumSquareAt3X.jpg","width":"1800"}],"prepTime":"PT10M","cookTime":"PT20M","totalTime":"PT30M","recipeYield":"4 servings","recipeCuisine":"","recipeCategory":"dinner, easy, lunch, quick, weeknight, grains and rice, main course, side dish","keywords":"cherry tomato, cilantro, coconut milk, dill, jasmine rice, lime, mint, peanut, peanut butter, sambal oelek, stovetop, summer, vegetarian","aggregateRating":{"@type":"AggregateRating","ratingValue":5,"ratingCount":1822},"nutrition":{"@context":"http:\\/\\/schema.org","@type":"NutritionInformation","calories":591,"unsaturatedFatContent":"11 grams","carbohydrateContent":"65 grams","cholesterolContent":null,"fatContent":"35 grams","fiberContent":"9 grams","proteinContent":"14 grams","saturatedFatContent":"21 grams","sodiumContent":"710 milligrams","sugarContent":"7 grams","transFatContent":"0 grams"},"recipeIngredient":["1 cup uncooked jasmine rice, rinsed","1 (13- to 14-ounce) can coconut milk\\u00a0","Salt and pepper\\u00a0","1 (1 1\\/2-inch) piece ginger","2 large garlic cloves","2 limes\\u00a0","1\\/2 cup roasted and salted peanuts, crushed","2 tablespoons peanut butter","2 teaspoons granulated sugar","2 teaspoons sambal oelek\\u00a0","2 cups ripe cherry tomatoes, halved (about 10 ounces)","1 cup roughly chopped mixed herbs (such as dill, cilantro or mint)"],"recipeInstructions":[{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"Cook the rice according to the packaging instructions until tender, replacing 1 1\\/4 cups of the cooking water with 1 1\\/4 cups of the coconut milk. Fluff the cooked rice with a fork, transfer to a serving bowl and season with salt and pepper \\u2014 it should taste well-seasoned and almost buttery \\u2014 and let cool."},{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"While the rice is cooking, add 1\\/4 cup coconut milk to another bowl. Finely grate the ginger and garlic into the bowl, followed by the zest of 1 lime. Then, juice both limes into the bowl. Whisk in 1\\/4 cup of the peanuts, the peanut butter, sugar and sambal and season with salt."},{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"When ready to serve, add the tomatoes and 3\\/4 cup of the herbs to the bowl with the rice. Pour in the coconut dressing, toss well to coat, season with pepper and top with remaining 1\\/4 cup crushed peanuts and 1\\/4 cup herbs. For the best flavor, serve at room temperature the day it\\u2019s made."}],"publisher":{"@id":"https:\\/\\/cooking.nytimes.com\\/#publisher","@type":"Organization","name":"NYT Cooking"},"datePublished":"2024-06-21T00:00:00.000Z","dateModified":"2024-06-28T15:19:31.000Z","review":[{"@type":"Review","author":{"@type":"Person","name":"Jimbo"},"reviewBody":"I\'ve been using NYT Cooking for years and this is the first time I\'ve been inclined to comment on a recipe. WOW! This was amazing. I used diced mango in place of cherry tomatoes because my husband is not a tomato fan. This will definitely be a regular in our meal rotation.\\nThank you Christian!","datePublished":"2025-04-03T15:52:51.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Michelle"},"reviewBody":"I bought my usual coconut milk that I use for other dishes and enjoy but this tasted like coconut sunscreen. Didn\'t enjoy at all.","datePublished":"2025-04-03T00:59:55.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Kathy"},"reviewBody":"I eyeballed the entire recipe. It came out well. I substituted harissa for sambal oelek and thought it was fine. (Not that I know what anything should taste like).","datePublished":"2025-04-03T01:46:10.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Shelby"},"reviewBody":"I love when I make something and even before finishing I\'m confident that it\'ll make its way into regular rotation. FWIW I followed the rice package instructions rather than the recipe\'s, so used 1 cup rice to 1.5c coconut milk (no water) in a rice cooker and it came out great. Depending on season, the tomatoes could easily be subbed out for whatever crunchy veg you want to add in. Paired this with the easy Miso Chicken recipe and it was a huge hit.","datePublished":"2025-04-02T18:54:36.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Arlene Steffen"},"reviewBody":"Margaret Curry:\\n Best Sambal Oelek Substitutes\\n1. Sriracha\\n2. Tabasco \\/ Other Hot Sauce\\n3. Gochujang\\n4. Hot Chilli Powder or Chilli Flakes\\n5. Chilli Bean Paste","datePublished":"2025-04-02T11:35:59.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Mr. MoJumbo"},"reviewBody":"Swap cherry tomatoes for chopped mango, and add ground chicken cooked with soy sauce, ginger, and black vinegar - WOW!","datePublished":"2025-04-02T00:00:12.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Patrick W."},"reviewBody":"Banger! Quick, simple and delicious. My partner accidentally bought honey roasted peanuts, but no problemo\\u2014just skipped the granulated sugar and everything was just fine.","datePublished":"2025-04-02T02:54:40.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Dana"},"reviewBody":"This is yummy and I really appreciate all the comments and ideas. I added tofu per one comment and cucumber per another. Delicious.","datePublished":"2025-04-01T00:25:29.000Z"},{"@type":"Review","author":{"@type":"Person","name":"David P"},"reviewBody":"Tasty, but honestly, too much effort for a side dish. I added more sambal oelek in individual servings to brighten up the general mushiness.","datePublished":"2025-03-29T21:59:55.000Z"},{"@type":"Review","author":{"@type":"Person","name":"ARS"},"reviewBody":"Blistering the tomatoes is a great way to bring out their flavor!","datePublished":"2025-03-25T07:12:43.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Sandra"},"reviewBody":"Does anyone else feel like the sauce should have been cooked a bit? I love garlic, but the raw garlic flavor was strong and in general, the flavors didn\'t meld together. Something was too much: the lime, ginger or sambal oelek. I added more peanut butter and a bit more sugar to tone it down. Next time, I will simmer the sauce before i pour it over the rice. There\'s nothing wrong with serving this warm. Good idea for a dish tho","datePublished":"2025-03-23T23:51:34.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Sibyl"},"reviewBody":"It was fine. Basically the juice wasn\\u2019t worth the squeeze on this one. Getting the rice to cook completely in the coconut wasn\\u2019t easy. Removing from my saved.","datePublished":"2025-03-22T12:25:55.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Fukaeri"},"reviewBody":"This recipe takes you directly to Thailand. Amazing, cheap, simple and fast. I added just one teaspoon of sambal oelek and juice from one lemon and it was perfect. The dressing is so good that it deserves a separate recipe.","datePublished":"2025-03-18T12:03:44.000Z"},{"@type":"Review","author":{"@type":"Person","name":"A Female Texan"},"reviewBody":"I found no need to make a half-recipe if only cooking for one or two, since it\\u2019s noted as being best served room-temp the day of preparation. This dish keeps well overnight, reheated in a skillet, to where the coconut rice is just shy of a crisp crust and served as a side dish.","datePublished":"2025-03-16T17:33:26.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Sandra"},"reviewBody":"Great ideas. I would have liked all your changes.","datePublished":"2025-03-23T23:53:12.000Z"},{"@type":"Review","author":{"@type":"Person","name":"David P"},"reviewBody":"Fish sauce and rice vinegar are a great addition.","datePublished":"2025-03-29T22:05:28.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Jason K"},"reviewBody":"This dish was too limey, would have been better by exchanging 1 lime for fish sauce and rice vinegar. I like the idea of coconutting the rice, now need to perfect the flavor. We added steamed green beans and minced pork to round it out.","datePublished":"2025-03-14T00:19:05.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Sheri I."},"reviewBody":"This seems like it would be delicious with mango instead of tomatoes and a very finely minced serrano pepper added to the dressing. Also wishing NYT Cooking had a place to put your own notes in a recipe so it shows up when you go to make it again.","datePublished":"2024-06-27T00:00:25.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Margaret Curry"},"reviewBody":"Would siracha sub for the sambal oelek and sugar?","datePublished":"2024-06-26T15:20:29.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Kimberly Call"},"reviewBody":"What is missing in this recipe is this - instead of saying just x amount of coconut milk will replace water in recipe - we need to know ALSO roughly what % of the water are we replacing, for the size of the batch of rice cooked will vary and thus the ratio, taste and effect of the milk in the rice will vary greatly - please advise? Thank you","datePublished":"2024-06-26T17:06:16.000Z"},{"@type":"Review","author":{"@type":"Person","name":"marielle van strijp"},"reviewBody":"I put a diced mango in the rice and used cashews instead of peanuts. Delicious.","datePublished":"2024-06-27T16:55:19.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Jackie"},"reviewBody":"Laura, I make coconut rice in my rice cooker, subbing half the water with full fat coconut milk. It comes out great. I wouldn\\u2019t do it with all coconut milk though - I think it would gum up the steam vent.","datePublished":"2024-06-26T16:04:13.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Tara W"},"reviewBody":"I made this for lunch today exactly as written and it came out perfectly. The very first thing I did was wash the herbs (basil, cilantro) and set them out to dry. Then, I sliced the cherry tomatoes, lightly salted and drained them for a bit of time so as to not add moisture to the salad. Made the rice on the stove top, put everything together, and my vegan gluten-free guests loved it. It\\u2019s very filling. I served some fresh pineapple chunks on the side.","datePublished":"2024-06-26T22:14:55.000Z"},{"@type":"Review","author":{"@type":"Person","name":"SusanW"},"reviewBody":"@Sheri I.: You can post a \\"private\\" note instead of a \\"public\\" note; see the options below the \\"Add note\\" box.","datePublished":"2024-06-27T17:38:47.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Chantal"},"reviewBody":"I think depending on which chili sauce and herbs you use, you could mend it to various cuisines from South East Asia. You could use Sriracha, mint, dill and make it one way or chile crisp, Thai basil, cilantro and go in another direction.","datePublished":"2024-06-26T16:23:45.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Eric"},"reviewBody":"Is gochujang a good substitute for sambal oelek?","datePublished":"2024-06-26T16:07:52.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Mark Lynn"},"reviewBody":"This makes a great breakfast with a fried egg on top. A great lunch or dinner with dosas or roti and grilled veggies.","datePublished":"2024-06-26T16:02:37.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Merit Scotford"},"reviewBody":"All I had were honey roasted peanuts so I used those and left out the sugar. Fantastic!","datePublished":"2024-06-26T16:05:27.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Lauren J (Seattle)"},"reviewBody":"I defrosted and squeezed the water out of firm tofu, crumbled and pan fried it, and added it to the rice for more protein as a full dinner. We also enjoyed diced baby cucumber added in with the tomatoes.","datePublished":"2024-07-13T03:39:58.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Ashley"},"reviewBody":"This sauce made me weak in the knees. I\'m saving half and putting it on noodles tomorrow.","datePublished":"2024-06-26T17:26:15.000Z"},{"@type":"Review","author":{"@type":"Person","name":"kathybc"},"reviewBody":"Didn\\u2019t have sambal oelek and subbed gochujang. Didn\\u2019t miss the acid as the lime juice and tomatoes were enough.","datePublished":"2024-06-26T16:58:23.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Jeremy"},"reviewBody":"The recipe calls for 1 cup of rice, so I\'m not sure why the rice batch size would vary. Lundberg jasmine rice calls for 1.5 cups of water per 1 cup of uncooked rice, so 1.25 cups of coconut milk and 0.25 cups of water.","datePublished":"2024-06-27T18:31:02.000Z"}],"copyrightHolder":{"@id":"https:\\/\\/cooking.nytimes.com\\/#publisher","@type":"Organization","name":"NYT Cooking"},"copyrightYear":2024}',
                'image' => 'https://static01.nyt.com/images/2024/06/21/multimedia/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt/cr-Creamy-Coconut-Rice-With-Tomatoesrex-cfgt-videoSixteenByNineJumbo1600.jpg',
            'ingredients' => '["1 cup uncooked jasmine rice, rinsed","1 (13- to 14-ounce) can coconut milk\\u00a0","Salt and pepper\\u00a0","1 (1 1\\/2-inch) piece ginger","2 large garlic cloves","2 limes\\u00a0","1\\/2 cup roasted and salted peanuts, crushed","2 tablespoons peanut butter","2 teaspoons granulated sugar","2 teaspoons sambal oelek\\u00a0","2 cups ripe cherry tomatoes, halved (about 10 ounces)","1 cup roughly chopped mixed herbs (such as dill, cilantro or mint)"]',
                'directions' => '["Cook the rice according to the packaging instructions until tender, replacing 1 1\\/4 cups of the cooking water with 1 1\\/4 cups of the coconut milk. Fluff the cooked rice with a fork, transfer to a serving bowl and season with salt and pepper \\u2014 it should taste well-seasoned and almost buttery \\u2014 and let cool.","While the rice is cooking, add 1\\/4 cup coconut milk to another bowl. Finely grate the ginger and garlic into the bowl, followed by the zest of 1 lime. Then, juice both limes into the bowl. Whisk in 1\\/4 cup of the peanuts, the peanut butter, sugar and sambal and season with salt.","When ready to serve, add the tomatoes and 3\\/4 cup of the herbs to the bowl with the rice. Pour in the coconut dressing, toss well to coat, season with pepper and top with remaining 1\\/4 cup crushed peanuts and 1\\/4 cup herbs. For the best flavor, serve at room temperature the day it\\u2019s made."]',
                'nutrition' => '{"@context":"http:\\/\\/schema.org","@type":"NutritionInformation","calories":591,"unsaturatedFatContent":"11 grams","carbohydrateContent":"65 grams","cholesterolContent":null,"fatContent":"35 grams","fiberContent":"9 grams","proteinContent":"14 grams","saturatedFatContent":"21 grams","sodiumContent":"710 milligrams","sugarContent":"7 grams","transFatContent":"0 grams"}',
                'slug' => 'creamy-coconut-lime-rice-with-peanuts',
                'raw_data' => NULL,
                'category' => NULL,
                'cuisine' => NULL,
                'created_at' => '2025-04-05 12:31:56',
                'updated_at' => '2025-04-05 12:31:56',
                'site_link' => NULL,
            ),
