            'content' => '{"@context":"https:\\/\\/schema.org","@graph":[{"@type":"Article","@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#article","isPartOf":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/"},"author":{"name":"Monique Volz","@id":"https:\\/\\/www.ambitiouskitchen.com\\/#\\/schema\\/person\\/1c82f82166ff54c01fa010babe96c5bc"},"headline":"Chipotle Black Bean Roasted Veggie Enchilada Casserole","datePublished":"2025-08-10T16:00:07+00:00","dateModified":"2025-08-11T00:27:56+00:00","wordCount":1582,"commentCount":164,"publisher":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/#organization"},"image":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/enchiladacasserole-5.jpg","articleSection":["Ambitious Kitchen Favorites","Cooking Methods","Diet Type","Dinner","Easter","Fall","Food","Freezer-Friendly","Global Inspiration","Gluten Free","Gluten Free Dinner","Gluten Free Tacos &amp; Enchiladas","Hispanic","Holiday Recipes","Kid-Friendly","Kid-Friendly Dinner","Meal Prep","Seasonal","Spring","Tacos + Enchiladas","Vegetarian","Vegetarian Dinner","Vegetarian Tacos &amp; Enchiladas"],"inLanguage":"en-US","potentialAction":[{"@type":"CommentAction","name":"Comment","target":["https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#respond"]}]},{"@type":"WebPage","@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/","url":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/","name":"Chipotle Black Bean Veggie Enchilada Casserole | Ambitious Kitchen","isPartOf":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/#website"},"primaryImageOfPage":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#primaryimage"},"image":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/enchiladacasserole-5.jpg","datePublished":"2025-08-10T16:00:07+00:00","dateModified":"2025-08-11T00:27:56+00:00","description":"The BEST easy vegetarian enchilada casserole packed with veggies, black beans, corn tortillas, a homemade chipotle enchilada sauce & cheese.","breadcrumb":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#primaryimage","url":"https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/enchiladacasserole-5.jpg","contentUrl":"https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/enchiladacasserole-5.jpg","width":822,"height":1200,"caption":"lifting a slice of healthy enchilada casserole out of a baking dish"},{"@type":"BreadcrumbList","@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/www.ambitiouskitchen.com\\/"},{"@type":"ListItem","position":2,"name":"Blog","item":"https:\\/\\/www.ambitiouskitchen.com\\/blog\\/"},{"@type":"ListItem","position":3,"name":"Chipotle Black Bean Roasted Veggie Enchilada Casserole"}]},{"@type":"WebSite","@id":"https:\\/\\/www.ambitiouskitchen.com\\/#website","url":"https:\\/\\/www.ambitiouskitchen.com\\/","name":"Ambitious Kitchen","description":"Inspiring you in and out of the kitchen","publisher":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/www.ambitiouskitchen.com\\/?s={search_term_string}"},"query-input":"required name=search_term_string"}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/www.ambitiouskitchen.com\\/#organization","name":"Ambitious Kitchen","url":"https:\\/\\/www.ambitiouskitchen.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/www.ambitiouskitchen.com\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/2020\\/05\\/AK-for-small-sizes.png","contentUrl":"https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/2020\\/05\\/AK-for-small-sizes.png","width":900,"height":900,"caption":"Ambitious Kitchen"},"image":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/www.facebook.com\\/ambitiouskitchen","https:\\/\\/twitter.com\\/ambitiouskitch","https:\\/\\/www.instagram.com\\/ambitiouskitchen\\/","https:\\/\\/www.pinterest.com\\/moniquevolz\\/"]},{"@type":"Person","@id":"https:\\/\\/www.ambitiouskitchen.com\\/#\\/schema\\/person\\/1c82f82166ff54c01fa010babe96c5bc","name":"Monique Volz","sameAs":["https:\\/\\/www.ambitiouskitchen.com\\/about\\/","https:\\/\\/www.facebook.com\\/ambitiouskitchen","https:\\/\\/www.instagram.com\\/ambitiouskitchen\\/","https:\\/\\/www.pinterest.com\\/moniquevolz\\/","https:\\/\\/twitter.com\\/ambitiouskitch"],"url":"https:\\/\\/www.ambitiouskitchen.com\\/author\\/admin\\/"},{"@type":"Recipe","name":"Chipotle Black Bean Roasted Veggie Enchilada Casserole","author":{"@type":"Person","name":"Monique Volz of AmbitiousKitchen.com","url":"https:\\/\\/www.ambitiouskitchen.com\\/about\\/","sameAs":["https:\\/\\/www.facebook.com\\/ambitiouskitchen","https:\\/\\/www.instagram.com\\/ambitiouskitchen\\/","https:\\/\\/www.pinterest.com\\/moniquevolz\\/","https:\\/\\/twitter.com\\/ambitiouskitch"]},"description":"Delicious chipotle black bean roasted veggie enchilada casserole with layers of veggies snuggled between black beans, corn tortillas, a homemade chipotle enchilada sauce and cheese. This easy vegetarian enchilada casserole is protein-packed and makes the perfect weeknight dinner for a family or incredible leftovers for meal prep!","datePublished":"2025-08-10T11:00:07+00:00","image":["https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/2020\\/08\\/enchiladacasserole-5.jpg","https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/fly-images\\/45097\\/enchiladacasserole-5-500x500-c.jpg","https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/fly-images\\/45097\\/enchiladacasserole-5-500x375-c.jpg","https:\\/\\/www.ambitiouskitchen.com\\/wp-content\\/uploads\\/fly-images\\/45097\\/enchiladacasserole-5-480x270-c.jpg"],"recipeYield":["6","6 servings"],"prepTime":"PT15M","cookTime":"PT45M","totalTime":"PT60M","recipeIngredient":["For the roasted veggies:","1 red bell pepper, diced","1 orange bell pepper, diced","1 yellow bell pepper, diced","1 red onion, diced","1 (8 oz) package sliced baby bella mushrooms","1 medium zucchini, quartered","2 tablespoons extra-virgin olive or avocado oil","3 cloves garlic, minced","Kosher salt and freshly ground pepper","For the chipotle enchilada sauce:","1 (15 oz can) tomato sauce","3 garlic cloves, roughly chopped","2 tablespoons chili powder* (I used McCormick chili powder - please read the notes section on this)","1 teaspoon cumin","2 chipotle peppers in adobo sauce (from the can)","\\u2154 cup any milk of choice (we love unsweetened almond or cashew) or sub plain Greek yogurt or sour cream","For the layers:","1 (15 oz) can black beans, rinsed and drained","2 cups shredded monterey jack cheese, divided (or pepper jack is delicious!)","9 flour or corn tortillas","To garnish:","Diced avocado, jalapeno slices, cilantro, pickled red onions and roasted pepitas"],"recipeInstructions":[{"@type":"HowToStep","text":"Preheat oven to 425 degrees F. Line a large baking sheet with parchment paper, or you can also line two smaller baking sheets if that\\u2019s all you have available. Place diced bell pepper, diced onion, mushrooms, and quartered zucchini on prepared baking sheet(s). Drizzle with olive oil and toss garlic on top and generously season with salt and pepper. Toss with your hands to coat the veggies with garlic and oil. Roast vegetables for 25 to 30 minutes.","name":"Preheat oven to 425 degrees F. Line a large baking sheet with parchment paper, or you can also line two smaller baking sheets if that\\u2019s all you have available. Place diced bell pepper, diced onion, mushrooms, and quartered zucchini on prepared baking sheet(s). Drizzle with olive oil and toss garlic on top and generously season with salt and pepper. Toss with your hands to coat the veggies with garlic and oil. Roast vegetables for 25 to 30 minutes.","url":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#wprm-recipe-24284-step-0-0"},{"@type":"HowToStep","text":"While the veggies are roasting prepare the chipotle enchilada sauce: In the bowl of a food processor or in a blender, add the sauce ingredients: tomato sauce, garlic, chili powder, cumin, chipotle peppers and milk (or yogurt or sour cream). Process for 30 seconds or until smooth.","name":"While the veggies are roasting prepare the chipotle enchilada sauce: In the bowl of a food processor or in a blender, add the sauce ingredients: tomato sauce, garlic, chili powder, cumin, chipotle peppers and milk (or yogurt or sour cream). Process for 30 seconds or until smooth.","url":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#wprm-recipe-24284-step-0-1"},{"@type":"HowToStep","text":"Reduce heat in oven to 375 degrees F. Grease a 9x13 inch baking pan with nonstick cooking spray. Add heaping 1\\/2 cup enchilada sauce to the bottom of the pan and spread out evenly. Place 3 tortillas over the sauce. You may need to cut one tortilla in half to create a single layer. Next add \\u00bd of the roasted veggies and half of the black beans on top of the tortillas. Then drizzle \\u00bd cup of enchilada sauce on top followed by 1\\/2 cup of shredded cheese.","name":"Reduce heat in oven to 375 degrees F. Grease a 9x13 inch baking pan with nonstick cooking spray. Add heaping 1\\/2 cup enchilada sauce to the bottom of the pan and spread out evenly. Place 3 tortillas over the sauce. You may need to cut one tortilla in half to create a single layer. Next add \\u00bd of the roasted veggies and half of the black beans on top of the tortillas. Then drizzle \\u00bd cup of enchilada sauce on top followed by 1\\/2 cup of shredded cheese.","url":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#wprm-recipe-24284-step-0-2"},{"@type":"HowToStep","text":"Repeat the layers again, starting with the 3 corn tortillas, remaining veggies and beans, \\u00bd cup enchilada sauce and 1\\/2 cup cheese.","name":"Repeat the layers again, starting with the 3 corn tortillas, remaining veggies and beans, \\u00bd cup enchilada sauce and 1\\/2 cup cheese.","url":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#wprm-recipe-24284-step-0-3"},{"@type":"HowToStep","text":"Finally add 3 more corn tortillas on top to evenly cover the veggies and beans, then top with remaining enchilada sauce and 1 12 cups cheese. Bake for 25 to 30 minutes or until cheese is melted and enchiladas are bubbly. Serves 6. Top with diced or sliced avocado, cilantro, pickled red onion and a sprinkle of roasted pepitas. I also love this with a dollop of yogurt or sour cream on top!","name":"Finally add 3 more corn tortillas on top to evenly cover the veggies and beans, then top with remaining enchilada sauce and 1 12 cups cheese. Bake for 25 to 30 minutes or until cheese is melted and enchiladas are bubbly. Serves 6. Top with diced or sliced avocado, cilantro, pickled red onion and a sprinkle of roasted pepitas. I also love this with a dollop of yogurt or sour cream on top!","url":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#wprm-recipe-24284-step-0-4"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"4.89","ratingCount":"53","reviewCount":"8"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Such a delicious vegetarian meal! I noticed in your comments that people thought it was the chili powder that gave too much heat but I actually think it might be the two chipotle peppers in adobo. Having used this ingredient before, I opted for one chipotle pepper and that was PLENTY heat. So for those looking for a little less heat, I recommend trying one chipotle pepper instead of two!","author":{"@type":"Person","name":"Kelly"},"datePublished":"2026-05-01"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This recipe is SO good. It is a regular in my house and I have also made it for guests several times. I do add shredded chicken and use flour tortillas instead, and sometimes I use less chili powder to lower the heat depending on who will be eating it. But it\\u2019s such a healthy, filling and delicious meal - definitely try it!","author":{"@type":"Person","name":"Tatiana"},"datePublished":"2026-02-26"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This was delicious! We have issues with cooked peppers so I roasted some extra zucchini and added cherry tomato along with the red onion and mushrooms. I also wanted more protein so I chose ground chicken as suggested and I cooked it with some garlic and shallot and simmered it in some of the enchilada sauce. I used it where the recipe called for sauce in the 1st and 2nd layer.","author":{"@type":"Person","name":"Hilary"},"datePublished":"2026-01-17"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Full of flavor and fiber!","author":{"@type":"Person","name":"Ali"},"datePublished":"2025-08-20"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Zucchini &amp;sausage baked rice with hot honey &amp;feta\\r\\nI made this for dinner the other night and kids parents great grandma and papa and yaya loved it ! I used brown rice for gluten free. Thanks so much!!!","author":{"@type":"Person","name":"Penny Hansen"},"datePublished":"2025-08-11"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Another great veggie-packed recipe from Monique! I used one chipotle and 1 tablespoon of chili powder and it was still plenty spicy. I think it could use a few more tortillas. Next time I will try using 12. I made it in two pans and froze one.","author":{"@type":"Person","name":"Valerie"},"datePublished":"2025-08-11"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I made this for a meatless Monday dinner and it was delicious. Thank you for another nourishing, flavorful recipe!","author":{"@type":"Person","name":"Patty"},"datePublished":"2024-08-12"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"What a great recipe!!! Easy to make and follow. I love how easy the enchilada sauce is to make. I tried it before using and decided to add an additional Chipotle. So glad I found this blog. Would recommend!","author":{"@type":"Person","name":"Meredith"},"datePublished":"2024-03-24"}],"recipeCategory":["Dinner","Gluten Free","Nut Free","Vegetarian"],"recipeCuisine":["hispanic"],"keywords":"enchilada casserole, healthy enchilada casserole, vegetarian enchilada casserole","nutrition":{"@type":"NutritionInformation","servingSize":"1 serving (based on 6)","calories":"410 kcal","carbohydrateContent":"49.6 g","proteinContent":"23.1 g","fatContent":"14.2 g","saturatedFatContent":"6.5 g","fiberContent":"8.3 g","sugarContent":"5.3 g"},"@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#recipe","isPartOf":{"@id":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/#article"},"mainEntityOfPage":"https:\\/\\/www.ambitiouskitchen.com\\/chipotle-black-bean-vegetarian-enchilada-casserole\\/"}]}',
                'image' => 'https://www.ambitiouskitchen.com/wp-content/uploads/2020/08/enchiladacasserole-5.jpg',
            'ingredients' => '["For the roasted veggies:","1 red bell pepper, diced","1 orange bell pepper, diced","1 yellow bell pepper, diced","1 red onion, diced","1 (8 oz) package sliced baby bella mushrooms","1 medium zucchini, quartered","2 tablespoons extra-virgin olive or avocado oil","3 cloves garlic, minced","Kosher salt and freshly ground pepper","For the chipotle enchilada sauce:","1 (15 oz can) tomato sauce","3 garlic cloves, roughly chopped","2 tablespoons chili powder* (I used McCormick chili powder - please read the notes section on this)","1 teaspoon cumin","2 chipotle peppers in adobo sauce (from the can)","\\u2154 cup any milk of choice (we love unsweetened almond or cashew) or sub plain Greek yogurt or sour cream","For the layers:","1 (15 oz) can black beans, rinsed and drained","2 cups shredded monterey jack cheese, divided (or pepper jack is delicious!)","9 flour or corn tortillas","To garnish:","Diced avocado, jalapeno slices, cilantro, pickled red onions and roasted pepitas"]',
            'directions' => '["Preheat oven to 425 degrees F. Line a large baking sheet with parchment paper, or you can also line two smaller baking sheets if that\\u2019s all you have available. Place diced bell pepper, diced onion, mushrooms, and quartered zucchini on prepared baking sheet(s). Drizzle with olive oil and toss garlic on top and generously season with salt and pepper. Toss with your hands to coat the veggies with garlic and oil. Roast vegetables for 25 to 30 minutes.","While the veggies are roasting prepare the chipotle enchilada sauce: In the bowl of a food processor or in a blender, add the sauce ingredients: tomato sauce, garlic, chili powder, cumin, chipotle peppers and milk (or yogurt or sour cream). Process for 30 seconds or until smooth.","Reduce heat in oven to 375 degrees F. Grease a 9x13 inch baking pan with nonstick cooking spray. Add heaping 1\\/2 cup enchilada sauce to the bottom of the pan and spread out evenly. Place 3 tortillas over the sauce. You may need to cut one tortilla in half to create a single layer. Next add \\u00bd of the roasted veggies and half of the black beans on top of the tortillas. Then drizzle \\u00bd cup of enchilada sauce on top followed by 1\\/2 cup of shredded cheese.","Repeat the layers again, starting with the 3 corn tortillas, remaining veggies and beans, \\u00bd cup enchilada sauce and 1\\/2 cup cheese.","Finally add 3 more corn tortillas on top to evenly cover the veggies and beans, then top with remaining enchilada sauce and 1 12 cups cheese. Bake for 25 to 30 minutes or until cheese is melted and enchiladas are bubbly. Serves 6. Top with diced or sliced avocado, cilantro, pickled red onion and a sprinkle of roasted pepitas. I also love this with a dollop of yogurt or sour cream on top!"]',
            'nutrition' => '[{"@type":"NutritionInformation","servingSize":"1 serving (based on 6)","calories":"410 kcal","carbohydrateContent":"49.6 g","proteinContent":"23.1 g","fatContent":"14.2 g","saturatedFatContent":"6.5 g","fiberContent":"8.3 g","sugarContent":"5.3 g"}]',
                'slug' => 'chipotle-black-bean-roasted-veggie-enchilada-casserole',
