/uploads\\/2026\\/04\\/DatZ-logo-stacked-color-RGB-SQUARE-YOAST_696.jpg","contentUrl":"https:\\/\\/www.dinneratthezoo.com\\/wp-content\\/uploads\\/2026\\/04\\/DatZ-logo-stacked-color-RGB-SQUARE-YOAST_696.jpg","width":696,"height":696,"caption":"Dinner at the Zoo"},"image":{"@id":"https:\\/\\/www.dinneratthezoo.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["http:\\/\\/www.facebook.com\\/dinneratthezoo","https:\\/\\/x.com\\/dinneratthezoo","http:\\/\\/www.instagram.com\\/dinneratthezoo","http:\\/\\/www.pinterest.com\\/dinneratthezoo"]},{"@type":"Person","@id":"https:\\/\\/www.dinneratthezoo.com\\/#\\/schema\\/person\\/3874ff1c9d558166e703ec4f11f11190","name":"Sara Welch","image":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/008b9a079f72a6cc33350130cf7f24feb9662a4ff3c0b86432495a1547c4addf?s=96&d=mm&r=g","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/008b9a079f72a6cc33350130cf7f24feb9662a4ff3c0b86432495a1547c4addf?s=96&d=mm&r=g","contentUrl":"https:\\/\\/secure.gravatar.com\\/avatar\\/008b9a079f72a6cc33350130cf7f24feb9662a4ff3c0b86432495a1547c4addf?s=96&d=mm&r=g","caption":"Sara Welch"},"sameAs":["https:\\/\\/www.dinneratthezoo.com\\/about-me-contact-info\\/"]},{"@type":"Recipe","name":"Pumpkin Chocolate Chip Muffins","author":{"@id":"https:\\/\\/www.dinneratthezoo.com\\/#\\/schema\\/person\\/3874ff1c9d558166e703ec4f11f11190"},"description":"These pumpkin chocolate chip muffins are light and tender treats full of warm spices and plenty of chocolate chips. Pumpkin muffins make for a great dessert, after school snack or party offering.","datePublished":"2018-10-04T12:39:24+00:00","image":["https:\\/\\/www.dinneratthezoo.com\\/wp-content\\/uploads\\/2018\\/10\\/pumpkin-chocolate-chip-muffins-1.jpg","https:\\/\\/www.dinneratthezoo.com\\/wp-content\\/uploads\\/2018\\/10\\/pumpkin-chocolate-chip-muffins-1-500x500.jpg","https:\\/\\/www.dinneratthezoo.com\\/wp-content\\/uploads\\/2018\\/10\\/pumpkin-chocolate-chip-muffins-1-500x375.jpg","https:\\/\\/www.dinneratthezoo.com\\/wp-content\\/uploads\\/2018\\/10\\/pumpkin-chocolate-chip-muffins-1-480x270.jpg"],"recipeYield":["12"],"prepTime":"PT10M","cookTime":"PT15M","totalTime":"PT25M","recipeIngredient":["2 eggs","1 cup granulated sugar","1 cup pumpkin puree","3\\/4 cup vegetable oil","1 1\\/2 cups all purpose flour","1 teaspoon baking soda","1\\/2 teaspoon baking powder","1 1\\/2 teaspoons pumpkin pie spice","1\\/2 teaspoon vanilla extract","1\\/4 teaspoon salt","1 1\\/2 cups semisweet chocolate chips (divided use)","cooking spray"],"recipeInstructions":[{"@type":"HowToStep","text":"Preheat the oven to 400 degrees F. Coat a 12 cup muffin tin with cooking spray, or you can use paper liners.","name":"Preheat the oven to 400 degrees F. Coat a 12 cup muffin tin with cooking spray, or you can use paper liners.","url":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#wprm-recipe-17838-step-0-0"},{"@type":"HowToStep","text":"Place the eggs, sugar, pumpkin puree and oil in a bowl. Whisk until smooth.","name":"Place the eggs, sugar, pumpkin puree and oil in a bowl. Whisk until smooth.","url":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#wprm-recipe-17838-step-0-1"},{"@type":"HowToStep","text":"Add the flour, baking soda, baking powder, pumpkin pie spice, vanilla extract and salt to the bowl. Stir until just combined.","name":"Add the flour, baking soda, baking powder, pumpkin pie spice, vanilla extract and salt to the bowl. Stir until just combined.","url":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#wprm-recipe-17838-step-0-2"},{"@type":"HowToStep","text":"Fold in 1 cup of chocolate chips.","name":"Fold in 1 cup of chocolate chips.","url":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#wprm-recipe-17838-step-0-3"},{"@type":"HowToStep","text":"Divide the batter evenly among the 12 muffin cups and sprinkle the remaining chocolate chips over the tops of the muffins.","name":"Divide the batter evenly among the 12 muffin cups and sprinkle the remaining chocolate chips over the tops of the muffins.","url":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#wprm-recipe-17838-step-0-4"},{"@type":"HowToStep","text":"Bake for 17-22 minutes, or until lightly browned and a toothpick inserted in the center of a muffin comes out clean.\\u00a0","name":"Bake for 17-22 minutes, or until lightly browned and a toothpick inserted in the center of a muffin comes out clean.\\u00a0","url":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#wprm-recipe-17838-step-0-5"},{"@type":"HowToStep","text":"Cool for 5 minutes in the pan, then transfer the muffins to a wire rack to cool completely.","name":"Cool for 5 minutes in the pan, then transfer the muffins to a wire rack to cool completely.","url":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#wprm-recipe-17838-step-0-6"},{"@type":"HowToStep","text":"Serve, or store the muffins in an airtight container for up to 5 days.","name":"Serve, or store the muffins in an airtight container for up to 5 days.","url":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#wprm-recipe-17838-step-0-7"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"4.99","ratingCount":"151","reviewCount":"11"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Best. Muffins. Ever! These muffins are easy to make, moist and an absolute crowd pleaser. Everyone LOVES them. I make double-batches regularly. They also freeze very well. I\'ll be making these forever.","author":{"@type":"Person","name":"Schnauzer Mom"},"datePublished":"2026-01-12"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Family\'s favorite muffins! My kids beg for more as soon as they\'ve been eaten, delicious!","author":{"@type":"Person","name":"JACQUELINE"},"datePublished":"2025-11-11"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Absolute best pumpkin chocolate chip muffin recipe ever. I was on the hunt for the best moist muffins and these are absolutely perfect. I\\u2019ve made them so many times now and my whole family loves them. They are literally gone in one day. The only thing I tweak is that I bake on 350 instead of 400. And I do 1\\/2 cup of vegetable oil instead. I found them to be too oily the first time.","author":{"@type":"Person","name":"Jillian"},"datePublished":"2025-11-03"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"These chocolate chip pumpkin muffins are a huge hit in my house. They\'re so moist. My kids love them in their lunch and I love them with coffee. We are higher altitude and this recipe translates. No notes! Super delish.","author":{"@type":"Person","name":"Megan M"},"datePublished":"2025-10-30"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"My go to recipe for pumpkin muffins so good!","author":{"@type":"Person","name":"Gabrielle Harriman"},"datePublished":"2025-10-26"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Can you use olive oil instead of veg oil?","author":{"@type":"Person","name":"Danielle"},"datePublished":"2025-09-30"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This recipe has been on repeat for the last few years in my house. A hit every single time. Thank you for the delicious recipe!","author":{"@type":"Person","name":"Mom of 5"},"datePublished":"2025-05-30"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Great recipe! My wife loves them","author":{"@type":"Person","name":"Joe Smith"},"datePublished":"2025-05-11"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Very good, moist, not too sweet. Made a couple modifications (swapped white flour for whole wheat flour, swapped the sugar for half cup truvia, half cup coconut sugar) and they still turned out great. Only thing is, the batter did not look like the pictures and seemed very thick, so I added about half cup more pumpkin puree.","author":{"@type":"Person","name":"Lianne"},"datePublished":"2025-03-18"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"After making these, I understand why they are so highly rated! They come together super easily, and the pumpkin is the star of the show (as it should be!). I subbed gluten free flour and they taste amazing. I also only put just under a cup of chocolate chips in altogether to cut down on sugar and I found there were still lots of chocolate in each muffin! This is my new go-to pumpkin muffin recipe for sure.","author":{"@type":"Person","name":"Emily"},"datePublished":"2025-01-23"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"These muffins were awesome! Super moist and tasty :)","author":{"@type":"Person","name":"Ashley"},"datePublished":"2024-11-18"}],"recipeCategory":["Dessert"],"recipeCuisine":["American"],"keywords":"pumpkin chocolate chip muffins, pumpkin muffins","nutrition":{"@type":"NutritionInformation","calories":"288 kcal","carbohydrateContent":"42 g","proteinContent":"4 g","fatContent":"13 g","saturatedFatContent":"16 g","cholesterolContent":"28 mg","sodiumContent":"154 mg","fiberContent":"2 g","sugarContent":"25 g","servingSize":"1 serving"},"@id":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#recipe","isPartOf":{"@id":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/#article"},"mainEntityOfPage":"https:\\/\\/www.dinneratthezoo.com\\/pumpkin-chocolate-chip-muffins\\/"}]}',
