                'user_id' => 1,
                'description' => 'This quick and easy vegan zucchini pasta sauce is made from sauteed zucchini that\'s blended into a magical creamy plant-based pasta sauce.',
            'content' => '{"@context":"https:\\/\\/schema.org","@graph":[{"@type":"Article","@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#article","isPartOf":{"@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/"},"author":{"name":"Monica Davis","@id":"https:\\/\\/thehiddenveggies.com\\/#\\/schema\\/person\\/8cd9fb41a8defddcc699901d44b71260"},"headline":"Creamy Vegan Zucchini Pasta Sauce","datePublished":"2023-08-22T22:05:50+00:00","dateModified":"2026-05-26T14:27:39+00:00","wordCount":990,"commentCount":4,"image":{"@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/thehiddenveggies.com\\/wp-content\\/uploads\\/2023\\/08\\/vegan-zucchini-pasta-sq.jpg","articleSection":["Easy Vegan Meals","Italian-Inspired","Main Course","Pasta"],"inLanguage":"en-US","potentialAction":[{"@type":"CommentAction","name":"Comment","target":["https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#respond"]}]},{"@type":"WebPage","@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/","name":"Creamy Vegan Zucchini Pasta Sauce","isPartOf":{"@id":"https:\\/\\/thehiddenveggies.com\\/#website"},"primaryImageOfPage":{"@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#primaryimage"},"image":{"@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/thehiddenveggies.com\\/wp-content\\/uploads\\/2023\\/08\\/vegan-zucchini-pasta-sq.jpg","datePublished":"2023-08-22T22:05:50+00:00","dateModified":"2026-05-26T14:27:39+00:00","author":{"@id":"https:\\/\\/thehiddenveggies.com\\/#\\/schema\\/person\\/8cd9fb41a8defddcc699901d44b71260"},"description":"This quick and easy vegan zucchini pasta sauce is made from sauteed zucchini that\'s blended into a magical creamy plant-based pasta sauce.","breadcrumb":{"@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#primaryimage","url":"https:\\/\\/thehiddenveggies.com\\/wp-content\\/uploads\\/2023\\/08\\/vegan-zucchini-pasta-sq.jpg","contentUrl":"https:\\/\\/thehiddenveggies.com\\/wp-content\\/uploads\\/2023\\/08\\/vegan-zucchini-pasta-sq.jpg","width":1200,"height":1200,"caption":"Vegan zucchini pasta with parsley and red pepper flakes served on a white plate with a fork next to it."},{"@type":"BreadcrumbList","@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/thehiddenveggies.com\\/"},{"@type":"ListItem","position":2,"name":"Main Course","item":"https:\\/\\/thehiddenveggies.com\\/category\\/dinner\\/"},{"@type":"ListItem","position":3,"name":"Pasta","item":"https:\\/\\/thehiddenveggies.com\\/category\\/dinner\\/pasta\\/"},{"@type":"ListItem","position":4,"name":"Creamy Vegan Zucchini Pasta Sauce"}]},{"@type":"WebSite","@id":"https:\\/\\/thehiddenveggies.com\\/#website","url":"https:\\/\\/thehiddenveggies.com\\/","name":"The Hidden Veggies","description":"Your trusted source for affordable vegan recipes that taste like the real deal and satisfy your cravings!","potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/thehiddenveggies.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Person","@id":"https:\\/\\/thehiddenveggies.com\\/#\\/schema\\/person\\/8cd9fb41a8defddcc699901d44b71260","name":"Monica Davis","description":"Monica Davis is the recipe developer, writer, and photographer behind The Hidden Veggies recipe blog. On the blog, you will find family-friendly vegan recipes for \\u201cnormal\\u201d everyday comfort foods, including vegan cheese, seitan, vegan pasta, slow cooker recipes, tofu, salads, desserts, and more.","sameAs":["https:\\/\\/thehiddenveggies.com\\/about-me\\/","https:\\/\\/www.facebook.com\\/thehiddenveggies\\/","https:\\/\\/www.instagram.com\\/thehiddenveggies\\/","https:\\/\\/www.pinterest.com\\/gfveganmeals\\/the-hidden-veggies\\/","https:\\/\\/x.com\\/Hidden_Veggies","https:\\/\\/www.youtube.com\\/@monicadavis4501"]},{"@type":"Recipe","name":"Vegan Zucchini Pasta Sauce","author":{"@id":"https:\\/\\/thehiddenveggies.com\\/#\\/schema\\/person\\/8cd9fb41a8defddcc699901d44b71260"},"description":"Rich and creamy pasta sauce made from blended sauteed zucchini and garlic.","datePublished":"2023-08-22T18:05:50+00:00","image":["https:\\/\\/thehiddenveggies.com\\/wp-content\\/uploads\\/2023\\/08\\/vegan-zucchini-pasta-sq.jpg","https:\\/\\/thehiddenveggies.com\\/wp-content\\/uploads\\/2023\\/08\\/vegan-zucchini-pasta-sq-500x500.jpg","https:\\/\\/thehiddenveggies.com\\/wp-content\\/uploads\\/2023\\/08\\/vegan-zucchini-pasta-sq-500x375.jpg","https:\\/\\/thehiddenveggies.com\\/wp-content\\/uploads\\/2023\\/08\\/vegan-zucchini-pasta-sq-480x270.jpg"],"recipeYield":["8"],"prepTime":"PT10M","cookTime":"PT15M","totalTime":"PT25M","recipeIngredient":["1 (16oz) package pasta","2 tablespoons olive oil","4 cloves garlic","5 cups zucchini (sliced ( this is about 3-4 medium zucchini))","1\\/2 teaspoon salt","1 teaspoon Italian seasoning","1\\/4 teaspoon red pepper flakes","1 1\\/2 cups pasta water ((reserved from cooking water))"],"recipeInstructions":[{"@type":"HowToStep","text":"Cook your pasta of choice according to the package directions in salted water. (Reserve 1 1\\/2 cups of the cooking water.)","name":"Cook your pasta of choice according to the package directions in salted water. (Reserve 1 1\\/2 cups of the cooking water.)","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#wprm-recipe-30977-step-0-0"},{"@type":"HowToStep","text":"While your pasta is cooking, wash and slice the zucchini into 1 cm thick slices.","name":"While your pasta is cooking, wash and slice the zucchini into 1 cm thick slices.","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#wprm-recipe-30977-step-0-1"},{"@type":"HowToStep","text":"In a large skillet over medium-low heat, add 2 tablespoons of oil, 4 cloves of minced garlic, and sprinkle with salt and spices.","name":"In a large skillet over medium-low heat, add 2 tablespoons of oil, 4 cloves of minced garlic, and sprinkle with salt and spices.","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#wprm-recipe-30977-step-0-2"},{"@type":"HowToStep","text":"Saut\\u00e9 the zucchini over medium-low heat for about 12-15 minutes, stirring every minute or two to avoid burning, until the zucchini becomes translucent.","name":"Saut\\u00e9 the zucchini over medium-low heat for about 12-15 minutes, stirring every minute or two to avoid burning, until the zucchini becomes translucent.","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#wprm-recipe-30977-step-0-3"},{"@type":"HowToStep","text":"Reserve 1 1\\/2 cups of pasta cooking water before draining your cooked pasta.","name":"Reserve 1 1\\/2 cups of pasta cooking water before draining your cooked pasta.","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#wprm-recipe-30977-step-0-4"},{"@type":"HowToStep","text":"Place the sauteed zucchini in a blender with 1\\/2 cup of the reserved pasta water and blend for 30 seconds. Slowly add in the remainder of the pasta water until the desired consistency is reached.","name":"Place the sauteed zucchini in a blender with 1\\/2 cup of the reserved pasta water and blend for 30 seconds. Slowly add in the remainder of the pasta water until the desired consistency is reached.","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#wprm-recipe-30977-step-0-5"},{"@type":"HowToStep","text":"Add the pasta to the large skillet and coat well with the zucchini pasta sauce.","name":"Add the pasta to the large skillet and coat well with the zucchini pasta sauce.","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#wprm-recipe-30977-step-0-6"},{"@type":"HowToStep","text":"Add salt, black pepper, or red pepper flakes to taste if needed, and serve hot.","name":"Add salt, black pepper, or red pepper flakes to taste if needed, and serve hot.","url":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#wprm-recipe-30977-step-0-7"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"5","ratingCount":"3","reviewCount":"1"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Freeze leftovers including pasta? This is super and healthy.","author":{"@type":"Person","name":"Bernadette Conroy"},"datePublished":"2024-06-13"}],"recipeCategory":["Main Course"],"recipeCuisine":["American","vegan"],"keywords":"vegan zucchini pasta, vegan zucchini pasta sauce","nutrition":{"@type":"NutritionInformation","servingSize":"1.5 cup","calories":"279 kcal","carbohydrateContent":"50 g","proteinContent":"9 g","fatContent":"5 g","saturatedFatContent":"1 g","sodiumContent":"159 mg","fiberContent":"3 g","sugarContent":"4 g","unsaturatedFatContent":"4 g"},"@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#recipe","isPartOf":{"@id":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/#article"},"mainEntityOfPage":"https:\\/\\/thehiddenveggies.com\\/vegan-zucchini-pasta\\/"}]}',
                'image' => 'https://thehiddenveggies.com/wp-content/uploads/2023/08/vegan-zucchini-pasta-sq.jpg',
            'ingredients' => '["1 (16oz) package pasta","2 tablespoons olive oil","4 cloves garlic","5 cups zucchini (sliced ( this is about 3-4 medium zucchini))","1\\/2 teaspoon salt","1 teaspoon Italian seasoning","1\\/4 teaspoon red pepper flakes","1 1\\/2 cups pasta water ((reserved from cooking water))"]',
            'directions' => '["Cook your pasta of choice according to the package directions in salted water. (Reserve 1 1\\/2 cups of the cooking water.)","While your pasta is cooking, wash and slice the zucchini into 1 cm thick slices.","In a large skillet over medium-low heat, add 2 tablespoons of oil, 4 cloves of minced garlic, and sprinkle with salt and spices.","Saut\\u00e9 the zucchini over medium-low heat for about 12-15 minutes, stirring every minute or two to avoid burning, until the zucchini becomes translucent.","Reserve 1 1\\/2 cups of pasta cooking water before draining your cooked pasta.","Place the sauteed zucchini in a blender with 1\\/2 cup of the reserved pasta water and blend for 30 seconds. Slowly add in the remainder of the pasta water until the desired consistency is reached.","Add the pasta to the large skillet and coat well with the zucchini pasta sauce.","Add salt, black pepper, or red pepper flakes to taste if needed, and serve hot."]',
                'nutrition' => '[{"@type":"NutritionInformation","servingSize":"1.5 cup","calories":"279 kcal","carbohydrateContent":"50 g","proteinContent":"9 g","fatContent":"5 g","saturatedFatContent":"1 g","sodiumContent":"159 mg","fiberContent":"3 g","sugarContent":"4 g","unsaturatedFatContent":"4 g"}]',
