            array (
                'id' => 37,
                'name' => 'Instant Pot Butternut Squash Lentil Curry',
                'url' => 'https://rainbowplantlife.com/instant-pot-butternut-squash-lentil-curry/',
                'site_domain' => 'https://rainbowplantlife.com/',
                'site_name' => 'Rainbow Plant Life',
                'user_id' => 1,
                'description' => 'With just a few minutes of hands-on cooking, this Instant Pot Butternut Squash Lentil Curry will become your go-to for weeknight meals.',
