rich, creamy, and delicious one-pot meal.","breadcrumb":{"@id":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#primaryimage","url":"https:\\/\\/triedtestedandtrue.com\\/wp-content\\/uploads\\/2021\\/05\\/alfredo.jpeg","contentUrl":"https:\\/\\/triedtestedandtrue.com\\/wp-content\\/uploads\\/2021\\/05\\/alfredo.jpeg","width":1365,"height":2048,"caption":"a bowl of Instant Pot alfredo"},{"@type":"BreadcrumbList","@id":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Instant Pot Recipes","item":"https:\\/\\/triedtestedandtrue.com\\/instantpotrecipes\\/"},{"@type":"ListItem","position":2,"name":"Instant Pot Fettuccine Alfredo"}]},{"@type":"WebSite","@id":"https:\\/\\/triedtestedandtrue.com\\/#website","url":"https:\\/\\/triedtestedandtrue.com\\/","name":"Tried Tested and True","description":"Instant Pot Recipes and More","publisher":{"@id":"https:\\/\\/triedtestedandtrue.com\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/triedtestedandtrue.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/triedtestedandtrue.com\\/#organization","name":"Tried, Tested, and True","url":"https:\\/\\/triedtestedandtrue.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/triedtestedandtrue.com\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/triedtestedandtrue.com\\/wp-content\\/uploads\\/2023\\/08\\/Tried-Tested-and-True-Web.jpg","contentUrl":"https:\\/\\/triedtestedandtrue.com\\/wp-content\\/uploads\\/2023\\/08\\/Tried-Tested-and-True-Web.jpg","width":1200,"height":675,"caption":"Tried, Tested, and True"},"image":{"@id":"https:\\/\\/triedtestedandtrue.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/www.facebook.com\\/triedtestedandtrue\\/","https:\\/\\/www.instagram.com\\/instantpot_cooking\\/","https:\\/\\/www.linkedin.com\\/in\\/lisa-adachi-childs-93985a67\\/","https:\\/\\/www.pinterest.com\\/instantpot_cooking\\/"]},{"@type":"Person","@id":"https:\\/\\/triedtestedandtrue.com\\/#\\/schema\\/person\\/cdb2843f2e4663e372c266976d152fdd","name":"Lisa Childs","sameAs":["https:\\/\\/triedtestedandtrue.com\\/about"]},{"@type":"Recipe","name":"Instant Pot Fettuccine Alfredo","author":{"@type":"Person","name":"Lisa Childs"},"description":"Instant Pot Fettuccine Alfredo is an easy, inexpensive classic favorite! Simply add the ingredients to the Instant Pot and start for a rich, creamy, and delicious one-pot meal.","datePublished":"2021-06-14T10:10:46+00:00","image":["https:\\/\\/triedtestedandtrue.com\\/wp-content\\/uploads\\/2021\\/05\\/alfredo.jpeg"],"prepTime":"PT5M","cookTime":"PT12M","totalTime":"PT20M","recipeIngredient":["1 1\\/2 cups chicken broth*","2 cups heavy cream","1 teaspoon minced garlic","1 teaspoon salt","1\\/4 teaspoon pepper","1 teaspoon dried parsley","2 tablespoons butter","8 ounces fettuccine noodles (broken in half)","1\\/2 cup parmesan cheese (shredded*)"],"recipeInstructions":[{"@type":"HowToStep","text":"Add chicken broth, cream, garlic, salt, pepper, parsley, and butter to the Instant Pot.","name":"Add chicken broth, cream, garlic, salt, pepper, parsley, and butter to the Instant Pot.","url":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#wprm-recipe-4706-step-0-0"},{"@type":"HowToStep","text":"Scatter the noodles over the liquid, alternating the direction of the noodles to prevent sticking. Pat the noodles down slightly to submerge them in as much liquid as possible.","name":"Scatter the noodles over the liquid, alternating the direction of the noodles to prevent sticking. Pat the noodles down slightly to submerge them in as much liquid as possible.","url":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#wprm-recipe-4706-step-0-1"},{"@type":"HowToStep","text":"Lock the lid, turn the knob to sealing, then pressure cook on high pressure for 7 minutes. Allow a 5 minute natural pressure release.","name":"Lock the lid, turn the knob to sealing, then pressure cook on high pressure for 7 minutes. Allow a 5 minute natural pressure release.","url":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#wprm-recipe-4706-step-0-2"},{"@type":"HowToStep","text":"Remove the lid, and stir the noodles and sauce together. Slowly sprinkle in the parmesan cheese and mix to combine. Serve immediately.","name":"Remove the lid, and stir the noodles and sauce together. Slowly sprinkle in the parmesan cheese and mix to combine. Serve immediately.","url":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#wprm-recipe-4706-step-0-3"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"5","ratingCount":"1","reviewCount":"1"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Tried this recipe and loved it. Had to release slow because of the sputter, and had to saut\\u00e9 for a few to thicken up; just like the recipe said. It was great. Making fettuccine Alfredo on the stove takes 2 pans and a skillet, plus serving dish. Doing this in the Instant Pot of course uses only one pot. Yay. Will be making this again.\\r\\n\\r\\nGerald","author":{"@type":"Person","name":"Gerald Drake"},"datePublished":"2023-03-17"}],"recipeCategory":["Instant Pot Dump and Go Recipes"],"recipeCuisine":["Italian"],"keywords":"Instant Pot alfredo","nutrition":{"@type":"NutritionInformation","servingSize":"1 g","calories":"590 kcal","carbohydrateContent":"22 g","proteinContent":"11 g","fatContent":"52 g","saturatedFatContent":"33 g","transFatContent":"2 g","cholesterolContent":"159 mg","sodiumContent":"1390 mg","fiberContent":"1 g","sugarContent":"5 g","unsaturatedFatContent":"16 g"},"@id":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#recipe","isPartOf":{"@id":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/#article"},"mainEntityOfPage":"https:\\/\\/triedtestedandtrue.com\\/instant-pot-fettuccine-alfredo\\/"}]}',
