                'description' => 'This Vegetarian Gumbo recipe is easy to make, loaded up with tons of savory veggies, and tastes SO rich and delicious!',
            'content' => '{"@context":"https:\\/\\/schema.org","@graph":[{"@type":"Article","@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#article","isPartOf":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/"},"author":{"name":"Ali","@id":"https:\\/\\/www.gimmesomeoven.com\\/#\\/schema\\/person\\/f2ec3b8956be0c3431af79ad7e71d6b5"},"headline":"Vegetarian Gumbo","datePublished":"2019-02-25T10:02:32+00:00","dateModified":"2025-06-23T00:42:28+00:00","wordCount":1847,"commentCount":41,"publisher":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/#organization"},"image":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2019\\/02\\/Vegetarian-Gumbo-Recipe-2.jpg","articleSection":["Dinners","Mardi Gras Recipes","Soup Recipes"],"inLanguage":"en-US","potentialAction":[{"@type":"CommentAction","name":"Comment","target":["https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#respond"]}]},{"@type":"WebPage","@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/","url":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/","name":"Vegetarian Gumbo - Gimme Some Oven","isPartOf":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/#website"},"primaryImageOfPage":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#primaryimage"},"image":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2019\\/02\\/Vegetarian-Gumbo-Recipe-2.jpg","datePublished":"2019-02-25T10:02:32+00:00","dateModified":"2025-06-23T00:42:28+00:00","description":"This Vegetarian Gumbo recipe is easy to make, loaded up with tons of savory veggies, and tastes SO rich and delicious!","breadcrumb":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#primaryimage","url":"https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2019\\/02\\/Vegetarian-Gumbo-Recipe-2.jpg","contentUrl":"https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2019\\/02\\/Vegetarian-Gumbo-Recipe-2.jpg","width":1392,"height":2088,"caption":"Vegetarian Gumbo"},{"@type":"BreadcrumbList","@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/www.gimmesomeoven.com\\/"},{"@type":"ListItem","position":2,"name":"Courses","item":"https:\\/\\/www.gimmesomeoven.com\\/courses\\/"},{"@type":"ListItem","position":3,"name":"Dinners","item":"https:\\/\\/www.gimmesomeoven.com\\/courses\\/main-course\\/"},{"@type":"ListItem","position":4,"name":"Vegetarian Gumbo"}]},{"@type":"WebSite","@id":"https:\\/\\/www.gimmesomeoven.com\\/#website","url":"https:\\/\\/www.gimmesomeoven.com\\/","name":"Gimme Some Oven","description":"Celebrating Delicious and Easy Recipes","publisher":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/www.gimmesomeoven.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/www.gimmesomeoven.com\\/#organization","name":"Gimme Some Oven","url":"https:\\/\\/www.gimmesomeoven.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/www.gimmesomeoven.com\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2021\\/09\\/Logo-square.png","contentUrl":"https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2021\\/09\\/Logo-square.png","width":410,"height":410,"caption":"Gimme Some Oven"},"image":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/www.facebook.com\\/GimmeSomeOvenBlog\\/","https:\\/\\/www.instagram.com\\/gimmesomeoven\\/","https:\\/\\/www.pinterest.com\\/gimmesomeoven\\/","https:\\/\\/www.youtube.com\\/user\\/gimmesomeovenblog"]},{"@type":"Person","@id":"https:\\/\\/www.gimmesomeoven.com\\/#\\/schema\\/person\\/f2ec3b8956be0c3431af79ad7e71d6b5","name":"Ali","image":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/2a46f70c682717622ea29d081ed6cbfed1d8b1d89faa6e768a984b7970610c83?s=96&d=mm&r=pg","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/2a46f70c682717622ea29d081ed6cbfed1d8b1d89faa6e768a984b7970610c83?s=96&d=mm&r=pg","contentUrl":"https:\\/\\/secure.gravatar.com\\/avatar\\/2a46f70c682717622ea29d081ed6cbfed1d8b1d89faa6e768a984b7970610c83?s=96&d=mm&r=pg","caption":"Ali"},"description":"Hi, I\'m Ali Martin! I created this site in 2009 to celebrate good food and gathering around the table. I live in Kansas City with my husband and two young boys and love creating simple, reliable, delicious recipes that anyone can make!","sameAs":["https:\\/\\/www.gimmesomeoven.com\\/about\\/","https:\\/\\/x.com\\/gimmesomeoven"],"url":"https:\\/\\/www.gimmesomeoven.com\\/about\\/"},{"@type":"Recipe","name":"Vegetarian Gumbo","author":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/#\\/schema\\/person\\/f2ec3b8956be0c3431af79ad7e71d6b5"},"description":"This Vegetarian Gumbo recipe is easy to make, loaded up with tons of savory veggies, and tastes SO rich and delicious.\\u00a0 I recommend prepping all of your ingredients before you begin to cook the gumbo, so that you can give your full attention to that delicious roux. ;)","datePublished":"2019-02-25T04:02:32+00:00","image":["https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2019\\/02\\/Vegetarian-Gumbo-Recipe-2.jpg","https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2019\\/02\\/Vegetarian-Gumbo-Recipe-2-500x500.jpg","https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2019\\/02\\/Vegetarian-Gumbo-Recipe-2-500x375.jpg","https:\\/\\/www.gimmesomeoven.com\\/wp-content\\/uploads\\/2019\\/02\\/Vegetarian-Gumbo-Recipe-2-480x270.jpg"],"recipeYield":["8","8 -10 servings"],"prepTime":"PT20M","cookTime":"PT40M","totalTime":"PT60M","recipeIngredient":["1\\/2 cup butter (or oil)","2\\/3 cup all-purpose flour","2 medium red bell peppers (cored and diced)","2 celery stalks (diced)","1 small white onion (peeled and diced)","1 cup fresh or frozen chopped okra","5 cloves garlic (minced)","3 cups vegetable stock","1 small head of cauliflower (cored and chopped into florets)","1 pound (16 ounces) baby bella or button mushrooms (diced)","1 (14 ounce) can fire-roasted tomatoes","2 teaspoons Creole or Cajun seasoning","1\\/2 teaspoon dried thyme","1\\/2 teaspoon cayenne (or more\\/less to taste)","1 bay leaf","fine sea salt and freshly-cracked black pepper (to taste)","optional topping: thinly-sliced green onions"],"recipeInstructions":[{"@type":"HowToStep","text":"Heat butter in a large heavy-bottomed pot (I used a Dutch oven) over medium-high heat until melted.\\u00a0 Whisk in flour until combined. \\u00a0Continue to cook, stirring constantly, for about 20 minutes, or until the roux mixture reaches a dark amber-brown color.\\u00a0 Keep a very close eye on the roux at all times, turning the heat down a bit if it seems to be cooking too quickly or starts to faintly smell burnt.","name":"Heat butter in a large heavy-bottomed pot (I used a Dutch oven) over medium-high heat until melted.\\u00a0 Whisk in flour until combined. \\u00a0Continue to cook, stirring constantly, for about 20 minutes, or until the roux mixture reaches a dark amber-brown color.\\u00a0 Keep a very close eye on the roux at all times, turning the heat down a bit if it seems to be cooking too quickly or starts to faintly smell burnt.","url":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#wprm-recipe-59812-step-0-0"},{"@type":"HowToStep","text":"Once the roux is ready, immediately stir in the bell peppers, celery, onion, okra and garlic until combined. \\u00a0Continue to cook, stirring every 10-15 seconds, until the vegetables have softened, about 5 minutes.","name":"Once the roux is ready, immediately stir in the bell peppers, celery, onion, okra and garlic until combined. \\u00a0Continue to cook, stirring every 10-15 seconds, until the vegetables have softened, about 5 minutes.","url":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#wprm-recipe-59812-step-0-1"},{"@type":"HowToStep","text":"Stir\\u00a0in the vegetable stock gradually until the broth is smooth.\\u00a0 Then add in the cauliflower, mushrooms, tomatoes, seasoning, thyme, cayenne and bay leaf.\\u00a0 Stir until combined, and continue cooking until the soup reaches a simmer.","name":"Stir\\u00a0in the vegetable stock gradually until the broth is smooth.\\u00a0 Then add in the cauliflower, mushrooms, tomatoes, seasoning, thyme, cayenne and bay leaf.\\u00a0 Stir until combined, and continue cooking until the soup reaches a simmer.","url":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#wprm-recipe-59812-step-0-2"},{"@type":"HowToStep","text":"Reduce heat to medium-low and let the gumbo continue to simmer for 5-10 minutes minutes, or until the vegetables are tender. \\u00a0Taste, and season with extra salt, pepper and\\/or cayenne if needed.","name":"Reduce heat to medium-low and let the gumbo continue to simmer for 5-10 minutes minutes, or until the vegetables are tender. \\u00a0Taste, and season with extra salt, pepper and\\/or cayenne if needed.","url":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#wprm-recipe-59812-step-0-3"},{"@type":"HowToStep","text":"Serve warm over rice, garnished with lots of green onions.\\u00a0 Or transfer to a sealed container and refrigerate for up to 3 days or freeze for up to 3 months.","name":"Serve warm over rice, garnished with lots of green onions.\\u00a0 Or transfer to a sealed container and refrigerate for up to 3 days or freeze for up to 3 months.","url":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#wprm-recipe-59812-step-0-4"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"4.67","ratingCount":"21","reviewCount":"9"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Found this about 5 years ago when I was still learning how to be a satisfied vegetarian. Glad to see it still here to guide folks because it\'s a delicious source of winter comfort for me and it\'s a very cold winter. Never tried adding okra but it\'s just fine without it. The aim and method are explained beautifully. Thank you!","author":{"@type":"Person","name":"Robert"},"datePublished":"2026-07-05"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"4"},"reviewBody":"Good start but I think the recipe needs a few edits. The recipe says to start melting the butter at medium high heat and then add the flour. I had to lower my heat all the way to low as it was burning\\/cooking too quickly. I also added atleast a another cup of liquid as it didn\'t seem to have enough as is. I may try this again, and I was happy to find a vegetarian recipe!","author":{"@type":"Person","name":"Stefany"},"datePublished":"2024-11-04"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This was absolutely delicious! I went with the \\"using seafood\\" suggestion as we are pescatarian and used seafood stock (instead of veggie). I still used all of the veggies except cauliflower. About five minutes before we were ready to eat I threw in a pound of peeled, deveined wild shrimp, a can of clams and a pound of scallops. It was so good. I ate without rice and hubs had some white rice. We both had seconds :).","author":{"@type":"Person","name":"Jessie"},"datePublished":"2024-02-20"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Gave it a 5 cuz can\\u2019t give a 10!!!!! I am addicted to this!! Best ever","author":{"@type":"Person","name":"Carole Crawford"},"datePublished":"2022-08-13"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"4"},"reviewBody":"Hello, \\r\\n\\r\\nEven though I followed the directions, the roux never browned. I used smoked paprika for the Creole seasoning. The flavor was good.","author":{"@type":"Person","name":"Hope Bloom"},"datePublished":"2022-02-20"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"We made this for dinner tonight and absolutely loved it! Thank you so much! I was curious if you\'d ever tried making it in a crock pot... I am not sure how that would work, but I thought it might be fun to try.","author":{"@type":"Person","name":"Julie Kennedy"},"datePublished":"2022-02-16"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Made this w\\/out the cauliflower. This is one of the best Gumbos I\'ve made ever.. Added a tsp of Old Bay, just because, and a pound of peeled de-veined shrimp along with a few dashes of liquid smoke. The family wants more.. so I\'ll be using this recipe from now on!","author":{"@type":"Person","name":"Judy Cole"},"datePublished":"2022-01-23"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"We love this recipe and have made it many times. It\'s a family favorite and will be a Thanksgiving staple as well. It is truly delicious!","author":{"@type":"Person","name":"Melanie"},"datePublished":"2021-10-26"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Delicious! Even better the next day. My husband already asking for this gumbo again and I just made it last week.","author":{"@type":"Person","name":"DenaG"},"datePublished":"2021-09-20"}],"recipeCategory":["Soup"],"recipeCuisine":["American"],"keywords":"mardi gras, vegetarian","@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#recipe","isPartOf":{"@id":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/#article"},"mainEntityOfPage":"https:\\/\\/www.gimmesomeoven.com\\/vegetarian-gumbo\\/"}]}',
                'image' => 'https://www.gimmesomeoven.com/wp-content/uploads/2019/02/Vegetarian-Gumbo-Recipe-2.jpg',
            'ingredients' => '["1\\/2 cup butter (or oil)","2\\/3 cup all-purpose flour","2 medium red bell peppers (cored and diced)","2 celery stalks (diced)","1 small white onion (peeled and diced)","1 cup fresh or frozen chopped okra","5 cloves garlic (minced)","3 cups vegetable stock","1 small head of cauliflower (cored and chopped into florets)","1 pound (16 ounces) baby bella or button mushrooms (diced)","1 (14 ounce) can fire-roasted tomatoes","2 teaspoons Creole or Cajun seasoning","1\\/2 teaspoon dried thyme","1\\/2 teaspoon cayenne (or more\\/less to taste)","1 bay leaf","fine sea salt and freshly-cracked black pepper (to taste)","optional topping: thinly-sliced green onions"]',
            'directions' => '["Heat butter in a large heavy-bottomed pot (I used a Dutch oven) over medium-high heat until melted.\\u00a0 Whisk in flour until combined. \\u00a0Continue to cook, stirring constantly, for about 20 minutes, or until the roux mixture reaches a dark amber-brown color.\\u00a0 Keep a very close eye on the roux at all times, turning the heat down a bit if it seems to be cooking too quickly or starts to faintly smell burnt.","Once the roux is ready, immediately stir in the bell peppers, celery, onion, okra and garlic until combined. \\u00a0Continue to cook, stirring every 10-15 seconds, until the vegetables have softened, about 5 minutes.","Stir\\u00a0in the vegetable stock gradually until the broth is smooth.\\u00a0 Then add in the cauliflower, mushrooms, tomatoes, seasoning, thyme, cayenne and bay leaf.\\u00a0 Stir until combined, and continue cooking until the soup reaches a simmer.","Reduce heat to medium-low and let the gumbo continue to simmer for 5-10 minutes minutes, or until the vegetables are tender. \\u00a0Taste, and season with extra salt, pepper and\\/or cayenne if needed.","Serve warm over rice, garnished with lots of green onions.\\u00a0 Or transfer to a sealed container and refrigerate for up to 3 days or freeze for up to 3 months."]',
