\\/\\/www.beetofthewild.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-CA"},{"@type":"Organization","@id":"https:\\/\\/www.beetofthewild.com\\/#organization","name":"Beet of the Wild","url":"https:\\/\\/www.beetofthewild.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-CA","@id":"https:\\/\\/www.beetofthewild.com\\/#\\/schema\\/logo\\/image\\/","url":"","contentUrl":"","caption":"Beet of the Wild"},"image":{"@id":"https:\\/\\/www.beetofthewild.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/facebook.com\\/beetofthewild","https:\\/\\/x.com\\/beetofthewild","https:\\/\\/mastodon.social\\/@beetofthewild","https:\\/\\/instagram.com\\/beetofthewild","https:\\/\\/pinterest.com\\/beetofthewild","https:\\/\\/youtube.com\\/@beetofthewild","https:\\/\\/tiktok.com\\/beetofthewild","https:\\/\\/flipboard.com\\/@beetofthewild"],"description":"A blog dedicated to seasonally inspired whole food recipes, natural living and healthy homemade staples for the holistic home cook.","email":"beetofthewild@gmail.com","legalName":"Beet of the Wild","foundingDate":"2019-05-22","numberOfEmployees":{"@type":"QuantitativeValue","minValue":"1","maxValue":"10"}},{"@type":"Person","@id":"https:\\/\\/www.beetofthewild.com\\/#\\/schema\\/person\\/acae3098bcee9097aec3c5f20598947a","name":"Michelle McCowan","image":{"@type":"ImageObject","inLanguage":"en-CA","@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/376bffa22dee71ffb0f6def35485501029d3774b93852fa23307aaf07afae00b?s=96&d=blank&r=g","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/376bffa22dee71ffb0f6def35485501029d3774b93852fa23307aaf07afae00b?s=96&d=blank&r=g","contentUrl":"https:\\/\\/secure.gravatar.com\\/avatar\\/376bffa22dee71ffb0f6def35485501029d3774b93852fa23307aaf07afae00b?s=96&d=blank&r=g","caption":"Michelle McCowan"},"description":"I\'m Michelle, a photographer and nutritionally trained recipe developer who believes in the power of real food, dancing to nature\'s rhythm, and tuning into our wild roots through simple, slow, and natural living. One of my greatest passions is creating tasty recipes that utilize whole foods and minimally processed ingredients, along with sharing easy-to-digest information that simplifies healthy eating, home cooking, and natural wellness.","sameAs":["https:\\/\\/www.beetofthewild.com","https:\\/\\/www.facebook.com\\/beetofthewild","https:\\/\\/www.instagram.com\\/beetofthewild","https:\\/\\/www.pinterest.com\\/beetofthewild","https:\\/\\/x.com\\/https:\\/\\/www.twitter.com\\/beetofthewild","https:\\/\\/www.youtube.com\\/beetofthwild"]},{"@type":"Recipe","name":"Chili Lime Quinoa Salad with Kale and Chickpeas","author":{"@id":"https:\\/\\/www.beetofthewild.com\\/#\\/schema\\/person\\/acae3098bcee9097aec3c5f20598947a"},"description":"This crowd-pleasing Quinoa Salad with massaged kale, roasted Chickpeas and a homemade Chili Lime Dressing is the perfect make-ahead meal or potluck side!","datePublished":"2024-07-07T13:58:00+00:00","image":["https:\\/\\/www.beetofthewild.com\\/wp-content\\/uploads\\/2024\\/06\\/Chili-Lime-Quinoa-Salad-with-Kale-and-Chickpeas-Beet-of-the-Wild-Michelle-McCowan-ALLRIGHTSRESERVED-51.jpg","https:\\/\\/www.beetofthewild.com\\/wp-content\\/uploads\\/2024\\/06\\/Chili-Lime-Quinoa-Salad-with-Kale-and-Chickpeas-Beet-of-the-Wild-Michelle-McCowan-ALLRIGHTSRESERVED-51-500x500.jpg","https:\\/\\/www.beetofthewild.com\\/wp-content\\/uploads\\/2024\\/06\\/Chili-Lime-Quinoa-Salad-with-Kale-and-Chickpeas-Beet-of-the-Wild-Michelle-McCowan-ALLRIGHTSRESERVED-51-500x375.jpg","https:\\/\\/www.beetofthewild.com\\/wp-content\\/uploads\\/2024\\/06\\/Chili-Lime-Quinoa-Salad-with-Kale-and-Chickpeas-Beet-of-the-Wild-Michelle-McCowan-ALLRIGHTSRESERVED-51-480x270.jpg"],"video":{"name":"Crave-Worthy Quinoa Salad with Massaged Kale and Roasted Chickpeas","description":"If you\'re looking for a crave-worthy summer lunch or side, this Quinoa Salad is a must-try! Tossed in a homemade chili lime dressing with fresh vegetables, massaged kale, roasted chickpeas and fresh goat cheese, this quinoa salad is always a hit at potlucks, BBQs, picnics and summer cookouts. Plus, it\'s a great meal prep recipe that serves as a delicious weekday lunch.\\n\\nGet the Full Recipe\\u21a1\\nhttps:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/\\n\\nFind More Real Food Recipes \\u21a1\\nhttps:\\/\\/www.beetofthewild.com\\n\\nSubscribe + Get a Free eBook \\u21a1\\nhttps:\\/\\/www.beetofthewild.com\\/freebies\\/\\n\\nStay Connected\\u21a1\\nPinterest: https:\\/\\/pinterest.com\\/beetofthewild\\nFlipboard: https:\\/\\/flipboard.com\\/@beetofthewild \\nInstagram: https:\\/\\/instagram.com\\/beetofthewild \\nFacebook: https:\\/\\/facebook.com\\/beetofthewild\\n\\nMusic Credit \\u21a1\\nFolk Better Days by Sonic Collective\\n\\n\\n***This is Human Made and Edited Content***","uploadDate":"2024-07-07T18:00:16+00:00","duration":"PT2M9S","thumbnailUrl":"https:\\/\\/i.ytimg.com\\/vi\\/ZCmXi4hfzls\\/hqdefault.jpg","embedUrl":"https:\\/\\/www.youtube.com\\/embed\\/ZCmXi4hfzls?feature=oembed","contentUrl":"https:\\/\\/www.youtube.com\\/watch?v=ZCmXi4hfzls","@type":"VideoObject"},"recipeYield":["16"],"prepTime":"PT20M","totalTime":"PT20M","recipeIngredient":["3 Tbsp Olive Oil","2 Tbsp Apple Cider Vinegar","2 Tbsp Coconut Aminos","1 Organic Lime (Juice and Zest)","2 tsp Chili Powder","1 tsp Garlic Powder","1\\/4 tsp Ground Coriander","1\\/4 tsp Ground Turmeric","1\\/2 tsp Himalayan Salt","1 Dash Pepper","3 cups Cooked Quinoa (Organic)","2 stalks Kale","1 cup Homemade Chili Lime Chickpeas","1 cup Cherry Tomatoes (sliced or quartered)","1.5 cups Cucumber (chopped)","3\\/4 cup Yellow Bell Pepper (chopped)","3\\/4 cup Red Onion (chopped)","100 grams Fresh Goat Cheese \\/ Ch\\u00e8vre (pasture-raised)"],"recipeInstructions":[{"@type":"HowToStep","text":"In a small bowl, mix lime zest and juice, extra virgin olive oil, coconut aminos, apple cider vinegar, chili powder, garlic powder, ground coriander, ground turmeric, salt and pepper until well combined.","name":"Make Chili Lime Dressing","url":"https:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/#wprm-recipe-9740-step-0-0"},{"@type":"HowToStep","text":"Massage a few drops of Chili Lime Dressing into the kale (see how it&#39;s done in the video). Alternatively, you can use equal parts olive oil and apple cider vinegar. Then break the kale into bite-sized pieces.Massaging the kale gives it an extra punch of flavour. It also increases digestibility and nutrient absorption.","name":"Massage Kale","url":"https:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/#wprm-recipe-9740-step-0-1"},{"@type":"HowToStep","text":"In a large serving bowl, add cooked quinoa, chopped cucumber, cherry tomatoes, bell pepper and red onion. Lightly mix in the Roasted Chili Lime Chickpeas and fresh pasture-raised goat cheese (Ch\\u00e8vre). Optionally, you can leave either or both out to serve on the side.","name":"Mix Salad","url":"https:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/#wprm-recipe-9740-step-0-2"},{"@type":"HowToStep","text":"Next, drizzle the Chili Lime Dressing and gently mix. Then, toss in the kale until evenly distributed.","name":"Toss in Dressing","url":"https:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/#wprm-recipe-9740-step-0-3"},{"@type":"HowToStep","text":"Serve right away or keep chilled.This Quinoa Salad can be premixed and stored in the refrigerator. I prefer to store it in glass containers since plastic can compromise the taste and nutrition.If you like your vegetables extra fresh and crisp, you can also store the dressing separately and toss it into the salad right before serving.This Quinoa Salad will last up to 5 days when refrigerated and stored in an airtight container.","name":"Serve or Store","url":"https:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/#wprm-recipe-9740-step-0-4"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"5","ratingCount":"2","reviewCount":"2"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This salad was excellent. The dressing was flavorful. I didn\'t care for the chickpeas though. I felt they were dry and the process was too much work for the outcome. Since the chickpea seasoning was pretty much the same as the dressing, I\'ll add the chickpeas straight out of the can and just add the dressing as usual.","author":{"@type":"Person","name":"Diane"},"datePublished":"2025-08-13"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Crowd favourite salad for potlucks!","author":{"@type":"Person","name":"Pam"},"datePublished":"2024-07-08"}],"recipeCategory":["Main Course","Salad","Side Dish"],"recipeCuisine":["Mediterranean"],"suitableForDiet":["https:\\/\\/schema.org\\/GlutenFreeDiet","https:\\/\\/schema.org\\/LowLactoseDiet","https:\\/\\/schema.org\\/VegetarianDiet"],"keywords":"BBQ, Meal Prep, Potluck, Summer","nutrition":{"@type":"NutritionInformation","servingSize":"0.5 cup","calories":"104 kcal","carbohydrateContent":"12 g","proteinContent":"4 g","fatContent":"5 g","saturatedFatContent":"1 g","cholesterolContent":"3 mg","sodiumContent":"175 mg","fiberContent":"2 g","sugarContent":"1 g","unsaturatedFatContent":"3 g"},"@id":"https:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/#recipe","isPartOf":{"@id":"https:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/#article"},"mainEntityOfPage":"https:\\/\\/www.beetofthewild.com\\/chili-lime-quinoa-salad\\/"}]}',
                'image' => 'https://www.beetofthewild.com/wp-content/uploads/2024/06/Chili-Lime-Quinoa-Salad-with-Kale-and-Chickpeas-Beet-of-the-Wild-Michelle-McCowan-ALLRIGHTSRESERVED-51.jpg',
            'ingredients' => '["3 Tbsp Olive Oil","2 Tbsp Apple Cider Vinegar","2 Tbsp Coconut Aminos","1 Organic Lime (Juice and Zest)","2 tsp Chili Powder","1 tsp Garlic Powder","1\\/4 tsp Ground Coriander","1\\/4 tsp Ground Turmeric","1\\/2 tsp Himalayan Salt","1 Dash Pepper","3 cups Cooked Quinoa (Organic)","2 stalks Kale","1 cup Homemade Chili Lime Chickpeas","1 cup Cherry Tomatoes (sliced or quartered)","1.5 cups Cucumber (chopped)","3\\/4 cup Yellow Bell Pepper (chopped)","3\\/4 cup Red Onion (chopped)","100 grams Fresh Goat Cheese \\/ Ch\\u00e8vre (pasture-raised)"]',
            'directions' => '["In a small bowl, mix lime zest and juice, extra virgin olive oil, coconut aminos, apple cider vinegar, chili powder, garlic powder, ground coriander, ground turmeric, salt and pepper until well combined.","Massage a few drops of Chili Lime Dressing into the kale (see how it&#39;s done in the video). Alternatively, you can use equal parts olive oil and apple cider vinegar. Then break the kale into bite-sized pieces.Massaging the kale gives it an extra punch of flavour. It also increases digestibility and nutrient absorption.","In a large serving bowl, add cooked quinoa, chopped cucumber, cherry tomatoes, bell pepper and red onion. Lightly mix in the Roasted Chili Lime Chickpeas and fresh pasture-raised goat cheese (Ch\\u00e8vre). Optionally, you can leave either or both out to serve on the side.","Next, drizzle the Chili Lime Dressing and gently mix. Then, toss in the kale until evenly distributed.","Serve right away or keep chilled.This Quinoa Salad can be premixed and stored in the refrigerator. I prefer to store it in glass containers since plastic can compromise the taste and nutrition.If you like your vegetables extra fresh and crisp, you can also store the dressing separately and toss it into the salad right before serving.This Quinoa Salad will last up to 5 days when refrigerated and stored in an airtight container."]',
