            45 => 
            array (
                'id' => 46,
                'name' => 'Cheesy Potato Gratin Recipe ',
                'url' => 'https://cooking.nytimes.com/recipes/1017724-cheesy-hasselback-potato-gratin',
                'site_domain' => 'https//cooking.nytimes.com',
                'site_name' => 'Emily Weinstein',
                'user_id' => 1,
            'description' => 'The principal innovation here is placing the sliced potatoes in the casserole dish vertically, on their edges, rather than laying them flat as in a standard gratin, in order to get those crisp ridges on top. Allow extra time for the task of slicing the potatoes, for which it\'s helpful to have a mandoline or food processor (though not necessary, strictly speaking). And do buy extra potatoes, just in case; you want to pack the potatoes tightly and keep them standing up straight. Discover more ideas for the big day at NYT Cooking.',
            'content' => '{"@context":"http:\\/\\/schema.org","@id":"nyt:\\/\\/recipe\\/0142fca8-6d69-535e-bd40-8a5ad9f28fb2","@type":"Recipe","mainEntityOfPage":{"@id":"https:\\/\\/cooking.nytimes.com\\/recipes\\/1017724-cheesy-hasselback-potato-gratin","@type":"WebPage","name":"Cheesy Hasselback Potato Gratin"},"url":"https:\\/\\/cooking.nytimes.com\\/recipes\\/1017724-cheesy-hasselback-potato-gratin","name":"Cheesy Potato Gratin Recipe ","description":"The principal innovation here is placing the sliced potatoes in the casserole dish vertically, on their edges, rather than laying them flat as in a standard gratin, in order to get those crisp ridges on top. Allow extra time for the task of slicing the potatoes, for which it\'s helpful to have a mandoline or food processor (though not necessary, strictly speaking). And do buy extra potatoes, just in case; you want to pack the potatoes tightly and keep them standing up straight. Discover more ideas for the big day at NYT Cooking.","author":{"@type":"Person","name":"Emily Weinstein"},"image":[{"@id":"nyt:\\/\\/image\\/77fce7a6-76f1-58a3-8de9-a6deb4c1d3c1#videoSixteenByNineJumbo1600","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-videoSixteenByNineJumbo1600.jpg","creditText":"Christopher Testani for The New York Times. Food Stylist:Simon Andrews. Prop Stylist: Christina Lane.","dateModified":"2025-11-07T15:43:58.350Z","datePublished":"2021-11-02T13:36:49.000Z","height":"900","representativeOfPage":true,"uploadDate":"2021-11-02T13:36:49.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-videoSixteenByNineJumbo1600.jpg","width":"1600"},{"@id":"nyt:\\/\\/image\\/77fce7a6-76f1-58a3-8de9-a6deb4c1d3c1#threeByTwoLargeAt2X","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-threeByTwoLargeAt2X.jpg","creditText":"Christopher Testani for The New York Times. Food Stylist:Simon Andrews. Prop Stylist: Christina Lane.","dateModified":"2025-11-07T15:43:58.350Z","datePublished":"2021-11-02T13:36:49.000Z","height":"4059","representativeOfPage":true,"uploadDate":"2021-11-02T13:36:49.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-threeByTwoLargeAt2X.jpg","width":"6090"},{"@id":"nyt:\\/\\/image\\/77fce7a6-76f1-58a3-8de9-a6deb4c1d3c1#mediumSquareAt3X","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-mediumSquareAt3X.jpg","creditText":"Christopher Testani for The New York Times. Food Stylist:Simon Andrews. Prop Stylist: Christina Lane.","dateModified":"2025-11-07T15:43:58.350Z","datePublished":"2021-11-02T13:36:49.000Z","height":"1800","representativeOfPage":true,"uploadDate":"2021-11-02T13:36:49.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-mediumSquareAt3X.jpg","width":"1800"},{"@id":"nyt:\\/\\/image\\/77fce7a6-76f1-58a3-8de9-a6deb4c1d3c1#facebookJumbo","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-facebookJumbo.jpg","creditText":"Christopher Testani for The New York Times. Food Stylist:Simon Andrews. Prop Stylist: Christina Lane.","dateModified":"2025-11-07T15:43:58.350Z","datePublished":"2021-11-02T13:36:49.000Z","height":"549","representativeOfPage":true,"uploadDate":"2021-11-02T13:36:49.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-facebookJumbo.jpg","width":"1050"}],"totalTime":"PT2H","recipeYield":"6 servings","recipeCuisine":"american","recipeCategory":"side dish","keywords":"christmas, thanksgiving, gratin, gruy\\u00e8re, heavy cream, russet potato","aggregateRating":{"@type":"AggregateRating","ratingValue":5,"ratingCount":9316},"nutrition":{"@context":"http:\\/\\/schema.org","@type":"NutritionInformation","calories":657,"unsaturatedFatContent":"12 grams","carbohydrateContent":"62 grams","cholesterolContent":null,"fatContent":"40 grams","fiberContent":"5 grams","proteinContent":"16 grams","saturatedFatContent":"25 grams","sodiumContent":"1004 milligrams","sugarContent":"4 grams","transFatContent":"1 gram"},"recipeIngredient":["3 ounces finely grated Gruy\\u00e8re or comt\\u00e9 cheese","2 ounces finely grated Parmigiano-Reggiano","2 cups heavy cream","2 medium cloves garlic, minced","1 tablespoon fresh thyme leaves, roughly chopped","Kosher salt and black pepper","4 to 4 1\\/2 pounds russet potatoes, peeled and sliced 1\\/8-inch thick on a mandoline slicer (7 to 8 medium, see Tip)","2 tablespoons unsalted butter"],"recipeInstructions":[{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"Adjust oven rack to middle position and heat oven to 400 degrees. Combine cheeses in a large bowl. Transfer 1\\/3 of cheese mixture to a separate bowl and set aside. Add cream, garlic and thyme to cheese mixture. Season generously with salt and pepper. Add potato slices and toss with your hands until every slice is coated with cream mixture, making sure to separate any slices that are sticking together to get the cream mixture in between them."},{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"Grease a 2-quart casserole dish with butter. Pick up a handful of potatoes, organizing them into a neat stack, and lay them in the casserole dish with their edges aligned vertically. Continue placing potatoes in the dish, working around the perimeter and into the center until all the potatoes have been added. The potatoes should be very tightly packed. If necessary, slice an additional potato, coat with cream mixture, and add to casserole."},{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"Pour the excess cream\\/cheese mixture evenly over the potatoes until the mixture comes halfway up the sides of the casserole. You may not need all the excess liquid."},{"@context":"http:\\/\\/schema.org","@type":"HowToStep","text":"Cover dish tightly with foil and transfer to the oven. Bake for 30 minutes. Remove foil and continue baking until the top is pale golden brown, about 30 minutes longer. Carefully remove from oven, sprinkle with remaining cheese, and return to oven. Bake until deep golden brown and crisp on top, about 30 minutes longer. Remove from oven, let rest for a few minutes, and serve."}],"video":{"@id":"nyt:\\/\\/video\\/714b42e0-589d-575d-98cc-147d90f85669","@type":"VideoObject","author":{"@id":"nyt:\\/\\/person\\/56667012-c61f-532b-9929-8f2ccf6962a9","@type":"Person","name":"Adam Centrella","url":"https:\\/\\/www.nytimes.com\\/by\\/adam-centrella"},"bitrate":"1456429","contentSize":"103703783","contentUrl":"https:\\/\\/vp.nyt.com\\/video\\/2025\\/11\\/03\\/153585_1_Cheesy-Hasselback-Potato-Gratin-YT-VID_wg_480p.mp4","creator":{"@id":"nyt:\\/\\/person\\/56667012-c61f-532b-9929-8f2ccf6962a9","@type":"Person","name":"Adam Centrella","url":"https:\\/\\/www.nytimes.com\\/by\\/adam-centrella"},"dateModified":"2025-11-07T15:44:00.958Z","datePublished":"2025-11-06T15:50:56.000Z","duration":"PT8M43S","height":"480","name":"Cheesy Hasselback Potato Gratin","publisher":{"@id":"https:\\/\\/www.nytimes.com\\/#publisher","@type":"NewsMediaOrganization","name":"The New York Times"},"thumbnail":[{"@id":"nyt:\\/\\/image\\/77fce7a6-76f1-58a3-8de9-a6deb4c1d3c1#videoSixteenByNineJumbo1600","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-videoSixteenByNineJumbo1600.jpg","creditText":"Christopher Testani for The New York Times. Food Stylist:Simon Andrews. Prop Stylist: Christina Lane.","dateModified":"2025-11-07T15:43:58.350Z","datePublished":"2021-11-02T13:36:49.000Z","height":"900","uploadDate":"2021-11-02T13:36:49.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-videoSixteenByNineJumbo1600.jpg","width":"1600"},{"@id":"nyt:\\/\\/image\\/77fce7a6-76f1-58a3-8de9-a6deb4c1d3c1#threeByTwoLargeAt2X","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-threeByTwoLargeAt2X.jpg","creditText":"Christopher Testani for The New York Times. Food Stylist:Simon Andrews. Prop Stylist: Christina Lane.","dateModified":"2025-11-07T15:43:58.350Z","datePublished":"2021-11-02T13:36:49.000Z","height":"4059","uploadDate":"2021-11-02T13:36:49.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-threeByTwoLargeAt2X.jpg","width":"6090"},{"@id":"nyt:\\/\\/image\\/77fce7a6-76f1-58a3-8de9-a6deb4c1d3c1#mediumSquareAt3X","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-mediumSquareAt3X.jpg","creditText":"Christopher Testani for The New York Times. Food Stylist:Simon Andrews. Prop Stylist: Christina Lane.","dateModified":"2025-11-07T15:43:58.350Z","datePublished":"2021-11-02T13:36:49.000Z","height":"1800","uploadDate":"2021-11-02T13:36:49.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-mediumSquareAt3X.jpg","width":"1800"},{"@id":"nyt:\\/\\/image\\/77fce7a6-76f1-58a3-8de9-a6deb4c1d3c1#facebookJumbo","@type":"ImageObject","contentUrl":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-facebookJumbo.jpg","creditText":"Christopher Testani for The New York Times. Food Stylist:Simon Andrews. Prop Stylist: Christina Lane.","dateModified":"2025-11-07T15:43:58.350Z","datePublished":"2021-11-02T13:36:49.000Z","height":"549","uploadDate":"2021-11-02T13:36:49.000Z","url":"https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-facebookJumbo.jpg","width":"1050"}],"thumbnailUrl":["https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-videoSixteenByNineJumbo1600.jpg","https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-threeByTwoLargeAt2X.jpg","https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-mediumSquareAt3X.jpg","https:\\/\\/static01.nyt.com\\/images\\/2021\\/11\\/02\\/dining\\/kla-hasselback-potatoes\\/kla-hasselback-potatoes-facebookJumbo.jpg"],"transcript":"\\u201cI like that that looks like one mouthful the way it is right now.\\u201d \\u201cLike that.\\u201d [MUSIC PLAYING] \\u201cHey, everyone, I\\u2019m Kenji L\\u00f3pez-Alt. I am a \\u2018New York Times\\u2019 contributor and the author of \\u2018The Food Lab,\\u2019 and in this book I had a recipe for this dish. The idea for this recipe started with the concept of a potato gratin. I wanted to have a potato gratin recipe in here. And then I was thinking about this other dish called hasselback potatoes. It was a dish that was created in the 1950s in Sweden. The idea is that you take a whole potato, you slice it not quite all the way through, but you cut it into a lot of thin slices that are all connected on the bottom. You put butter on it and you roast it, and so you end up with this half baked potato, half potato chip hybrid thing. So the idea was how do I combine that dish with a potato gratin. And so what we do is we slice our potatoes and put them on their side, and so you end up with a dish that\\u2019s creamy and buttery and cheesy and really satisfying in the way that potato gratin is but with this array of potato chip-like crispiness on the top. It\\u2019s really good. It\\u2019s great for the holidays. It\\u2019s -- is it great any time of year? It\\u2019s not great in the middle of the summer, but it\\u2019s really good for the holidays or whenever it\\u2019s cold outside or whenever you feel like doing a little bit of work and putting some time into your potatoes. So first thing we\\u2019re going to do, we\\u2019re going to start with russet potatoes. I like to use russet potatoes for this because they have a higher starch content and a lower water content than most other types of potatoes. When they\\u2019re starchier like this, they end up a little bit crisper, so you get a much nicer contrast between the crisp top layer and the creamier bottom layer in the same way that a russet potato makes a really good French fry because it gets crispy on the outside but stays nice and fluffy and creamy in the center. So we\\u2019re going to do about 4 to 4 and 1\\/2 pounds of these. We want basically enough that they\\u2019re going to fill up a casserole dish entirely. Once you\\u2019ve got your potatoes done. Now we\\u2019re going to slice them. So we want to go about an 1\\/8 of an inch thick. That looks about right. These mandolins are sharp, And They come with a little plastic guard which always gets lost. But you can also get Kevlar gloves, or you can get someone else to do this bit like a little small child.\\u201d \\u201cJoke.\\u201d \\u201cIt was a joke.\\u201d \\u201cOnce you get your potato sliced, you put together this cream mixture. So it\\u2019s going to be heavy cream as well as a mixture of parmesan and gruyere. So we\\u2019re going to actually keep some of this grated gruyere and parmesan off to the side, about 1\\/3 of it off to the side because we\\u2019re going to add that to the top in the end. But the rest we\\u2019re going to put right in here. We\\u2019ve got some fresh thyme, minced garlic, and then some freshly ground pepper and salt. Whenever you\\u2019re making a potato dish, potatoes really love salt, so you want to make sure you season it pretty heavily, a little more than you think you should. We\\u2019re going to mix that all up. And this is a thing where it is best to get in there with your hands. So we\\u2019ll get all our potatoes in this bowl. This is a step by way you can\\u2019t really do any of this ahead because potatoes, they oxidize if you slice them or peel them. So they\\u2019ll start to turn red, and if you let them sit long enough, they\\u2019ll even start to turn black. It\\u2019s not going to kill you or anything, but it makes the dish look not as good. The one thing you got to be careful about is that the potato slices because of their big surface area tend to stick together, so you want to make sure that you\\u2019re separating the potatoes and getting that cream mixture really nicely, coating each slice. I wouldn\\u2019t do the potatoes ahead and soak them in water. When you do that, you -- you\\u2019re -- you pull starch out of there, and so it actually ends up a little bit less creamy when you do that. This is one of those dishes where you once you start making it, you want to get it into the oven. There\\u2019s going to be three basic oven steps in here, and you could potentially do the first two ahead of time and then finish it off on the last day if you really want to make this ahead. But potatoes, their starch retrogrades once you\\u2019ve cooked it and let them cool, which is why french fries or mashed potatoes are never quite as good when you reheat them. I\\u2019m not going to bother washing my hands because I\\u2019m going to take some butter and rub it into this casserole dish. You want to get it to go all the way up the edges because as this gratin cooks, the cream starts to bubble up, and it\\u2019ll leave a layer of caramelized cream and cheese all around the edges, which is really nice to pick off and eat before you serve it to your guests. Since I got this extra butter, I\\u2019m just going to -- just going to plop it in here. Now at this stage, we\\u2019re going to start assembling our casserole. And what you want to do is take a little stacks of potatoes like that. You actually don\\u2019t want the edges to line up perfectly. So it\\u2019s perfectly fine that some are big and some are small because we want some of the edges to jut out and others to sink down. We\\u2019re just going to work our way around the perimeter first. If you\\u2019ve got kids, this is a good task for them to do. Oftentimes I will do a ton of experimenting to come up with a recipe. This is one of those dishes where I literally woke up in the middle of the night, and I was like, oh, that\\u2019s a great idea. And I started peeling potatoes at like 2:00 AM and stayed up until 4:00 until the first one came out of the oven. But the idea for the dish itself was one of those rare moments where it just came in a dream. I came up with this idea, like, come on, somebody\\u2019s got to have done this before, and I\\u2019m sure somebody has but at least not in the published literature, because we went around looking in books and looking all over the internet to see if there was a sideways potato gratin. And at the time that I wrote this recipe, there wasn\\u2019t. So once you work your way all the way around the edges, you\\u2019re going to start filling up the center like this. You might find that 4 or 4 and 1\\/2 pounds is not quite enough to fit into a dish. This turned out pretty perfectly. So if you do find that you don\\u2019t have quite enough potatoes left over, you can always just slice an extra one, get it mixed in here and mix it in. Now if you have too much potatoes, you can also get a little ramekin or something and make a little side casserole for yourself. I should have done this at the beginning, but I am going to just taste my cream mixture for seasoning. Yeah, so it should be nice and salty at this point because you need to put enough salt into the cream that it seasons all the potatoes and the cream mixture. We\\u2019re going to cover it with foil, and then we\\u2019re going to put it straight into a 400 degree oven for about 30 minutes. So all we\\u2019re going to do now is take that foil off, pop it back in, and it\\u2019s going to go for another 30 minutes uncovered like that. Ooh, it\\u2019s looking like the inside of an angry volcano here. We\\u2019re going to add some cheese. There\\u2019s some chefs or cookbook authors I\\u2019ve read who insist that a potato gratin does not need cheese. I think they\\u2019re correct. But it doesn\\u2019t need cheese in the way that a bath doesn\\u2019t need bubbles. It\\u2019ll function, but it\\u2019s better with it. And because this looks like it might overflow the edges a little bit and I don\\u2019t want to completely mess up my oven or the \\u2018New York Times\\u2019\\u2019 oven, I\\u2019m going to stick a tray on the bottom. It\\u2019s going to go for one final half hour where it\\u2019s going to crisp up. Things are looking good in here. The cream has broken, meaning that it has evaporated enough that the butter fat of it is starting to separate from the liquid elements, which means that the potatoes have absorbed some of that milk whey. They\\u2019ve absorbed some of the butter fat, so they\\u2019re going to be nice and creamy in the bottom. Let me give it a little poke to make sure that we\\u2019re tender all the way through. Oh, yeah. This is going to be insanely hot at this point, so I\\u2019m going to let it rest for about 10, 15 minutes or so. And in that time, what\\u2019s going to happen is some of that butter that we see bubbling at the surface will all sink back down and absorb into the potatoes. So this is the finished dish. You can see the bottoms of these potatoes are really nice and creamy. And the tops, you get these almost little potato chip-like crunchy bits. So when you eat it all together, just it\\u2019s like wild mix of textures and flavors that all come from really simple ingredients -- a hint of garlic, a hint of thyme. So good it doesn\\u2019t even need gravy. You can find this recipe, all of my other recipes, and all of the other great recipes from other contributors on New York Times Cooking.com.\\u201d [MUSIC PLAYING]","uploadDate":"2025-11-06T15:50:56.000Z","url":"https:\\/\\/www.nytimes.com\\/video\\/embedded\\/dining\\/100000010499279\\/cheesy-hasselback-potato-gratin.html","width":"854"},"publisher":{"@id":"https:\\/\\/cooking.nytimes.com\\/#publisher","@type":"Organization","name":"NYT Cooking"},"datePublished":"2015-09-30T00:00:00.000Z","dateModified":"2025-11-12T21:13:26.000Z","review":[{"@type":"Review","author":{"@type":"Person","name":"Joshua"},"reviewBody":"At listed temp, times and colors- the potatoes came out a little al dente. I will probably slice thinner than the recommended 1\\/4\\u201d next time.","datePublished":"2025-11-16T14:28:51.000Z"},{"@type":"Review","author":{"@type":"Person","name":"CarGonza"},"reviewBody":"@Danny This is such an easy, uncomplicated recipe. If it was too much for you, good luck with the rest of this app.","datePublished":"2025-11-15T13:44:12.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Joshua"},"reviewBody":"@Barrett same issue! I ran out of potatoes- so used a yam and simply shuffled it into the stacks to fill space. I took it out of the oven at time- then chose a random disc to test- so soft but\\u2026sweet? I had forgotten that I had interspersed those yam pieces. I chose another disc from another spot, same thing! Then I remembered, LOL what are the chances? Third try found a potato, and yes- al dente! Returned to oven for an additional 20 minutes at lower heat. Next time will simply slice thinner than the 1\\/4\\u201d recommended (I did think that was pretty thick while prepping\\u2026)","datePublished":"2025-11-16T14:38:18.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Barrett"},"reviewBody":"I wanted to love this recipe\\u2014but even after 100 minutes in the oven, the potatoes were still crunchy. Flavor is excellent. I just want softer potatoes!","datePublished":"2025-11-15T03:50:20.000Z"},{"@type":"Review","author":{"@type":"Person","name":"evieid"},"reviewBody":"Wanted to add a quick note about russet potatoes. They are not all created equal! The best tasting russet potato is the Russet Burbank. Most potatoes in the grocery store labeled as Russet are Norkotahs. \\n\\nNorkotahs are prettier (more oval, more shallow eyes, few knobs), but less tasty than the classic Russet Burbank. I highly recommend the Russet Burbanks variety if you can find them. I come from a farming family in Idaho and take these things very seriously!","datePublished":"2025-11-14T18:22:27.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Aileen G"},"reviewBody":"Can you make this in advance? If so, where should you stop the process?","datePublished":"2025-11-14T17:03:06.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Pips"},"reviewBody":"Can I make this and freeze it for dinner next week?","datePublished":"2025-11-14T16:10:53.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Jan"},"reviewBody":"Can this be made the day before and just cooked on Tanksgiving? Or should it be fully cooked and reheated on the day of the dinner?","datePublished":"2025-11-14T16:12:59.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Paige"},"reviewBody":"I made this yesterday. Wow! So delicious! I couldn\\u2019t stop eating it LOL. I did a half recipe just to try it out prior to making it for thanksgiving. 2.5 lbs of russet potatoes (3 large ones). My husband does NOT like cheese\\u2026 I love cheese! so I used Comte and parmigiana, my thinking on that was the Comte isn\\u2019t as strong of a flavor as Gruy\\u00e8re can be! I baked it in a 1.5qt round Pyrex casserole dish. Used all of the sliced up potatoes as well as all of the cheese\\/cream mixture, the cream mixture only came up halfway when I poured it over the potatoes. Nothing overflowed! Lots of great browned crispy edges. The cooking time was spot on for me as well. AND BEST OF ALL my cheese hating husband liked it!!!! Woohoo! Major freaking win! Will definitely be making this again and for thanksgiving!!!","datePublished":"2025-11-13T15:07:04.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Alexandra"},"reviewBody":"Does anyone know the casserole dish being used? I love it!","datePublished":"2025-11-13T04:47:16.000Z"},{"@type":"Review","author":{"@type":"Person","name":"KC"},"reviewBody":"As long as you scrub the potatoes clean, you don\'t need to peel them. Potato skins are delicious as they bake and crisp up","datePublished":"2025-11-13T01:26:12.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Jakob Lindstr\\u00f6m Wranne"},"reviewBody":"Yes, Hasselbacks Potatoes were invented at the Hasselbacken Restaurant in the Royal Djurg\\u00e5rden (Royal Animal Haven) island in central Stockholm, Sweden. This happened just before the end of the 19th century. In Swedish it\'s called Hasselbackspotatis. And, it\'s still as loved today as back then. It\'s an easy way of cooking something that has an extravagant touch to it.","datePublished":"2025-11-12T23:55:16.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Crystal"},"reviewBody":"I made this recipe the other day exactly as its written and it was wonderful. I used a square 8\\u00d78 2-quart glass baking dish. I think if I had a longer, slightly shallower cooking vessel, it would have allowed for better browning and even more of a crunchy consistency on the tops of the potatoes. I didn\'t need all of the cream mixture. I poured the cream more than half way up the side of the pan (oops!) and I had some cheese bubbling over onto the handles of the dish. Thank goodness I put a sheet pan directly below the dish because I did have oil drip down and collect on it. In hindsight, I recommend covering the sheet pan with foil for easier cleanup. The smell of the potatoes cooking filled my house with the most delightful aroma of cheese, garlic, and thyme. Definitely worth making!","datePublished":"2025-11-12T21:21:19.000Z"},{"@type":"Review","author":{"@type":"Person","name":"mmtacoma"},"reviewBody":"@Jenn D. Taste as you go! When the cream tastes salty to you, you\\u2019re good.","datePublished":"2025-11-13T05:38:36.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Jenn D."},"reviewBody":"Any idea of how much Kosher salt they\'re using in this recipe? He says to oversalt it, but there is no indication of how much to use. Any advice from those that have made it before is useful, thanks.","datePublished":"2025-11-12T20:49:19.000Z"},{"@type":"Review","author":{"@type":"Person","name":"David C."},"reviewBody":"I make a potato gratin that\'s similar, but I start by saut\\u00e9ing about 1 cup of chopped onions with salt in butter until soft. Then add cream and thyme, bring to gentle simmer to reduce the moisture. Remove from heat and add grated Parmesan \\/ Romano and stir until melted. Let cool before adding to potatoes. The extra steps take 10 minutes (plus cooling) and yields a more favorable gratin.","datePublished":"2025-11-12T20:19:52.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Dawn"},"reviewBody":"I have been making a version of this recipe for a number of years for Christmas dinner. I use white cheddar and parm. This recipe is so easy, and it tastes good. My family really enjoys it.","datePublished":"2025-11-12T17:33:37.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Kris"},"reviewBody":"A couple of things...<br\\/>1. Since Hasselback is called out here, acknowledgement to our friends in Sweden @ the Hasselback Hotel are in order. Legend has it this dish was invented there.<br\\/>2. A lot of time can be saved arranging potatoes on their ends by taking a nice Yukon Gold, placing it in a wooden spoon (the spoony-end) and slicing till your knife hits the spoon. The tater stays together nicely at the bottom and it\'s very easy to handle. You can google this.","datePublished":"2017-10-30T15:44:30.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Kate C"},"reviewBody":"Excellent! Added a grated onion to the liquid\\/cheese mix for flavor. Made it through first 2 thirty minute bakings in advance. Then covered and chilled. Brought to the dinner, sprinkled cheese on top and did final baking of about 40 minutes at the meal (removed foil half way through.) Texture was great! I was worried because initially liquid barely covered bottom of pan, but juices came out with baking and it was perfect! Good crusty bits on bottom too. A real keeper of a recipe.","datePublished":"2017-10-30T15:51:05.000Z"},{"@type":"Review","author":{"@type":"Person","name":"J Hoppe"},"reviewBody":"I made this dish for Thanksgiving with sweet potatoes (not yams) to wild success. My family practically hoisted me upon their shoulders. When I called my mother a week later, she answered the phone without a hello: \\"Those sweet potatoes were the best thing I\'ve ever eaten.\\"\\nI said, \\"Hi, Mom. How\'s everything?\\"\\nShe said, \\"God, those sweet potatoes were good.\\"\\nI give my full throated endorsement for this recipe. It can make you feel like a conquering hero.","datePublished":"2017-12-11T17:26:01.000Z"},{"@type":"Review","author":{"@type":"Person","name":"John A."},"reviewBody":"I\'ve read reference here to soaking the potatoes in water before making the dish- as a shortcut or \\"timesaver\\" I suppose- even from a food editor at the Times. Big mistake. Any of these gratin Dauphinois kind of potato dishes (sliced potatoes baked in cream) need the natural starch of the potato mixed with the cream to thicken it, not to mention the flavor of the potato. Soaking the sliced potatoes washes starch & flavor away and reduces the quality of the finished dish.","datePublished":"2017-10-24T17:26:06.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Lee"},"reviewBody":"We made this with sweet potatoes instead of russets, and it was absolutely amazing. Very delicious (both savory and sweet), and exactly as you promised: creamy potato and crusty cheesy edge in every bite. It was transcendent.","datePublished":"2017-10-30T15:02:57.000Z"},{"@type":"Review","author":{"@type":"Person","name":"christine Andrews"},"reviewBody":"I made these in cupcake tins. Extra crispy and a nice serving size.","datePublished":"2019-08-31T20:07:13.000Z"},{"@type":"Review","author":{"@type":"Person","name":"recox"},"reviewBody":"I would say it serves 6, but it depends on what else you are serving. I made a double batch in an 11x13 pan and it was about 12 one-cup servings. My guests fell on it like starving wolves and ate every scrap, so you should probably err on the side of too much rather than too little. It is THAT delicious. <br\\/><br\\/>Since my dish was rectangular I put the slices in rows. There was a gap along the edge of the pan, so I pushed the rows together more tightly to make room for another full row.","datePublished":"2017-10-30T15:45:04.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Jerry"},"reviewBody":"Great recipe! I\'ve made it twice with great success. I used somewhat more cheese than called for because I like rich, creamy dishes. I didn\'t peel the potatoes on the second try because my daughter insisted that the peel has all the nutrients. It was just as good. It\'s helpful to choose potatoes of equal size.","datePublished":"2017-10-30T15:05:50.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Rita"},"reviewBody":"OK. Russets? Really? The best potato for a recipe like this is an Eastern white like Long Island White or Maine Katahdin. Sorry. A potato snob since we grow them and are knowledgeable about the characteristics of the MANY different varieties.","datePublished":"2017-10-30T15:51:53.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Mona"},"reviewBody":"I agree. No Russets but Yukon Gold Potatoes are the Best for this","datePublished":"2017-10-30T15:58:32.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Pat"},"reviewBody":"I made this for Christmas, and it was amazing! Came out looking just like the photo. Potatoes were cheesy and soft on the bottom and crusty brown on top. I used 6 ounces of Gruyere cheese, and half and half instead of the heavy cream. It was so good, and got such rave reviews, that it will be a permanent part of our holiday fare from now on, and I\'ll definitely make it for guests throughout the year too!","datePublished":"2017-10-24T18:08:09.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Arianna"},"reviewBody":"Delicious - and very very rich. I made a half recipe in an 8x8 Pyrex baking dish; I had very little excess liquid, but the dish is still moist. Pay attention to the note to season generously - I used maybe a teaspoon of salt, and it\'s definitely not enough.","datePublished":"2017-10-30T15:00:32.000Z"},{"@type":"Review","author":{"@type":"Person","name":"kate"},"reviewBody":"Oops. Did not read carefully...now I see there are three 30 minute segments. I did have to give it \'extra\' time to brown it but the potatoes were still a bit too firm. Great flavor and I will make it correctly next time. I was glad to have help in the kitchen-it\'s a lot of prep work and the cream was flying when I was placing the creamy potato stacks in the dish. Also, recommend placing the casserole on a baking sheet in the oven.","datePublished":"2017-10-30T15:11:14.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Sam"},"reviewBody":"Soaked cut potatoes for 1 hour in cold water. Doubled cheese (which I grated fresh), Added 1t dried mustard, 1\\/2 cup diced onions saut\\u00e9ed brown in butter, 1T black pepper and 1T salt to mix before tossing potatoes and putting in dish. Baking takes 50 minutes (done at 400 covered\\/420 uncovered). Excellent!","datePublished":"2017-10-30T15:00:51.000Z"},{"@type":"Review","author":{"@type":"Person","name":"Scott"},"reviewBody":"Used Yukon Gold potatoes and left the skins on. Looked great. Added 1T Dijon mustard and 1.5 tsp smoked paprika as someone else here had suggested. Definitely improved the flavor over the original recipe (which we\'d tasted in the past). Also doubled the cheese--my wife says it\'s the staff of life. Who am I to argue.","datePublished":"2017-10-01T13:51:23.000Z"}],"copyrightHolder":{"@id":"https:\\/\\/cooking.nytimes.com\\/#publisher","@type":"Organization","name":"NYT Cooking"},"copyrightYear":2015}',
                'image' => 'https://static01.nyt.com/images/2021/11/02/dining/kla-hasselback-potatoes/kla-hasselback-potatoes-videoSixteenByNineJumbo1600.jpg',
            'ingredients' => '["3 ounces finely grated Gruy\\u00e8re or comt\\u00e9 cheese","2 ounces finely grated Parmigiano-Reggiano","2 cups heavy cream","2 medium cloves garlic, minced","1 tablespoon fresh thyme leaves, roughly chopped","Kosher salt and black pepper","4 to 4 1\\/2 pounds russet potatoes, peeled and sliced 1\\/8-inch thick on a mandoline slicer (7 to 8 medium, see Tip)","2 tablespoons unsalted butter"]',
                'directions' => '["Adjust oven rack to middle position and heat oven to 400 degrees. Combine cheeses in a large bowl. Transfer 1\\/3 of cheese mixture to a separate bowl and set aside. Add cream, garlic and thyme to cheese mixture. Season generously with salt and pepper. Add potato slices and toss with your hands until every slice is coated with cream mixture, making sure to separate any slices that are sticking together to get the cream mixture in between them.","Grease a 2-quart casserole dish with butter. Pick up a handful of potatoes, organizing them into a neat stack, and lay them in the casserole dish with their edges aligned vertically. Continue placing potatoes in the dish, working around the perimeter and into the center until all the potatoes have been added. The potatoes should be very tightly packed. If necessary, slice an additional potato, coat with cream mixture, and add to casserole.","Pour the excess cream\\/cheese mixture evenly over the potatoes until the mixture comes halfway up the sides of the casserole. You may not need all the excess liquid.","Cover dish tightly with foil and transfer to the oven. Bake for 30 minutes. Remove foil and continue baking until the top is pale golden brown, about 30 minutes longer. Carefully remove from oven, sprinkle with remaining cheese, and return to oven. Bake until deep golden brown and crisp on top, about 30 minutes longer. Remove from oven, let rest for a few minutes, and serve."]',
                'nutrition' => '{"@context":"http:\\/\\/schema.org","@type":"NutritionInformation","calories":657,"unsaturatedFatContent":"12 grams","carbohydrateContent":"62 grams","cholesterolContent":null,"fatContent":"40 grams","fiberContent":"5 grams","proteinContent":"16 grams","saturatedFatContent":"25 grams","sodiumContent":"1004 milligrams","sugarContent":"4 grams","transFatContent":"1 gram"}',
                'slug' => 'cheesy-potato-gratin-recipe',
