protein, high-fiber recipe that\\u2019s gluten free, easily vegetarian, and perfect for a hearty dinner.","breadcrumb":{"@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#breadcrumb"},"mainEntity":[{"@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1691085282993"},{"@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1692026331353"},{"@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1729621560710"}],"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#primaryimage","url":"https:\\/\\/avocadoskillet.com\\/wp-content\\/uploads\\/2025\\/09\\/IMG_2025-09-30-152928.jpeg","contentUrl":"https:\\/\\/avocadoskillet.com\\/wp-content\\/uploads\\/2025\\/09\\/IMG_2025-09-30-152928.jpeg","width":1200,"height":1200,"caption":"garlic parmesan white bean stew"},{"@type":"BreadcrumbList","@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/avocadoskillet.com\\/"},{"@type":"ListItem","position":2,"name":"Fall Favorites","item":"https:\\/\\/avocadoskillet.com\\/category\\/fall\\/"},{"@type":"ListItem","position":3,"name":"Garlic Parmesan White Bean Stew (high protein)"}]},{"@type":"WebSite","@id":"https:\\/\\/avocadoskillet.com\\/#website","url":"https:\\/\\/avocadoskillet.com\\/","name":"Avocado Skillet","description":"Healthy Plant Based Recipes and Wellness","publisher":{"@id":"https:\\/\\/avocadoskillet.com\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/avocadoskillet.com\\/?s={search_term_string}"},"query-input":"required name=search_term_string"}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/avocadoskillet.com\\/#organization","name":"Avocado Skillet","url":"https:\\/\\/avocadoskillet.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/avocadoskillet.com\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/avocadoskillet.com\\/wp-content\\/uploads\\/2022\\/01\\/logo_digital_3_50.jpg","contentUrl":"https:\\/\\/avocadoskillet.com\\/wp-content\\/uploads\\/2022\\/01\\/logo_digital_3_50.jpg","width":649,"height":132,"caption":"Avocado Skillet"},"image":{"@id":"https:\\/\\/avocadoskillet.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/www.instagram.com\\/avocado_skillet\\/","https:\\/\\/www.pinterest.com\\/avocadoskillet\\/","https:\\/\\/www.facebook.com\\/avocadoskillet\\/"]},{"@type":"Person","@id":"https:\\/\\/avocadoskillet.com\\/#\\/schema\\/person\\/9672699ccfbdf3802f89f9b9384e801d","name":"Kristi","image":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/avocadoskillet.com\\/#\\/schema\\/person\\/image\\/","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/a056597af5f6885fa21448efda40a062e149f03ef2bc619db73c4db500f2db0d?s=96&d=mm&r=g","contentUrl":"https:\\/\\/secure.gravatar.com\\/avatar\\/a056597af5f6885fa21448efda40a062e149f03ef2bc619db73c4db500f2db0d?s=96&d=mm&r=g","caption":"Kristi"},"sameAs":["https:\\/\\/avocadoskillet.com\\/about-me\\/"]},{"@type":"Question","@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1691085282993","position":1,"url":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1691085282993","name":"Is parmesan cheese healthy?","answerCount":1,"acceptedAnswer":{"@type":"Answer","text":"Parmesan is high in protein, calcium, and phosphorus, making it great for supporting strong bones and muscles. It also contains probiotics and easily digestible nutrients that promote gut health and provide a concentrated source of energy.","inLanguage":"en-US"},"inLanguage":"en-US"},{"@type":"Question","@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1692026331353","position":2,"url":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1692026331353","name":"What are the benefits of beans?","answerCount":1,"acceptedAnswer":{"@type":"Answer","text":"Beans are rich in plant-based protein, fiber, and essential nutrients that support heart health, stabilize blood sugar, and promote digestion. They also help lower cholesterol, keep you fuller for longer, and contribute to overall gut and metabolic health.","inLanguage":"en-US"},"inLanguage":"en-US"},{"@type":"Question","@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1729621560710","position":3,"url":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#faq-question-1729621560710","name":"Can I make this soup vegan?","answerCount":1,"acceptedAnswer":{"@type":"Answer","text":"Yes - use vegetable broth and vegan parmesan cheese. You could also play around with using nutritional yeast but 1\\/2 a cup would be too much.","inLanguage":"en-US"},"inLanguage":"en-US"},{"@type":"Recipe","name":"Garlic Parmesan White Bean Stew (high protein)","author":{"@id":"https:\\/\\/avocadoskillet.com\\/#\\/schema\\/person\\/9672699ccfbdf3802f89f9b9384e801d"},"description":"Garlic Parmesan White Bean Stew is a cozy, high-protein and high-fiber meal that\\u2019s naturally gluten free and can easily be made vegetarian. Creamy beans, garlic, fresh herbs, and parmesan come together for a nourishing stew that\\u2019s hearty, comforting, and perfect with sourdough.","datePublished":"2025-09-30T20:41:55+00:00","image":["https:\\/\\/avocadoskillet.com\\/wp-content\\/uploads\\/2025\\/09\\/IMG_2025-09-30-152928.jpeg","https:\\/\\/avocadoskillet.com\\/wp-content\\/uploads\\/2025\\/09\\/IMG_2025-09-30-152928-500x500.jpeg","https:\\/\\/avocadoskillet.com\\/wp-content\\/uploads\\/2025\\/09\\/IMG_2025-09-30-152928-500x375.jpeg","https:\\/\\/avocadoskillet.com\\/wp-content\\/uploads\\/2025\\/09\\/IMG_2025-09-30-152928-480x270.jpeg"],"recipeYield":["3"],"prepTime":"PT10M","cookTime":"PT18M","recipeIngredient":["1 tablespoon olive oil (use code avocadoskillet for 15% off Kosterina Olive oil)","1\\/2 yellow onion - finely chopped","6-10 cloves garlic - minced (adjust to your garlic preference)","1 medium carrot - finely chopped","2 stalks celery - finely chopped","2 cans white beans - drained","1 sprig fresh rosemary - finely chopped","1 teaspoon paprika","1 teaspoon dried thyme","1\\/2-1 teaspoon salt","1\\/2 teaspoon black pepper (or to taste)","1\\/2 cup parmesan cheese - grated","3-4 cups bone broth, vegetable broth, or chicken broth (adjust to your thickness preference, I like a thick stew so I used 3 cups)","2 cups finely chopped kale or green of choice","juice from 1\\/4 lemon (can sub 1 tablespoon apple cider vinegar)","toasted sourdough","red pepper flakes"],"recipeInstructions":[{"@type":"HowToStep","text":"Heat oil in a soup pot over medium heat. Add onions, carrots and celery cook for 5 minutes. Next, add in garlic, paprika, thyme, salt, pepper and rosemary. Cook for 5 more minutes.","name":"Heat oil in a soup pot over medium heat. Add onions, carrots and celery cook for 5 minutes. Next, add in garlic, paprika, thyme, salt, pepper and rosemary. Cook for 5 more minutes.","url":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#wprm-recipe-15191-step-0-0"},{"@type":"HowToStep","text":"Add all remaining ingredients to the pot except for the kale. Bring to a simmer and simmer for 15 minutes, until the veggies are tender.","name":"Add all remaining ingredients to the pot except for the kale. Bring to a simmer and simmer for 15 minutes, until the veggies are tender.","url":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#wprm-recipe-15191-step-0-1"},{"@type":"HowToStep","text":"Optional: Add 1-2 cups of soup to a blender and blend or partially blend with an immersion blender. This makes the soup creamy - but is not necessary.","name":"Optional: Add 1-2 cups of soup to a blender and blend or partially blend with an immersion blender. This makes the soup creamy - but is not necessary.","url":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#wprm-recipe-15191-step-0-2"},{"@type":"HowToStep","text":"Turn off heat and fold in kale. Divide out soup and serve. I topped mine with additional parmesan and red pepper flakes and served with toasted sourdough.","name":"Turn off heat and fold in kale. Divide out soup and serve. I topped mine with additional parmesan and red pepper flakes and served with toasted sourdough.","url":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#wprm-recipe-15191-step-0-3"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"5","ratingCount":"1","reviewCount":"1"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Soup is good and I LOVE garlic but it\\u2019s a bit overpowering. I only used 12 cloves for a double pot so would only use 3 or 5 for a double pot.","author":{"@type":"Person","name":"Carol Morrison"},"datePublished":"2025-10-29"}],"recipeCategory":["dinner"],"recipeCuisine":["American","high protein"],"keywords":"garlic parmesan white bean stew","nutrition":{"@type":"NutritionInformation","calories":"516 kcal","carbohydrateContent":"72 g","proteinContent":"36 g","fatContent":"11 g","saturatedFatContent":"4 g","cholesterolContent":"15 mg","sodiumContent":"808 mg","fiberContent":"16 g","sugarContent":"3 g","unsaturatedFatContent":"6 g","servingSize":"1 serving"},"@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#recipe","isPartOf":{"@id":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/#article"},"mainEntityOfPage":"https:\\/\\/avocadoskillet.com\\/garlic-parmesan-white-bean-stew-high-protein\\/"}]}',
                'image' => 'https://avocadoskillet.com/wp-content/uploads/2025/09/IMG_2025-09-30-152928.jpeg',
