        'content' => '{"@context":"https:\\/\\/schema.org","@graph":[{"@type":"Organization","@id":"https:\\/\\/whatsgabycooking.com\\/#organization","name":"Gaby Dalkin","sameAs":["https:\\/\\/www.facebook.com\\/WhatsGabyCooking\\/","https:\\/\\/twitter.com\\/whatsgabycookin"],"logo":{"@type":"ImageObject","@id":"https:\\/\\/whatsgabycooking.com\\/#logo","url":"https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2021\\/09\\/cropped-wgc-logo-small-g.png","contentUrl":"https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2021\\/09\\/cropped-wgc-logo-small-g.png","caption":"What\'s Gaby Cooking","inLanguage":"en-US"}},{"@type":"WebSite","@id":"https:\\/\\/whatsgabycooking.com\\/#website","url":"https:\\/\\/whatsgabycooking.com","name":"What\'s Gaby Cooking","publisher":{"@id":"https:\\/\\/whatsgabycooking.com\\/#organization"},"inLanguage":"en-US"},{"@type":"ImageObject","@id":"https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2017\\/10\\/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2.jpg","url":"https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2017\\/10\\/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2.jpg","width":"870","height":"580","inLanguage":"en-US"},{"@type":"WebPage","@id":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#webpage","url":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/","name":"Carnitas Burrito Bowl - What&#039;s Gaby Cooking","datePublished":"2021-09-16T13:00:00-07:00","dateModified":"2026-03-06T14:29:03-08:00","isPartOf":{"@id":"https:\\/\\/whatsgabycooking.com\\/#website"},"primaryImageOfPage":{"@id":"https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2017\\/10\\/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2.jpg"},"inLanguage":"en-US"},{"@type":"Person","@id":"https:\\/\\/whatsgabycooking.com\\/author\\/gaby\\/","name":"Gaby Dalkin","url":"https:\\/\\/whatsgabycooking.com\\/author\\/gaby\\/","image":{"@type":"ImageObject","@id":"https:\\/\\/secure.gravatar.com\\/avatar\\/035a2c21565b3e9dc0062bcd05cbabb4d1f5f855f74dfa7871a1fa96a8a94550?s=96&amp;d=mm&amp;r=g","url":"https:\\/\\/secure.gravatar.com\\/avatar\\/035a2c21565b3e9dc0062bcd05cbabb4d1f5f855f74dfa7871a1fa96a8a94550?s=96&amp;d=mm&amp;r=g","caption":"Gaby Dalkin","inLanguage":"en-US"},"sameAs":["https:\\/\\/www.whatsgabycooking.com\\/about-2","https:\\/\\/twitter.com\\/whatsgabycookin"],"worksFor":{"@id":"https:\\/\\/whatsgabycooking.com\\/#organization"}},{"@type":"BlogPosting","headline":"Carnitas Burrito Bowl - What&#039;s Gaby Cooking","keywords":"Carnitas Burrito Bowl","datePublished":"2021-09-16T13:00:00-07:00","dateModified":"2026-03-06T14:29:03-08:00","articleSection":"Weeknight Dinner, Healthy Dinner, Avocado Central, Pork, Bowls, Dinner, Game Day, Healthy, Lunch, Food + Drink, Meat","author":{"@id":"https:\\/\\/whatsgabycooking.com\\/author\\/gaby\\/","name":"Gaby Dalkin"},"publisher":{"@id":"https:\\/\\/whatsgabycooking.com\\/#organization"},"description":"Grab the recipe for a Carnitas Burrito Bowl loaded with the most succulent carnitas, tons of guacamole, pico, corn salsa and cilantro rice!!","name":"Carnitas Burrito Bowl - What&#039;s Gaby Cooking","@id":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#richSnippet","isPartOf":{"@id":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#webpage"},"image":{"@id":"https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2017\\/10\\/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2.jpg"},"inLanguage":"en-US","mainEntityOfPage":{"@id":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#webpage"}},{"@type":"Recipe","name":"Carnitas Burrito Bowl","author":{"@type":"Person","name":"Gaby Dalkin"},"description":"My all time fav Carnitas Burrito Bowl! All of the toppings, yummy rice, and the best carnitas you&#039;ll ever make!","datePublished":"2021-09-16T13:00:00+00:00","image":["https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2017\\/10\\/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2.jpg","https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2017\\/10\\/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2-500x500.jpg","https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2017\\/10\\/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2-500x375.jpg","https:\\/\\/whatsgabycooking.com\\/wp-content\\/uploads\\/2017\\/10\\/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2-480x270.jpg"],"recipeYield":["6","6 people"],"prepTime":"PT15M","cookTime":"PT225M","totalTime":"PT240M","recipeIngredient":["3 pounds boneless pork shoulder (cut into 2 inch cubes)","1\\/2 cup fresh orange juice","1\\/4 cup fresh lime juice","10 oz chipotle salsa","1 teaspoon kosher salt (plus more to taste)","1 teaspoon vegetable oil","1 cup white basmati rice","2 cups water","1 lime","2 tablespoons freshly chopped cilantro","kosher salt to taste","1 cup black beans (warmed)","1 cup frozen charred corn (warmed)","Guacamole","Pico de gallo","Shredded Monterey jack cheese"],"recipeInstructions":[{"@type":"HowToSection","name":"For the Carnitas","itemListElement":[{"@type":"HowToStep","text":"Place the pork in a large dutch oven with the orange juice, lime juice, salsa and salt. Add enough water to barely cover the meat. Bring to a boil. Once boiling, reduce heat to medium low and simmer with the lid on for 2 hours, at which point the pork should be falling apart to the touch. Turn the heat up to medium high, and continue to cook the pork for 45 minutes, uncovered, stirring every once in a while, until all the liquid has evaporated and the pork fat has been rendered. Parts of the pork should be caramelized and golden brown. Remove the dutch oven from the stove and season with salt as needed","name":"Place the pork in a large dutch oven with the orange juice, lime juice, salsa and salt. Add enough water to barely cover the meat. Bring to a boil. Once boiling, reduce heat to medium low and simmer with the lid on for 2 hours, at which point the pork should be falling apart to the touch. Turn the heat up to medium high, and continue to cook the pork for 45 minutes, uncovered, stirring every once in a while, until all the liquid has evaporated and the pork fat has been rendered. Parts of the pork should be caramelized and golden brown. Remove the dutch oven from the stove and season with salt as needed","url":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#wprm-recipe-32311-step-0-0"}]},{"@type":"HowToSection","name":"For the Rice","itemListElement":[{"@type":"HowToStep","text":"In a heavy saucepan, heat the oil over medium heat. Once hot, add the white rice and lime juice and saut\\u00e9 for 60 seconds to toast the rice. Add the water and bring the rice to a boil. Cover and reduce the heat to low and cook until the rice is tender and all the water is absorbed. Add in the cilantro and fluff rice with a fork. Taste and adjust salt and lime juice as needed.","name":"In a heavy saucepan, heat the oil over medium heat. Once hot, add the white rice and lime juice and saut\\u00e9 for 60 seconds to toast the rice. Add the water and bring the rice to a boil. Cover and reduce the heat to low and cook until the rice is tender and all the water is absorbed. Add in the cilantro and fluff rice with a fork. Taste and adjust salt and lime juice as needed.","url":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#wprm-recipe-32311-step-1-0"}]},{"@type":"HowToSection","name":"To assemble","itemListElement":[{"@type":"HowToStep","text":"Arrange equal parts of the white rice and carnitas in 4 bowls. Top with equal parts of the beans, corn, guacamole, pico and cheese. Season with salt and pepper as needed and serve immediately.","name":"Arrange equal parts of the white rice and carnitas in 4 bowls. Top with equal parts of the beans, corn, guacamole, pico and cheese. Season with salt and pepper as needed and serve immediately.","url":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#wprm-recipe-32311-step-2-0"}]}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"4.84","ratingCount":"12","reviewCount":"7"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This is so incredibly delicious!!!! Already looking forward to making it again. The whole family devoured it!","author":{"@type":"Person","name":"Kerrin Tierney"},"datePublished":"2022-07-31"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Delicious! And makes for excellent leftovers","author":{"@type":"Person","name":"Stephanie"},"datePublished":"2022-04-12"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Holy\\u2026. Why have I waited so long to make this! I\\u2019ve had it pinned to my board for so long. It\\u2019s amazing!!! Pork is so tender and has amazing flavor and the rice too!!","author":{"@type":"Person","name":"Yvonny J"},"datePublished":"2021-12-17"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"this is seriously delish, easy to make, and impressive to serve! Have made 3 times in the last 2 weeks for various gatherings and always a hit! Thank you Gaby!","author":{"@type":"Person","name":"Deb"},"datePublished":"2021-10-23"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This bowl was fabulous! Loved it and want to make it for girlfriends Friday night.","author":{"@type":"Person","name":"Susan"},"datePublished":"2021-10-18"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"The meat came out great! I\\u2019m not even the biggest pork fan but needed to change it up and this was delicious! It shredded like butter :) It is great in a bowl and would make awesome tacos too. My husband loved it and said definite make again! I followed the recipe exactly using TJs chipotle salsa and my 5.5 quart Le Creuset. Love this one, thanks Gaby!","author":{"@type":"Person","name":"Jessie"},"datePublished":"2021-10-03"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I do love all things in a bowl, and this is no exception. Beautiful!","author":{"@type":"Person","name":"Monika"},"datePublished":"2021-09-16"}],"recipeCategory":["Main Course"],"recipeCuisine":["Tex Mex","Southwestern"],"keywords":"pork carnitas, carnitas burrito bowl","nutrition":{"@type":"NutritionInformation","calories":"501 kcal","carbohydrateContent":"45 g","proteinContent":"58 g","fatContent":"9 g","saturatedFatContent":"3 g","transFatContent":"0.04 g","cholesterolContent":"136 mg","sodiumContent":"828 mg","fiberContent":"5 g","sugarContent":"4 g","unsaturatedFatContent":"6 g","servingSize":"1 serving"},"@id":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#recipe","mainEntityOfPage":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#webpage","isPartOf":{"@id":"https:\\/\\/whatsgabycooking.com\\/carnitas-burrito-bowl\\/#richSnippet"}}]}',
            'image' => 'https://whatsgabycooking.com/wp-content/uploads/2017/10/PORK-BOARD-Carnitas-Burrito-Bowl-3-copy-2.jpg',
        'ingredients' => '["3 pounds boneless pork shoulder (cut into 2 inch cubes)","1\\/2 cup fresh orange juice","1\\/4 cup fresh lime juice","10 oz chipotle salsa","1 teaspoon kosher salt (plus more to taste)","1 teaspoon vegetable oil","1 cup white basmati rice","2 cups water","1 lime","2 tablespoons freshly chopped cilantro","kosher salt to taste","1 cup black beans (warmed)","1 cup frozen charred corn (warmed)","Guacamole","Pico de gallo","Shredded Monterey jack cheese"]',
            'directions' => '{"For the Carnitas":["Place the pork in a large dutch oven with the orange juice, lime juice, salsa and salt. Add enough water to barely cover the meat. Bring to a boil. Once boiling, reduce heat to medium low and simmer with the lid on for 2 hours, at which point the pork should be falling apart to the touch. Turn the heat up to medium high, and continue to cook the pork for 45 minutes, uncovered, stirring every once in a while, until all the liquid has evaporated and the pork fat has been rendered. Parts of the pork should be caramelized and golden brown. Remove the dutch oven from the stove and season with salt as needed"],"For the Rice":["In a heavy saucepan, heat the oil over medium heat. Once hot, add the white rice and lime juice and saut\\u00e9 for 60 seconds to toast the rice. Add the water and bring the rice to a boil. Cover and reduce the heat to low and cook until the rice is tender and all the water is absorbed. Add in the cilantro and fluff rice with a fork. Taste and adjust salt and lime juice as needed."],"To assemble":["Arrange equal parts of the white rice and carnitas in 4 bowls. Top with equal parts of the beans, corn, guacamole, pico and cheese. Season with salt and pepper as needed and serve immediately."]}',
            'nutrition' => '[{"@type":"NutritionInformation","calories":"501 kcal","carbohydrateContent":"45 g","proteinContent":"58 g","fatContent":"9 g","saturatedFatContent":"3 g","transFatContent":"0.04 g","cholesterolContent":"136 mg","sodiumContent":"828 mg","fiberContent":"5 g","sugarContent":"4 g","unsaturatedFatContent":"6 g","servingSize":"1 serving"}]',
