,"breadcrumb":{"@id":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#primaryimage","url":"https:\\/\\/damndelicious.net\\/wp-content\\/uploads\\/2019\\/07\\/Korean-Beef-Power-BowlsIMG_0172.jpg","contentUrl":"https:\\/\\/damndelicious.net\\/wp-content\\/uploads\\/2019\\/07\\/Korean-Beef-Power-BowlsIMG_0172.jpg","width":760,"height":1140,"caption":"Korean Beef Power Bowls"},{"@type":"BreadcrumbList","@id":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/damndelicious.net\\/"},{"@type":"ListItem","position":2,"name":"Korean Beef Power Bowls"}]},{"@type":"WebSite","@id":"https:\\/\\/damndelicious.net\\/#website","url":"https:\\/\\/damndelicious.net\\/","name":"Damn Delicious Food Recipes","description":"Simple ingredients. Elegant dishes.","publisher":{"@id":"https:\\/\\/damndelicious.net\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/damndelicious.net\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/damndelicious.net\\/#organization","name":"Damn Delicious","url":"https:\\/\\/damndelicious.net\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/damndelicious.net\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/damndelicious.net\\/wp-content\\/uploads\\/2022\\/08\\/DDLogo.png","contentUrl":"https:\\/\\/damndelicious.net\\/wp-content\\/uploads\\/2022\\/08\\/DDLogo.png","width":640,"height":853,"caption":"Damn Delicious"},"image":{"@id":"https:\\/\\/damndelicious.net\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/www.facebook.com\\/damndeliciousblog","https:\\/\\/www.instagram.com\\/damn_delicious\\/"]},{"@type":"Person","@id":"https:\\/\\/damndelicious.net\\/#\\/schema\\/person\\/0580fef3f191728c69dace28d2fac9ff","name":"Chungah @ Damn Delicious","description":"Chungah is the recipe developer and photographer of Damn Delicious, a blog that was founded in 2011. She thought she would become an epidemiologist, obtaining a sociology degree at UCLA and a Masters in Public Health at USC. But what began as a grad school hobby blog is now her full-time job. Originally from Queens and living most of her life in Los Angeles, she now resides in Chicago with her crazy corgi duo, Butters and Cartman. She loves donuts and binging on Grey\'s Anatomy reruns, and hopes to one day start her very own corgi rescue.","sameAs":["https:\\/\\/damndelicious.net","https:\\/\\/www.facebook.com\\/damndeliciousblog","https:\\/\\/www.instagram.com\\/damn_delicious\\/","https:\\/\\/x.com\\/@damn_delicious"]},{"@type":"Recipe","name":"Korean Beef Power Bowls","author":{"@id":"https:\\/\\/damndelicious.net\\/#\\/schema\\/person\\/0580fef3f191728c69dace28d2fac9ff"},"description":"With the easiest Korean beef, shredded cabbage, caramelized kimchi, avocado slices, and the best ever Sriracha mayo. SO SO BOMB.","datePublished":"2019-07-13T21:00:25+00:00","image":["https:\\/\\/damndelicious.net\\/wp-content\\/uploads\\/2019\\/07\\/Korean-Beef-Power-BowlsIMG_0172.jpg"],"recipeYield":["4","4 servings"],"prepTime":"PT30M","cookTime":"PT15M","totalTime":"PT45M","recipeIngredient":["1\\/4 cup brown sugar (packed)","1\\/4 cup reduced sodium soy sauce","1 tablespoon freshly grated ginger","2 teaspoons sesame oil","1\\/2 teaspoon Sriracha (or more to taste)","1 tablespoon olive oil","2 cloves garlic (minced)","1 pound ground beef","2 teaspoons sesame oil","1 cup chopped kimchi","1 teaspoon sugar","1\\/4 cup mayonnaise","1 tablespoon Sriracha","2 teaspoons freshly squeezed lime juice","1 cup farro","1 1\\/2 cups shredded purple cabbage","1 avocado (halved, peeled, seeded and thinly sliced)","2 green onions (thinly sliced)","1\\/4 teaspoon sesame seeds"],"recipeInstructions":[{"@type":"HowToStep","text":"FOR THE KOREAN BEEF: In a small bowl, whisk together brown sugar, soy sauce, ginger, sesame oil and Sriracha.","name":"FOR THE KOREAN BEEF: In a small bowl, whisk together brown sugar, soy sauce, ginger, sesame oil and Sriracha.","url":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#wprm-recipe-34893-step-0-0"},{"@type":"HowToStep","text":"Heat olive\\u00a0oil in a large skillet over medium high heat. Add garlic and cook, stirring constantly, until fragrant, about 1 minute. Add ground beef and cook until browned, about 3-5 minutes, making sure to crumble the beef as it cooks; drain excess fat.","name":"Heat olive\\u00a0oil in a large skillet over medium high heat. Add garlic and cook, stirring constantly, until fragrant, about 1 minute. Add ground beef and cook until browned, about 3-5 minutes, making sure to crumble the beef as it cooks; drain excess fat.","url":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#wprm-recipe-34893-step-0-1"},{"@type":"HowToStep","text":"Stir in soy sauce mixture until well combined, allowing to simmer until heated through, about 2 minutes; set aside.","name":"Stir in soy sauce mixture until well combined, allowing to simmer until heated through, about 2 minutes; set aside.","url":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#wprm-recipe-34893-step-0-2"},{"@type":"HowToStep","text":"FOR THE KIMCHI: Heat sesame oil in small skillet over medium high heat. Add kimchi and sugar, and cook, stirring constantly, until caramelized and heated through, about 3-5 minutes; set aside.","name":"FOR THE KIMCHI: Heat sesame oil in small skillet over medium high heat. Add kimchi and sugar, and cook, stirring constantly, until caramelized and heated through, about 3-5 minutes; set aside.","url":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#wprm-recipe-34893-step-0-3"},{"@type":"HowToStep","text":"FOR THE SRIRACHA MAYONNAISE: In a small bowl, whisk together mayonnaise, Sriracha and lime juice; set aside.","name":"FOR THE SRIRACHA MAYONNAISE: In a small bowl, whisk together mayonnaise, Sriracha and lime juice; set aside.","url":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#wprm-recipe-34893-step-0-4"},{"@type":"HowToStep","text":"FOR THE BOWLS: Cook farro according to package instructions.","name":"FOR THE BOWLS: Cook farro according to package instructions.","url":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#wprm-recipe-34893-step-0-5"},{"@type":"HowToStep","text":"Divide farro into bowls. Top with ground beef mixture, kimchi, cabbage and avocado, drizzled with Sriracha mayonnaise and garnished with green onions and sesame seeds, if desired.","name":"Divide farro into bowls. Top with ground beef mixture, kimchi, cabbage and avocado, drizzled with Sriracha mayonnaise and garnished with green onions and sesame seeds, if desired.","url":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#wprm-recipe-34893-step-0-6"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"5","ratingCount":"49","reviewCount":"18"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"So great! Kids love it and we make a big batch for them to bring to school!","author":{"@type":"Person","name":"MB"},"datePublished":"2025-09-23"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Made this 3 times already for lunch meal prep and it\\u2019s so dang good! I like to add some chopped bok choy and shredded carrot to the meat at the last few minutes to soften them up.\\u00a0","author":{"@type":"Person","name":"Simone"},"datePublished":"2025-05-04"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"So great - my teen boys ate it and discovered they like kimchi! Who knew?!\\r\\nSo damn delicious.\\u00a0","author":{"@type":"Person","name":"Kellie Openshaw"},"datePublished":"2025-01-14"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This is incredibly good! \\u00a0Made it for dinner last night, leftovers for lunch today, already thinking about making it again!","author":{"@type":"Person","name":"Gail Kane"},"datePublished":"2025-01-07"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"One of our ABSOLUTE FAVORITES!!! Oh my goodness! We have bulgogi often so we will use it in this recipe instead of the ground beef it\'s soooo good to use up the leftovers! It\'s also amazing with the ground beef. We\'ve even used this recipe to make the most delicious Korean tacos!!!! So good and my husband requests it often!!!!!!!","author":{"@type":"Person","name":"Hannah"},"datePublished":"2024-06-30"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"OMG, YUM!!! This recipe is sooooo GOOD!!! I was a little intimidated to try this recipe because I never had kimchi or farro before. Now I\'m hooked on them. I was a little short on time so I just used cold kimchi, but I\'m going to caramelize it next time. I\'m never disappointed with Chungah\'s recipes, and this one has become a new favorite.","author":{"@type":"Person","name":"Courtney A."},"datePublished":"2024-05-07"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Second time making this. I doubled the recipe for my family of 6 and there are zero leftovers! It\\u2019s really good!","author":{"@type":"Person","name":"Kristin Conway"},"datePublished":"2024-04-11"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Pretty good, I used rice instead, I think I would leave out the red cabbage and use something else next time personally\\u00a0","author":{"@type":"Person","name":"Holly"},"datePublished":"2024-03-17"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Do you use store bought kimchi that\\u2019s already prepared or do you use plain cabbage?","author":{"@type":"Person","name":"Stella"},"datePublished":"2024-01-30"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Really great. Even teenagers liked it. We made some with tofu for our vegetarian friend.","author":{"@type":"Person","name":"Kathy"},"datePublished":"2023-11-22"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I make this bowl all the time! It\'s so good! I used glass noodles and it\'s delicious!","author":{"@type":"Person","name":"Trisha"},"datePublished":"2023-11-09"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Good but way too sweet. I will definitely cut back on the sugar if I make it again.","author":{"@type":"Person","name":"Juliann Zipkin"},"datePublished":"2023-07-27"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"This recipe is amazing! I made it with brown rice and it worked really well.\\u00a0","author":{"@type":"Person","name":"tyler funk"},"datePublished":"2023-04-09"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I love this recipe ( like I love most of Chungah\'s recipes) and so does my whole family. I did make an adjustment to the brown sugar as it is way too sweet for our liking and I felt you lost all the flavor of the soy sauce. I now use half of what is called for in this recipe. It\'s a family winner for sure. It also makes a great camping meal to make ahead, freeze and reheat.","author":{"@type":"Person","name":"Sasheen"},"datePublished":"2022-09-06"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Oh man this was good! I made some modifications to try to lighten it up a little and fit it to my macros. Unfortunately I just couldn\'t make the avocado fit those goals. It was great without it too but I kept thinking what a great addition avocado would be. I also made the sauce with greek yogurt instead of mayo and it was still bomb. Very tasty and satisfying. I wasn\'t sure if this should be warm or cold though...I cooked the farro in a crockpot and then mixed in the meat and kimchi after they were cooked too to keep everything warm. Will definitely make again and will enjoy the leftovers.","author":{"@type":"Person","name":"Caitlin Walbrun"},"datePublished":"2022-06-15"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"LOVE!!! The farro was such a nice touch instead of rice that I would typically use for any bowl meals. This was delish!\\u00a0","author":{"@type":"Person","name":"Leelee"},"datePublished":"2022-04-13"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I can\'t believe I have never reviewed this recipe. I\'ve been making this for 3 years and my boyfriend requests it near weekly. This meal is such a staple!! We sometimes add or take away some things but the recipe always stays in rotation.","author":{"@type":"Person","name":"Nina M"},"datePublished":"2022-03-06"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Amazing!!!!! Everything is spot on!! I used ground turkey breast. I also added fresh sliced cucumber.","author":{"@type":"Person","name":"Julie Adams"},"datePublished":"2022-02-10"}],"@id":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#recipe","isPartOf":{"@id":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/#article"},"mainEntityOfPage":"https:\\/\\/damndelicious.net\\/2019\\/07\\/13\\/korean-beef-power-bowls\\/"}]}',
