\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#primaryimage","url":"https:\\/\\/eatthegains.com\\/wp-content\\/uploads\\/2016\\/10\\/Veggie-Power-Bowl-5.jpg","contentUrl":"https:\\/\\/eatthegains.com\\/wp-content\\/uploads\\/2016\\/10\\/Veggie-Power-Bowl-5.jpg","width":700,"height":1050,"caption":"Veggie power bowl with kale, butternut squash, parsnips, beets, avocado, walnuts, and dried cranberries. It is topped with tahini dressing. Next to is is another bowl, half an avocado, bowl of walnuts, and a kitchen towel."},{"@type":"BreadcrumbList","@id":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/eatthegains.com\\/"},{"@type":"ListItem","position":2,"name":"Recipes","item":"https:\\/\\/eatthegains.com\\/recipe-index\\/"},{"@type":"ListItem","position":3,"name":"Dinners","item":"https:\\/\\/eatthegains.com\\/product-category\\/main-course\\/"},{"@type":"ListItem","position":4,"name":"Veggie Power Bowl"}]},{"@type":"WebSite","@id":"https:\\/\\/eatthegains.com\\/#website","url":"https:\\/\\/eatthegains.com\\/","name":"Eat the Gains","description":"Easy &amp; Healthy Macro Friendly Recipes","publisher":{"@id":"https:\\/\\/eatthegains.com\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/eatthegains.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/eatthegains.com\\/#organization","name":"Eat the Gains","url":"https:\\/\\/eatthegains.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/eatthegains.com\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/eatthegains.com\\/wp-content\\/uploads\\/2022\\/02\\/primary-logo.svg","contentUrl":"https:\\/\\/eatthegains.com\\/wp-content\\/uploads\\/2022\\/02\\/primary-logo.svg","width":278,"height":171,"caption":"Eat the Gains"},"image":{"@id":"https:\\/\\/eatthegains.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/x.com\\/eatthegains","https:\\/\\/www.instagram.com\\/eatthegains\\/","https:\\/\\/www.pinterest.com\\/eatthegains\\/"]},{"@type":"Person","@id":"https:\\/\\/eatthegains.com\\/#\\/schema\\/person\\/a8c65475acae93497d3103c33fab7c84","name":"Kelly Nardo","description":"Hi, I\'m Kelly, a nutrition coach and lover of food and fitness. I like to create healthy recipes that help fuel my workouts and enrich my health.","sameAs":["https:\\/\\/eatthegains.com\\/about"]},{"@type":"Recipe","name":"Winter Veggie Power Bowl","author":{"@id":"https:\\/\\/eatthegains.com\\/#\\/schema\\/person\\/a8c65475acae93497d3103c33fab7c84"},"description":"Easy veggie power bowl loaded with butternut\\u00a0squash,\\u00a0beets, parsnips, kale,\\u00a0avocado, walnuts, and dried cranberries and then tossed with a\\u00a0flavorful tahini dressing. Loaded with healthy fats, carbs, and fiber this vegan power bowl is gluten free, vegan, paleo, and customizable to your liking!","datePublished":"2020-03-04T10:00:16+00:00","image":["https:\\/\\/eatthegains.com\\/wp-content\\/uploads\\/2016\\/10\\/Veggie-Power-Bowl-5.jpg","https:\\/\\/eatthegains.com\\/wp-content\\/uploads\\/2016\\/10\\/Veggie-Power-Bowl-5-500x500.jpg","https:\\/\\/eatthegains.com\\/wp-content\\/uploads\\/2016\\/10\\/Veggie-Power-Bowl-5-500x375.jpg","https:\\/\\/eatthegains.com\\/wp-content\\/uploads\\/2016\\/10\\/Veggie-Power-Bowl-5-480x270.jpg"],"recipeYield":["3"],"prepTime":"PT10M","cookTime":"PT40M","totalTime":"PT50M","recipeIngredient":["2 tablespoons avocado oil ((divided))","3 cups cubed butternut squash (415 grams)","3 medium parsnips, peeled and cubed (2 heaping cups\\/270 grams)","1 teaspoon garlic powder","1 large beet, peeled and cubed (2 cups\\/275 grams)","1\\/2 teaspoon cumin","6 cups packed kale, roughly chopped (180 grams)","1\\/3 cup walnuts ((roughly chopped))","1\\/3 cup dried cranberries","1 small small avocado, sliced (100 grams)","salt and pepper, to taste","additional add ons: quinoa, chickpeas, roasted chicken, goat cheese...","2 tablespoons tahini","2 tablespoons coconut aminos","1 tablespoon lemon juice","1 teaspoon apple cider vinegar","1\\/4 teaspoon ground ginger","1\\/4 teaspoon garlic powder","1\\/4-1\\/2 teaspoon red pepper flakes","salt and pepper, to taste"],"recipeInstructions":[{"@type":"HowToStep","text":"Preheat oven to 375 degrees Fahrenheit. Line 1-2 large baking sheets with parchment paper.","name":"Preheat oven to 375 degrees Fahrenheit. Line 1-2 large baking sheets with parchment paper.","url":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#wprm-recipe-7431-step-0-0"},{"@type":"HowToStep","text":"Roast the veggies. In a medium bowl mix together butternut squash, parnships, 1 tablespoon avocado oil, garlic powder, and salt and pepper. Place on baking sheet making sure veggies are spread out evenly. In the same bowl add beets, 1\\/2 tablespoon avocado oil, cumin, and salt and pepper and mix to combine. Place on same baking sheet or another one if more room is needed. Roast for 35-40 minutes until soft and fork tender","name":"Roast the veggies. In a medium bowl mix together butternut squash, parnships, 1 tablespoon avocado oil, garlic powder, and salt and pepper. Place on baking sheet making sure veggies are spread out evenly. In the same bowl add beets, 1\\/2 tablespoon avocado oil, cumin, and salt and pepper and mix to combine. Place on same baking sheet or another one if more room is needed. Roast for 35-40 minutes until soft and fork tender","url":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#wprm-recipe-7431-step-0-1"},{"@type":"HowToStep","text":"While the vegetables roast, place kale in a bowl and massage with 1\\/2 tablepsoon avocado oil and a pinch of salt and pepper until leaves become tender and soft.","name":"While the vegetables roast, place kale in a bowl and massage with 1\\/2 tablepsoon avocado oil and a pinch of salt and pepper until leaves become tender and soft.","url":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#wprm-recipe-7431-step-0-2"},{"@type":"HowToStep","text":"Make the dressing. Mix all ingredients into a bowl and whisk to combine. Add a little water if you want a thinner consistency or more tahini if you want it thicker.","name":"Make the dressing. Mix all ingredients into a bowl and whisk to combine. Add a little water if you want a thinner consistency or more tahini if you want it thicker.","url":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#wprm-recipe-7431-step-0-3"},{"@type":"HowToStep","text":"When veggies are done assemble the bowls. Divide kale, roasted veggies, walnuts, cranberries, and avocado between 3 bowls. Top with dressing and enjoy!","name":"When veggies are done assemble the bowls. Divide kale, roasted veggies, walnuts, cranberries, and avocado between 3 bowls. Top with dressing and enjoy!","url":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#wprm-recipe-7431-step-0-4"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"5","ratingCount":"3","reviewCount":"1"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I served this tonight and my husband loved it.","author":{"@type":"Person","name":"Kim"},"datePublished":"2018-01-01"}],"recipeCategory":["Main Course","Salad","Side Dish"],"recipeCuisine":["American"],"keywords":"Vegan Power Bowl, Veggie Power Bowl, Winter Vegetarian Recipes","nutrition":{"@type":"NutritionInformation","servingSize":"1 bowl (ingredients + dressing divided up evenly)","carbohydrateContent":"63 g","proteinContent":"10 g","fatContent":"28.5 g","saturatedFatContent":"3.5 g","fiberContent":"18.5 g","sugarContent":"28.2 g","calories":"521 kcal","unsaturatedFatContent":"18.6 g"},"@id":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#recipe","isPartOf":{"@id":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/#article"},"mainEntityOfPage":"https:\\/\\/eatthegains.com\\/roasted-winter-veggie-power-bowl\\/"}]}',
            'image' => 'https://eatthegains.com/wp-content/uploads/2016/10/Veggie-Power-Bowl-5.jpg',
        'ingredients' => '["2 tablespoons avocado oil ((divided))","3 cups cubed butternut squash (415 grams)","3 medium parsnips, peeled and cubed (2 heaping cups\\/270 grams)","1 teaspoon garlic powder","1 large beet, peeled and cubed (2 cups\\/275 grams)","1\\/2 teaspoon cumin","6 cups packed kale, roughly chopped (180 grams)","1\\/3 cup walnuts ((roughly chopped))","1\\/3 cup dried cranberries","1 small small avocado, sliced (100 grams)","salt and pepper, to taste","additional add ons: quinoa, chickpeas, roasted chicken, goat cheese...","2 tablespoons tahini","2 tablespoons coconut aminos","1 tablespoon lemon juice","1 teaspoon apple cider vinegar","1\\/4 teaspoon ground ginger","1\\/4 teaspoon garlic powder","1\\/4-1\\/2 teaspoon red pepper flakes","salt and pepper, to taste"]',
            'directions' => '["Preheat oven to 375 degrees Fahrenheit. Line 1-2 large baking sheets with parchment paper.","Roast the veggies. In a medium bowl mix together butternut squash, parnships, 1 tablespoon avocado oil, garlic powder, and salt and pepper. Place on baking sheet making sure veggies are spread out evenly. In the same bowl add beets, 1\\/2 tablespoon avocado oil, cumin, and salt and pepper and mix to combine. Place on same baking sheet or another one if more room is needed. Roast for 35-40 minutes until soft and fork tender","While the vegetables roast, place kale in a bowl and massage with 1\\/2 tablepsoon avocado oil and a pinch of salt and pepper until leaves become tender and soft.","Make the dressing. Mix all ingredients into a bowl and whisk to combine. Add a little water if you want a thinner consistency or more tahini if you want it thicker.","When veggies are done assemble the bowls. Divide kale, roasted veggies, walnuts, cranberries, and avocado between 3 bowls. Top with dressing and enjoy!"]',
