            'description' => 'This lasagna soup has become a family and reader favorite! All the flavors and goodness of lasagna in comforting soup form! A must try recipe!',
        'content' => '{"@context":"https:\\/\\/schema.org","@graph":[{"@type":"Article","@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#article","isPartOf":{"@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/"},"author":{"name":"Jaclyn","@id":"https:\\/\\/www.cookingclassy.com\\/#\\/schema\\/person\\/7b33b4e339a89e5b4d034e63fb316884"},"headline":"Lasagna Soup","datePublished":"2018-12-31T23:14:56+00:00","dateModified":"2021-04-19T19:45:04+00:00","wordCount":1175,"commentCount":454,"image":{"@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/www.cookingclassy.com\\/wp-content\\/uploads\\/2018\\/12\\/lasagna-soup-12.jpg","keywords":["basil","chicken broth","fennel seeds","garlic","ground beef","mozzarella","olive oil","onions","oregano","parmesan","pasta","ricotta","rosemary","sugar","thyme","tomato paste","tomatoes"],"articleSection":["Beef and Pork","Main Dish","Videos"],"inLanguage":"en-US","potentialAction":[{"@type":"CommentAction","name":"Comment","target":["https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#respond"]}]},{"@type":"WebPage","@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/","name":"Lasagna Soup (Perfected Recipe!) - Cooking Classy","isPartOf":{"@id":"https:\\/\\/www.cookingclassy.com\\/#website"},"primaryImageOfPage":{"@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#primaryimage"},"image":{"@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#primaryimage"},"thumbnailUrl":"https:\\/\\/www.cookingclassy.com\\/wp-content\\/uploads\\/2018\\/12\\/lasagna-soup-12.jpg","datePublished":"2018-12-31T23:14:56+00:00","dateModified":"2021-04-19T19:45:04+00:00","author":{"@id":"https:\\/\\/www.cookingclassy.com\\/#\\/schema\\/person\\/7b33b4e339a89e5b4d034e63fb316884"},"description":"This lasagna soup has become a family and reader favorite! All the flavors and goodness of lasagna in comforting soup form! A must try recipe!","breadcrumb":{"@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#breadcrumb"},"inLanguage":"en-US","potentialAction":[{"@type":"ReadAction","target":["https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/"]}]},{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#primaryimage","url":"https:\\/\\/www.cookingclassy.com\\/wp-content\\/uploads\\/2018\\/12\\/lasagna-soup-12.jpg","contentUrl":"https:\\/\\/www.cookingclassy.com\\/wp-content\\/uploads\\/2018\\/12\\/lasagna-soup-12.jpg","width":1200,"height":1800,"caption":"Lasagna Soup"},{"@type":"BreadcrumbList","@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/www.cookingclassy.com\\/"},{"@type":"ListItem","position":2,"name":"Recipes","item":"https:\\/\\/www.cookingclassy.com\\/recipes\\/"},{"@type":"ListItem","position":3,"name":"Beef and Pork","item":"https:\\/\\/www.cookingclassy.com\\/recipes\\/meat\\/"},{"@type":"ListItem","position":4,"name":"Lasagna Soup"}]},{"@type":"WebSite","@id":"https:\\/\\/www.cookingclassy.com\\/#website","url":"https:\\/\\/www.cookingclassy.com\\/","name":"Cooking Classy","description":"with a sprinkle of fancy","potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/www.cookingclassy.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Person","@id":"https:\\/\\/www.cookingclassy.com\\/#\\/schema\\/person\\/7b33b4e339a89e5b4d034e63fb316884","name":"Jaclyn","sameAs":["https:\\/\\/www.cookingclassy.com"],"url":"https:\\/\\/www.cookingclassy.com\\/author\\/jaclyn\\/"},{"@type":"Recipe","name":"Lasagna Soup","author":{"@id":"https:\\/\\/www.cookingclassy.com\\/#\\/schema\\/person\\/7b33b4e339a89e5b4d034e63fb316884"},"description":"This Lasagna Soup is one of my all time favorites! You get all the flavors of a delicious hearty lasagna in a comforting soup form! It\'s loaded with beef, tomatoes and Italian herbs and the melty cheese just takes it over the top.","datePublished":"2018-12-31T16:14:56+00:00","image":["https:\\/\\/www.cookingclassy.com\\/wp-content\\/uploads\\/2018\\/12\\/lasagna-soup-12.jpg","https:\\/\\/www.cookingclassy.com\\/wp-content\\/uploads\\/2018\\/12\\/lasagna-soup-12-500x500.jpg","https:\\/\\/www.cookingclassy.com\\/wp-content\\/uploads\\/2018\\/12\\/lasagna-soup-12-500x375.jpg","https:\\/\\/www.cookingclassy.com\\/wp-content\\/uploads\\/2018\\/12\\/lasagna-soup-12-480x270.jpg"],"video":{"name":"Lasagna Soup","description":"This Lasagna Soup is one of my all time favorites! You get all the flavors of a delicious hearty lasagna in a comforting soup form! It\'s loaded with beef, tomatoes and Italian herbs and the melty cheese just takes it over the top.","thumbnailUrl":"https:\\/\\/content.jwplatform.com\\/thumbs\\/0H0UWjFf-720.jpg","contentUrl":"https:\\/\\/content.jwplatform.com\\/videos\\/0H0UWjFf.mp4","uploadDate":"2021-04-19T19:38:10.000Z","@type":"VideoObject"},"recipeYield":["6"],"prepTime":"PT15M","cookTime":"PT35M","totalTime":"PT50M","recipeIngredient":["2 Tbsp olive oil, (divided)","1 lb lean ground beef","1 large yellow onion, (diced (1 3\\/4 cups))","5 garlic cloves, (to taste, minced*)","4 1\\/2 cups low-sodium chicken broth, (then more to thin as desired)","1 (14.5 oz) can petite diced tomatoes","1 (14.5 oz) can crushed tomatoes","2 1\\/2 Tbsp tomato paste","1 3\\/4 tsp dried basil**","3\\/4 tsp dried oregano","1\\/2 tsp dried rosemary, (crushed)","1\\/2 tsp dried thyme","Salt and freshly ground black pepper, (to taste)","8 lasagna noodles, (broken into bite size pieces (6.5 oz)***)","1 1\\/4 cups (5 oz) shredded mozzarella cheese","1\\/2 cup (2 oz) finely shredded parmesan cheese","8 oz ricotta cheese","2 Tbsp chopped fresh parsley, (plus more for garnish)"],"recipeInstructions":[{"@type":"HowToStep","text":"Heat one tablespoon olive oil in a large pot over medium-high heat. Once hot, crumble beef into pot, season with salt and pepper to taste and cook, stirring occasionally until browned. Drain fat from beef and set beef aside.&nbsp;","name":"Heat one tablespoon olive oil in a large pot over medium-high heat. Once hot, crumble beef into pot, season with salt and pepper to taste and cook, stirring occasionally until browned. Drain fat from beef and set beef aside.&nbsp;","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#wprm-recipe-30576-step-0-0"},{"@type":"HowToStep","text":"Heat remaining 1 Tbsp olive oil in pot, add chopped yellow onion and saute until it begins to soften, about 3 minutes. Add in garlic and saute 30 seconds longer.&nbsp;","name":"Heat remaining 1 Tbsp olive oil in pot, add chopped yellow onion and saute until it begins to soften, about 3 minutes. Add in garlic and saute 30 seconds longer.&nbsp;","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#wprm-recipe-30576-step-0-1"},{"@type":"HowToStep","text":"Add in chicken broth, diced tomatoes, crushed tomatoes, tomato paste, basil, oregano, rosemary, thyme, browned ground beef and season with salt and pepper to taste.&nbsp;","name":"Add in chicken broth, diced tomatoes, crushed tomatoes, tomato paste, basil, oregano, rosemary, thyme, browned ground beef and season with salt and pepper to taste.&nbsp;","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#wprm-recipe-30576-step-0-2"},{"@type":"HowToStep","text":"Bring just to a boil, then reduce heat to medium-low, cover and simmer 20 minutes.","name":"Bring just to a boil, then reduce heat to medium-low, cover and simmer 20 minutes.","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#wprm-recipe-30576-step-0-3"},{"@type":"HowToStep","text":"Meanwhile, prepare lasagna noodles according to directions listed on package.","name":"Meanwhile, prepare lasagna noodles according to directions listed on package.","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#wprm-recipe-30576-step-0-4"},{"@type":"HowToStep","text":"In a mixing bowl, using a fork, stir together mozzarella, parmesan and ricotta.","name":"In a mixing bowl, using a fork, stir together mozzarella, parmesan and ricotta.","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#wprm-recipe-30576-step-0-5"},{"@type":"HowToStep","text":"Stir cooked pasta into soup along with parsley, then thin soup with a little more broth if desired****.&nbsp;","name":"Stir cooked pasta into soup along with parsley, then thin soup with a little more broth if desired****.&nbsp;","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#wprm-recipe-30576-step-0-6"},{"@type":"HowToStep","text":"Ladle soup into bowls, dollop with a large scoop of the cheese mixture and sprinkle with chopped parsley (cheese will melt well once stirred into soup).","name":"Ladle soup into bowls, dollop with a large scoop of the cheese mixture and sprinkle with chopped parsley (cheese will melt well once stirred into soup).","url":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#wprm-recipe-30576-step-0-7"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"4.95","ratingCount":"120","reviewCount":"6"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"How can this be done in a crockpot","author":{"@type":"Person","name":"Sylvia"},"datePublished":"2025-11-05"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I have made this many times. It is so delicious. Sometimes I use ground beef sometimes I use hot italian sausage sometimes I use some of each. I always use beef broth instead of chicken broth. Personal preference. I use bow tie pasta in My soup and I don\'t cook it ahead of time I just put it in with the soup after everything is cooked down a bit. The seasoning combination in this recipe is perfect. I highly recommend you make it.","author":{"@type":"Person","name":"Helen Kay"},"datePublished":"2025-09-26"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"4"},"reviewBody":"I always follow the recipe to see how it\\u2019s supposed taste but I found using chicken broth wasn\\u2019t rich enough and regret not using beef broth instead but again thought best to follow the recipe. I would also use half spicy Italian and half ground beef to add more flavour. The ricotta mixture needed a little salt. I\\u2019ll try it again with my version as it is easy but I want it to taste like lasagna.","author":{"@type":"Person","name":"Jacqueline"},"datePublished":"2025-03-15"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I\'ve had this recipe saved for years! I\'ve made this multiple times! Amazing! Family loves it. Thank you for this amazing recipe!","author":{"@type":"Person","name":"Patricia"},"datePublished":"2025-01-24"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Absolutely love it just wondering for the calories how much is a serving? I would assume a cup but on a cal deficit and this seems a really good way to keep on track","author":{"@type":"Person","name":"Madison"},"datePublished":"2025-01-14"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Recipe was excellent base - I didn\'t have the tomato paste but instead added 1 Cup of Jar Marinara Sauce. Instead of salt I used garlic salt which enhanced the flavor of the meat. Also, added probably 2 C more of the Chicken Broth. Also, didn\'t have all of the cheeses, but did have 1\\/2 Cup of mozzarella and opted to cut up into tiny pieces and add to the soup near the end. Additionally, I added 2 cups of frozen ravioli which took it up another notch and added the cheese. It was beyond my expectations!! My husband ate 3 bowls! I cannot wait to eat more of it today when the spices have a chance to meld into one another!!","author":{"@type":"Person","name":"Diane Moore"},"datePublished":"2024-11-08"}],"recipeCategory":["Soup"],"recipeCuisine":["Italian"],"keywords":"Lasagna Soup","nutrition":{"@type":"NutritionInformation","calories":"546 kcal","carbohydrateContent":"41 g","proteinContent":"38 g","fatContent":"26 g","saturatedFatContent":"11 g","cholesterolContent":"92 mg","sodiumContent":"649 mg","fiberContent":"4 g","sugarContent":"9 g","servingSize":"1 serving"},"@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#recipe","isPartOf":{"@id":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/#article"},"mainEntityOfPage":"https:\\/\\/www.cookingclassy.com\\/lasagna-soup\\/"}]}',
            'image' => 'https://www.cookingclassy.com/wp-content/uploads/2018/12/lasagna-soup-12.jpg',
        'ingredients' => '["2 Tbsp olive oil, (divided)","1 lb lean ground beef","1 large yellow onion, (diced (1 3\\/4 cups))","5 garlic cloves, (to taste, minced*)","4 1\\/2 cups low-sodium chicken broth, (then more to thin as desired)","1 (14.5 oz) can petite diced tomatoes","1 (14.5 oz) can crushed tomatoes","2 1\\/2 Tbsp tomato paste","1 3\\/4 tsp dried basil**","3\\/4 tsp dried oregano","1\\/2 tsp dried rosemary, (crushed)","1\\/2 tsp dried thyme","Salt and freshly ground black pepper, (to taste)","8 lasagna noodles, (broken into bite size pieces (6.5 oz)***)","1 1\\/4 cups (5 oz) shredded mozzarella cheese","1\\/2 cup (2 oz) finely shredded parmesan cheese","8 oz ricotta cheese","2 Tbsp chopped fresh parsley, (plus more for garnish)"]',
        'directions' => '["Heat one tablespoon olive oil in a large pot over medium-high heat. Once hot, crumble beef into pot, season with salt and pepper to taste and cook, stirring occasionally until browned. Drain fat from beef and set beef aside.&nbsp;","Heat remaining 1 Tbsp olive oil in pot, add chopped yellow onion and saute until it begins to soften, about 3 minutes. Add in garlic and saute 30 seconds longer.&nbsp;","Add in chicken broth, diced tomatoes, crushed tomatoes, tomato paste, basil, oregano, rosemary, thyme, browned ground beef and season with salt and pepper to taste.&nbsp;","Bring just to a boil, then reduce heat to medium-low, cover and simmer 20 minutes.","Meanwhile, prepare lasagna noodles according to directions listed on package.","In a mixing bowl, using a fork, stir together mozzarella, parmesan and ricotta.","Stir cooked pasta into soup along with parsley, then thin soup with a little more broth if desired****.&nbsp;","Ladle soup into bowls, dollop with a large scoop of the cheese mixture and sprinkle with chopped parsley (cheese will melt well once stirred into soup)."]',
            'nutrition' => '[{"@type":"NutritionInformation","calories":"546 kcal","carbohydrateContent":"41 g","proteinContent":"38 g","fatContent":"26 g","saturatedFatContent":"11 g","cholesterolContent":"92 mg","sodiumContent":"649 mg","fiberContent":"4 g","sugarContent":"9 g","servingSize":"1 serving"}]',
            'slug' => 'lasagna-soup',
            'raw_data' => NULL,
            'category' => 'Soup',
            'cuisine' => 'Italian',
            'created_at' => '2025-11-24 01:06:28',
            'updated_at' => '2026-07-13 04:44:25',
            'site_link' => 'https://www.cookingclassy.com/lasagna-soup/#recipe',
        ),
