            'id' => 64,
            'name' => 'Farro Bowls with Broccoli and Chickpeas',
            'url' => 'https://www.slenderkitchen.com/recipe/farro-bowls',
            'site_domain' => 'https://www.slenderkitchen.com',
            'site_name' => 'Kristen McCaffrey',
            'user_id' => 1,
            'description' => 'These Farro Bowls with Broccoli and Chickpeas, and lemon tahini sauce are a hearty vegetarian meal that’s perfect for easy meal prep.',
        'content' => '{"@context":"http:\\/\\/schema.org","@type":"Recipe","mainEntityOfPage":"https:\\/\\/www.slenderkitchen.com\\/recipe\\/farro-bowls","name":"Farro Bowls with Broccoli and Chickpeas","image":["https:\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/styles\\/gsd-1x1\\/public\\/recipe_images\\/farro-bowls.jpg","https:\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/styles\\/gsd-4x3\\/public\\/recipe_images\\/farro-bowls.jpg","https:\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/styles\\/gsd-16x9\\/public\\/recipe_images\\/farro-bowls.jpg","https:\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/styles\\/gsd-9x16\\/public\\/recipe_images\\/farro-bowls.jpg"],"description":"These Farro Bowls with Broccoli and Chickpeas, and lemon tahini sauce are a hearty vegetarian meal that\\u2019s perfect for easy meal prep.","datePublished":"2026-03-06","dateModified":"2026-03-09","author":{"@type":"Person","name":"Kristen McCaffrey","url":"https:\\/\\/www.slenderkitchen.com\\/user\\/kristen-mccaffrey"},"publisher":{"@type":"Organization","name":"Slender Kitchen","logo":{"@type":"ImageObject","url":"https:\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/sk-logo-347x60.png","width":347,"height":60}},"prepTime":"PT10M","cookTime":"PT30M","totalTime":"PT40M","recipeYield":"4","recipeIngredient":["[Bowls]","1 cup farro","4 cups broccoli florets","2 shallots, sliced","2 cups canned chickpeas, rinsed and drained","2 tbsp olive oil","2 tsp smoked paprika","1 tsp garlic powder","1 tsp kosher salt","1\\/2 tsp black pepper","1\\/2 cup reduced fat feta cheese","Salt and pepper","[Dressing]","1\\/4 cup tahini","3 tbsp olive oil","3 tbsp lemon juice","2 tsp Dijon mustard","2 tsp honey(or maple syrup)","2 tbsp water (up to double the amount)","1\\/2 tsp kosher salt","1\\/8 tsp red pepper flakes","Pepper to taste"],"recipeCategory":["Dinner","Lunch","Side Dish"],"recipeInstructions":[{"@type":"HowToStep","name":"Cook the farro.","text":"Add the farro and water to a pot on the stove. Add a pinch of salt. Bring to a boil and then turn down to a low simmer. Cover and cook for 20-25 minutes until the farro is tender. Drain any excess water.","url":"https:\\/\\/www.slenderkitchen.com\\/recipe\\/farro-bowls#step1","image":"\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/styles\\/feed_list_sm_2x\\/public\\/steps\\/farro-bowls-step 1.jpg"},{"@type":"HowToStep","name":"Roast broccoli.","text":"Preheat the oven to 425 degrees. Toss the broccoli, shallots, and chickpeas with the olive oil, smoked paprika, garlic powder, salt, and pepper. Spread our on a baking sheet in a single layer. Roast fro 20-25 minutes until broccoli is browned and chickpeas are crispy on the outside.","url":"https:\\/\\/www.slenderkitchen.com\\/recipe\\/farro-bowls#step2","image":"\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/styles\\/feed_list_sm_2x\\/public\\/steps\\/farro-bowls-step 2.jpg"},{"@type":"HowToStep","name":"Make tahini sauce.","text":"Meanwhile, make the tahini dressing by whisking together the tahini, olive oil, lemon juice, mustard, honey, water, salt, pepper, and red pepper flakes. If it is too thick, slowly add in more water. Adjust flavor to taste with more lemon juice, honey, salt, pepper, or red pepper flakes.","url":"https:\\/\\/www.slenderkitchen.com\\/recipe\\/farro-bowls#step3","image":"\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/styles\\/feed_list_sm_2x\\/public\\/steps\\/farro-bowls-step 3.jpg"},{"@type":"HowToStep","name":"Assemble farro bowls.","text":"Serve the roasted broccoli, shallots, and chickpeas over the farro with the sauce drizzled on top.","url":"https:\\/\\/www.slenderkitchen.com\\/recipe\\/farro-bowls#step4","image":"\\/\\/www.slenderkitchen.com\\/sites\\/default\\/files\\/styles\\/feed_list_sm_2x\\/public\\/steps\\/farro-bowls-step 4.jpg"}],"nutrition":{"@type":"NutritionInformation","servingSize":"2\\/3 cup farro with 1 cup broccoli and 2 tbsp sauce","calories":"649 cal","carbohydrateContent":"76 g","fatContent":"32 g","proteinContent":"24 g","fiberContent":"10 g","saturatedFatContent":"5 g","cholesterolContent":"7 mg","sodiumContent":"1506 mg","sugarContent":"10 g"},"recipeCuisine":"Middle Eastern","keywords":"Bowl, Make Ahead, Quick and Easy, grain bowl","video":{"@type":"VideoObject","name":"Farro Bowls with Broccoli and Chickpeas","description":"These Farro Bowls with Broccoli and Chickpeas are a cozy, vegetarian grain bowl with chewy farro, crispy roasted veggies, and a bright lemon tahini drizzle. They are endlessly customizable, great for meal prep, and use simple ingredients you probably already have at home!","thumbnailUrl":["https:\\/\\/content.jwplatform.com\\/thumbs\\/IaMnazLK-720.jpg"],"contentUrl":"https:\\/\\/content.jwplatform.com\\/videos\\/IaMnazLK.mp4","embedUrl":"","uploadDate":"2026-03-09T16:13:31+00:00","duration":"P0DT0H1M17S"}}',
            'image' => 'https://www.slenderkitchen.com/sites/default/files/styles/gsd-1x1/public/recipe_images/farro-bowls.jpg',
        'ingredients' => '["[Bowls]","1 cup farro","4 cups broccoli florets","2 shallots, sliced","2 cups canned chickpeas, rinsed and drained","2 tbsp olive oil","2 tsp smoked paprika","1 tsp garlic powder","1 tsp kosher salt","1\\/2 tsp black pepper","1\\/2 cup reduced fat feta cheese","Salt and pepper","[Dressing]","1\\/4 cup tahini","3 tbsp olive oil","3 tbsp lemon juice","2 tsp Dijon mustard","2 tsp honey(or maple syrup)","2 tbsp water (up to double the amount)","1\\/2 tsp kosher salt","1\\/8 tsp red pepper flakes","Pepper to taste"]',
            'directions' => '["Add the farro and water to a pot on the stove. Add a pinch of salt. Bring to a boil and then turn down to a low simmer. Cover and cook for 20-25 minutes until the farro is tender. Drain any excess water.","Preheat the oven to 425 degrees. Toss the broccoli, shallots, and chickpeas with the olive oil, smoked paprika, garlic powder, salt, and pepper. Spread our on a baking sheet in a single layer. Roast fro 20-25 minutes until broccoli is browned and chickpeas are crispy on the outside.","Meanwhile, make the tahini dressing by whisking together the tahini, olive oil, lemon juice, mustard, honey, water, salt, pepper, and red pepper flakes. If it is too thick, slowly add in more water. Adjust flavor to taste with more lemon juice, honey, salt, pepper, or red pepper flakes.","Serve the roasted broccoli, shallots, and chickpeas over the farro with the sauce drizzled on top."]',
            'nutrition' => '[{"@type":"NutritionInformation","servingSize":"2\\/3 cup farro with 1 cup broccoli and 2 tbsp sauce","calories":"649 cal","carbohydrateContent":"76 g","fatContent":"32 g","proteinContent":"24 g","fiberContent":"10 g","saturatedFatContent":"5 g","cholesterolContent":"7 mg","sodiumContent":"1506 mg","sugarContent":"10 g"}]',
