anguage":"en-US","@id":"https:\\/\\/thewoksoflife.com\\/green-sauce-recipe\\/#primaryimage","url":"https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2025\\/07\\/green-sauce-3.jpg","contentUrl":"https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2025\\/07\\/green-sauce-3.jpg","width":1200,"height":1527,"caption":"Green Sauce Recipe"},{"@type":"BreadcrumbList","@id":"https:\\/\\/thewoksoflife.com\\/green-sauce-recipe\\/#breadcrumb","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https:\\/\\/thewoksoflife.com\\/"},{"@type":"ListItem","position":2,"name":"Recipes","item":"https:\\/\\/thewoksoflife.com\\/category\\/recipes\\/"},{"@type":"ListItem","position":3,"name":"Condiments","item":"https:\\/\\/thewoksoflife.com\\/category\\/recipes\\/condiments\\/"},{"@type":"ListItem","position":4,"name":"Our Favorite Green Sauce Recipe (Peruvian Aji Verde)"}]},{"@type":"WebSite","@id":"https:\\/\\/thewoksoflife.com\\/#website","url":"https:\\/\\/thewoksoflife.com\\/","name":"The Woks of Life","description":"a culinary genealogy","publisher":{"@id":"https:\\/\\/thewoksoflife.com\\/#organization"},"potentialAction":[{"@type":"SearchAction","target":{"@type":"EntryPoint","urlTemplate":"https:\\/\\/thewoksoflife.com\\/?s={search_term_string}"},"query-input":{"@type":"PropertyValueSpecification","valueRequired":true,"valueName":"search_term_string"}}],"inLanguage":"en-US"},{"@type":"Organization","@id":"https:\\/\\/thewoksoflife.com\\/#organization","name":"The Woks of Life","url":"https:\\/\\/thewoksoflife.com\\/","logo":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/thewoksoflife.com\\/#\\/schema\\/logo\\/image\\/","url":"https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2019\\/05\\/Temporary-Logo-e1556728319201.png","contentUrl":"https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2019\\/05\\/Temporary-Logo-e1556728319201.png","width":365,"height":364,"caption":"The Woks of Life"},"image":{"@id":"https:\\/\\/thewoksoflife.com\\/#\\/schema\\/logo\\/image\\/"},"sameAs":["https:\\/\\/www.facebook.com\\/thewoksoflife","https:\\/\\/x.com\\/thewoksoflife"]},{"@type":"Person","@id":"https:\\/\\/thewoksoflife.com\\/#\\/schema\\/person\\/b6722edf39874a953ec3180cefb152e5","name":"Sarah","image":{"@type":"ImageObject","inLanguage":"en-US","@id":"https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2020\\/10\\/sarah-110x110.jpg","url":"https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2020\\/10\\/sarah-110x110.jpg","contentUrl":"https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2020\\/10\\/sarah-110x110.jpg","caption":"Sarah"},"description":"Sarah Leung is the eldest daughter in The Woks of Life family, working alongside younger sister Kaitlin and parents Bill and Judy. You could say this multigenerational recipe blog was born out of two things: 1) her realization in college that she had no idea how to make her mom\\u2019s Braised Pork Belly and 2) that she couldn\\u2019t find a job after graduation. With the rest of the family on board, she laid the groundwork for the blog in 2013. By 2015, it had become one of the internet\\u2019s most trusted resources for Chinese cooking. Creator of quick and easy recipes for harried home cooks and official Woks of Life photographer, Sarah loves creating accessible recipes that chase down familiar nostalgic flavors while adapting to the needs of modern home cooks. Alongside her family, Sarah has become a New York Times Bestselling author with their cookbook, The Woks of Life: Recipes to Know and Love from a Chinese American Family, as well as a James Beard Award nominee and IACP Award finalist.","sameAs":["https:\\/\\/www.thewoksoflife.com","facebook.com\\/thewoksoflife","https:\\/\\/x.com\\/thewoksoflife"],"url":"https:\\/\\/thewoksoflife.com\\/author\\/sleung\\/"},{"@type":"Recipe","name":"Green Sauce (Aji Verde)","author":{"@id":"https:\\/\\/thewoksoflife.com\\/#\\/schema\\/person\\/b6722edf39874a953ec3180cefb152e5"},"description":"This vibrant Peruvian-inspired green sauce is about to become your new go-to all-purpose condiment. Based on a classic aji verde that traditionally accompanies Peruvian roast chicken, this easy green sauce recipe delivers incredible flavor in just 5 minutes.","datePublished":"2025-08-03T22:09:46+00:00","image":["https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2025\\/07\\/green-sauce-5.jpg","https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2025\\/07\\/green-sauce-5-500x500.jpg","https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2025\\/07\\/green-sauce-5-500x375.jpg","https:\\/\\/thewoksoflife.com\\/wp-content\\/uploads\\/2025\\/07\\/green-sauce-5-480x270.jpg"],"recipeYield":["12"],"prepTime":"PT5M","totalTime":"PT5M","recipeIngredient":["2 whole jalape\\u00f1os ((roughly chopped))","1 cup fresh cilantro leaves ((packed))","2 cloves garlic","1\\/2 cup mayonnaise","1 lime ((juiced))","1 teaspoon distilled white vinegar","2 tablespoons extra virgin olive oil","salt and freshly ground black pepper"],"recipeInstructions":[{"@type":"HowToStep","text":"Combine jalape\\u00f1os, cilantro, garlic, mayonnaise, lime juice, and vinegar in a blender or food processor. Turn on high speed, pausing to scrape down the sides with a rubber spatula as necessary, until smooth. With the blender running, slowly drizzle in the olive oil. Season to taste with salt and pepper. Transfer to a sealed container and refrigerate until ready to use.","name":"Combine jalape\\u00f1os, cilantro, garlic, mayonnaise, lime juice, and vinegar in a blender or food processor. Turn on high speed, pausing to scrape down the sides with a rubber spatula as necessary, until smooth. With the blender running, slowly drizzle in the olive oil. Season to taste with salt and pepper. Transfer to a sealed container and refrigerate until ready to use.","url":"https:\\/\\/thewoksoflife.com\\/green-sauce-recipe\\/#wprm-recipe-92771-step-0-0"}],"aggregateRating":{"@type":"AggregateRating","ratingValue":"4.56","ratingCount":"9","reviewCount":"3"},"review":[{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I\'ve been looking for a really good green sauce recipe for years, and this one totally nails it! Was the perfect dipping sauce for Bill\'s Pan Fried Three Ingredients Chicken Wing last night. This will be a pantry staple. Thanks Sarah!","author":{"@type":"Person","name":"Neil McAllister"},"datePublished":"2026-06-18"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"Delicious sauce, I just couldn\'t find any use for it","author":{"@type":"Person","name":"Brushjl"},"datePublished":"2025-08-31"},{"@type":"Review","reviewRating":{"@type":"Rating","ratingValue":"5"},"reviewBody":"I\'m so mad at myself. Just went to grocery store and forgot the cilantro...it\'s 40 minutes away so I won\'t be running back. Is there anyway I could use dry cilantro?? If so how much- or am I better to use scallions and\\/or chives? I can\'t wait to try this with chicken. Many thanks!","author":{"@type":"Person","name":"M H"},"datePublished":"2025-08-06"}],"recipeCategory":["Condiments"],"recipeCuisine":["Peruvian"],"keywords":"aji verde, green sauce","nutrition":{"@type":"NutritionInformation","calories":"88 kcal","carbohydrateContent":"1 g","proteinContent":"0.2 g","fatContent":"9 g","saturatedFatContent":"1 g","transFatContent":"0.02 g","cholesterolContent":"4 mg","sodiumContent":"60 mg","fiberContent":"0.3 g","sugarContent":"0.3 g","unsaturatedFatContent":"7 g","servingSize":"1 serving"},"@id":"https:\\/\\/thewoksoflife.com\\/green-sauce-recipe\\/#recipe","isPartOf":{"@id":"https:\\/\\/thewoksoflife.com\\/green-sauce-recipe\\/#article"},"mainEntityOfPage":"https:\\/\\/thewoksoflife.com\\/green-sauce-recipe\\/"}]}',
